# SECTION: ContentSwitcher widget (custom implementation for Textual 8.x)
# ══════════════════════════════════════════════════════════════════════════════

class ContentSwitcher(Container):
    """A container that shows/hides children by ID based on the current view."""

    def __init__(self, *children, initial: str = None, **kwargs):
        super().__init__(*children, **kwargs)
        self._current = initial

    @property
    def current(self) -> str:
        return self._current

    @current.setter
    def current(self, value: str) -> None:
        self._current = value
        # Show/hide children based on current view
        for child in self.children:
            if hasattr(child, 'id') and child.id:
                child.display = (child.id == value)


