# ── Anonymous telemetry helpers ───────────────────────────────────────────────
# Tracks which screens had *real* actions executed (SSH commands sent) during
# this session - basically just me wanting to know if anyone uses the docker
# screen or if I wasted 3 evenings on it for nothing.  No personal data, no
# persistent ID.  Flushed to app_stats and sent with the update-check request.
_SCREEN_EXEC_LOG: dict[str, int] = {}   # screen_name → exec count (in-memory)

def _record_screen_exec(screen: str) -> None:
    """Call this whenever a screen sends a real command to a server."""
    _SCREEN_EXEC_LOG[screen] = _SCREEN_EXEC_LOG.get(screen, 0) + 1

# ── Logging setup ─────────────────────────────────────────────────────────────
from logging.handlers import RotatingFileHandler as _RotFH

_LOG_DIR = DEFLECT_DIR / "logs"
_LOG_DIR.mkdir(exist_ok=True)

_LOG_FMT = logging.Formatter(
    "%(asctime)s  %(levelname)-7s  %(name)s  %(message)s",
    datefmt="%Y-%m-%d %H:%M:%S"
)
_LOG_10MB = 10 * 1024 * 1024

def _make_rot(filename, level=logging.DEBUG) -> _RotFH:
    h = _RotFH(_LOG_DIR / filename, maxBytes=_LOG_10MB, backupCount=3, encoding="utf-8")
    h.setLevel(level)
    h.setFormatter(_LOG_FMT)
    return h

# deflect.log — full app log (DEBUG+), main logger
_log = logging.getLogger("deflect")
_log.setLevel(logging.DEBUG)
_log.propagate = False
if not _log.handlers:
    _log.addHandler(_make_rot("deflect.log", logging.DEBUG))
    _log.addHandler(_make_rot("errors.log",  logging.ERROR))   # errors-only, stays small

# security.log — security events (bans, attack loop errors)
_log_sec = logging.getLogger("deflect.security")
_log_sec.setLevel(logging.DEBUG)
if not _log_sec.handlers:
    _log_sec.addHandler(_make_rot("security.log", logging.INFO))
# propagates to _log → security entries also appear in deflect.log

# ai.log — AI defense / managed decisions and actions
_log_ai = logging.getLogger("deflect.ai")
_log_ai.setLevel(logging.DEBUG)
if not _log_ai.handlers:
    _log_ai.addHandler(_make_rot("ai.log", logging.INFO))
# propagates to _log → AI entries also appear in deflect.log


@dataclass
class SecurityMonitoringConfig:
    """Per-host security monitoring toggles and thresholds."""
    ssh_brute:            bool  = True
    http_flood:           bool  = True
    exploit_scan:         bool  = True
    http_brute:           bool  = True
    bot_detection:        bool  = True
    conn_flood:           bool  = True
    syn_flood:            bool  = True
    port_audit:           bool  = True
    ddos_detection:       bool  = True
    campaign_tracking:    bool  = True
    # v0.6 - email attack detection
    email_brute:          bool  = True   # AUTH failures / aggressive SMTP login attempts
    email_scan:           bool  = True   # RCPT-to unknown users / user enumeration
    # Thresholds
    http_flood_threshold: int   = 100   # req/min per IP
    conn_flood_threshold: int   = 50    # simultaneous connections per IP
    ddos_threshold:       int   = 500   # req/min across top-5 IPs combined
    email_brute_threshold:int   = 10    # AUTH failures per IP in log window → email_brute
    # Log paths
    nginx_log:            str   = "/var/log/nginx/access.log"
    apache_log:           str   = "/var/log/apache2/access.log"
    email_log:            str   = ""    # "" = auto-detect (exim4 mainlog or mail.log)


@dataclass
class HostConfig:
    id:            str
    label:         str
    address:       str
    port:          int        = 22
    username:      str        = "root"
    auth:          str        = "key"        # key | password | vault_key
    key_path:      str        = "~/.ssh/id_rsa"
    password:      str        = ""
    vault_key_id:  str        = ""
    tags:          list[str]  = field(default_factory=list)
    poll_interval: int        = 5
    services:      list[str]  = field(default_factory=list)  # empty = auto-discover
    port_forwards: list[dict] = field(default_factory=list)  # {name,type,local_port,remote_host,remote_port,enabled}
    maintenance:   bool       = False                        # if True - alerts silenced, ServerCard shows 🔧
    ai_controlled: bool       = False                        # if True - AI manages the host, ServerCard shows 🤖
    monitoring:    SecurityMonitoringConfig = field(default_factory=SecurityMonitoringConfig)
    ai_instructions: str      = ""                           # per-host freeform AI goals (v0.75)


@dataclass
class AIConfig:
    """
    AI engine configuration - stored in deflect.json under 'ai'.

    Two model tiers for cost-efficient usage:
      smart_model - powerful reasoning model for complex analysis tasks
                    (cyber defense, health audit, managed host decisions, AI Chat)
      fast_model  - lightweight cheap model for high-frequency simple tasks
                    (F8 hints every 15s, F9 command translation, quick explain)

    If fast_model is blank, smart_model is used for all tiers.
    Set fast_model to a cheaper variant to significantly reduce API costs:
      Claude:  smart=claude-sonnet-4-6  fast=claude-haiku-4-5-20251001
      OpenAI:  smart=gpt-4o             fast=gpt-4o-mini
      Gemini:  smart=gemini-1.5-pro     fast=gemini-1.5-flash
      Mistral: smart=mistral-large-latest  fast=mistral-small-latest
      Groq:    smart=llama-3.3-70b-versatile  fast=llama-3.1-8b-instant
    """
    enabled:            bool  = False
    provider:           str   = "anthropic"   # anthropic|openai|gemini|mistral|groq|lmstudio|custom
    api_key:            str   = ""            # enc:... or plain (encrypted on save by HardwareVault)
    api_base_url:       str   = ""            # for lmstudio/custom; blank = provider default
    smart_model:        str   = ""            # powerful model for complex tasks (blank = provider default)
    fast_model:         str   = ""            # cheap model for frequent simple tasks (blank = use smart)
    defense_mode:       str   = "advisory"    # advisory | semi_auto | full_auto
    defense_threshold:  int   = 10            # attacks/min to trigger AI defense loop
    max_tokens_per_req: int   = 2000          # token cap per single LLM request
    hourly_token_limit: int   = 0             # 0 = unlimited (counts all tiers combined)
    daily_token_limit:  int   = 0             # 0 = unlimited
    quota_warn_pct:     int   = 80            # notify when daily_used >= this % of daily_limit
    quota_notify:       bool  = True          # fire NotificationManager when quota approached/hit
    # ── context window limits (v0.75) ─────────────────────────────────────
    ctx_max_log_lines:     int  = 30    # AIHostContext: max recent log lines
    ctx_max_attack_events: int  = 50    # AIAttackContext / AIHostContext: max events
    ctx_max_inv_entries:   int  = 15    # AIHostContext: max inventory items
    ctx_shell_buf_chars:   int  = 2000  # AIShellContext: terminal buffer chars
    ctx_shell_max_inv:     int  = 10    # AIShellContext: max inventory items
    ctx_chat_max_history:  int  = 10    # AiChatScreen: turns before summarization
    ctx_dedup_window_secs: int  = 300   # attack event dedup time window (seconds)
    ctx_compact_threshold: int  = 75    # % of token budget to trigger compaction


@dataclass
class AppConfig:
    hosts:            list[HostConfig] = field(default_factory=list)
    refresh_interval: int   = 5
    sparkline_width:  int   = 18
    command_timeout:  int   = 10
    scripts_dir:      str   = "./scripts"
    cpu_warn:         int   = 75
    cpu_crit:         int   = 90
    ram_warn:         int   = 80
    ram_crit:         int   = 92
    disk_warn:        int   = 80
    disk_crit:        int   = 95
    attack_log_lines: int   = 300
    tg_token:         str   = ""
    tg_chat:          str   = ""
    webhook_url:      str   = ""
    # email
    smtp_host:        str   = ""
    smtp_port:        int   = 587
    smtp_user:        str   = ""
    smtp_password:    str   = ""
    smtp_from:        str   = ""
    smtp_to:          str   = ""
