# SECTION: metrics
# ══════════════════════════════════════════════════════════════════════════════

HISTORY = 60   # data points (~5 min at 5s interval)


@dataclass
class HostMetrics:
    host_id:    str
    cpu_pct:    float = 0.0
    ram_pct:    float = 0.0
    disk_pct:   float = 0.0
    load1:      float = 0.0
    net_rx_kb:  float = 0.0
    net_tx_kb:  float = 0.0
    uptime_s:   int   = 0
    updated_at: float = 0.0
    error:      str   = ""

    cpu_history: deque = field(default_factory=lambda: deque(maxlen=HISTORY))
    ram_history: deque = field(default_factory=lambda: deque(maxlen=HISTORY))
    net_rx_hist: deque = field(default_factory=lambda: deque(maxlen=HISTORY))
    net_tx_hist: deque = field(default_factory=lambda: deque(maxlen=HISTORY))
    mail_queue_hist: deque = field(default_factory=lambda: deque(maxlen=HISTORY))

    # SSL cert info: {domain: days_remaining}  (-1 = error/unreachable)
    ssl_certs: dict = field(default_factory=dict)

    # Mail server metrics (updated by _mail_loop every 5 min)
    # mail_queue_count = messages delivered in last sample window (used for throughput calculation)
    # mail_mta_type = "exim4" | "postfix" | None
    # mail_throughput_mpm = calculated msgs/min based on delta between samples
    # (monitoring mail servers is basically a gateway drug to monitoring everything else)
    mail_queue_count: int = 0
    mail_mta_type: Optional[str] = None
    mail_throughput_mpm: float = 0.0  # messages per minute
    mail_last_checked: float = 0.0
    mail_last_count: int = 0  # previous sample count for delta calculation
    mail_last_timestamp: float = 0.0  # timestamp of previous sample
    # v0.6 enhanced mail metrics
    mail_queue_msgs: int = 0       # messages currently in queue (pending delivery)
    mail_errors_10m: int = 0       # delivery errors in last 10 min (from logs)
    mail_spool_mb: float = 0.0     # spool directory total size in MB
    mail_accounts: list = field(default_factory=list)  # local mail users [{name, size_kb}]

    # Docker containers list (updated by _docker_loop)
    docker_containers: list = field(default_factory=list)
    # None = unknown (not yet checked), True = installed, False = not installed
    docker_installed: Optional[bool] = field(default=None)

    # APT info (updated by _apt_loop)
    apt_info: Optional["AptInfo"] = field(default=None)

    # Disk mount points (updated by _disk_loop every 10 min)
    # list of dicts: {mount, size, used, avail, pct, prev_pct}
    disk_mounts: list = field(default_factory=list)
    # top-10 dirs by size: list of dicts: {path, size_str, size_mb, prev_size_mb}
    disk_top_dirs: list = field(default_factory=list)
    disk_last_checked: float = 0.0

    # Cron jobs (updated by _cron_loop every 5 min)
    # list of dicts: {schedule, command, source} source = "crontab" | "timer"
    cron_jobs: list = field(default_factory=list)
    # Systemd timers: list of dicts: {unit, next, last, passed, activates}
    timers: list = field(default_factory=list)
    cron_last_checked: float = 0.0

    # Process list (updated by _proc_loop every 10s)
    # list of dicts: {pid, user, cpu_pct, mem_pct, vsz, rss, state, command}
    processes: list = field(default_factory=list)
    proc_last_checked: float = 0.0
    # OOM events detected from dmesg (list of strings)
    oom_events: list = field(default_factory=list)

    # Firewall rules (updated by _firewall_loop every 60s)
    # list of dicts: {num, action, proto, from_ip, to_ip, port, comment}
    firewall_rules: list = field(default_factory=list)
    firewall_enabled: Optional[bool] = None   # None = unknown, True/False = ufw status
    firewall_last_checked: float = 0.0
    # Security tools installation & fail2ban state (populated by _fetch_firewall)
    ufw_installed:        bool = False
    fail2ban_installed:   bool = False
    fail2ban_active:      bool = False
    # list of dicts: {jail, currently_banned, banned_ips: list[str]}
    fail2ban_jails:       list = field(default_factory=list)
    # Merged banned IPs: [{ip, source("ufw"|"f2b"|"both"), jail, host_id}]
    banned_ips_merged:    list = field(default_factory=list)

    # Network connections (updated by _netconn_loop every 15s)
    # list of dicts: {state, local_ip, local_port, remote_ip, remote_port, process, pid}
    net_connections: list = field(default_factory=list)
    net_conn_last_checked: float = 0.0

    # Database info (updated by _db_loop every 10s)
    # list of dicts: {engine, port, status, connections, max_connections,
    #                 size_mb, qps, hit_rate, repl_lag_s, slowlog, extra}
    db_instances: list = field(default_factory=list)
    db_last_checked: float = 0.0

    # Git repositories (updated by _git_loop every 5 min)
    # list of dicts: {path, branch, behind, ahead, dirty, last_commit}
    git_repos: list = field(default_factory=list)
    git_last_checked: float = 0.0

    # Backup info (updated by _backup_loop every 1h)
    # list of dicts: {tool, last_run, size_str, status, detail}
    backup_status: list = field(default_factory=list)
    backup_last_checked: float = 0.0

    # Environment variables (updated by _env_loop every 30 min)
    # dict: {path → {KEY: VALUE, ...}}
    # (or as I call it: "the place where all the secrets leak from")
    env_vars: dict = field(default_factory=dict)
    # SSH authorized_keys: list of dicts: {file, key_type, key_id, comment}
    ssh_keys: list = field(default_factory=list)
    env_last_checked: float = 0.0

    _prev_cpu:  Optional[list] = field(default=None, repr=False)
    _prev_net:  Optional[dict] = field(default=None, repr=False)
    _prev_time: float          = field(default=0.0,  repr=False)


@dataclass
class ContainerInfo:
    """Docker container state, populated by HostAgent._docker_loop()."""
    id:          str   = ""
    name:        str   = ""
    image:       str   = ""
    status:      str   = ""   # "running", "exited", etc.
    cpu_pct:     float = 0.0
    mem_pct:     float = 0.0
    disk_bytes:  int   = 0    # container RW layer size in bytes (from docker ps -s)
    ports:       str   = ""   # e.g. "0.0.0.0:80->80/tcp"


@dataclass
class AptInfo:
    """APT / OS state, populated by HostAgent._apt_loop()."""
    os_version:      str      = ""   # e.g. "Ubuntu 22.04.3 LTS"
    kernel:          str      = ""   # e.g. "5.15.0-105-generic"
    upgradable:      list     = field(default_factory=list)  # list of dicts {name,current,new,security}
    security_count:  int      = 0
    total_count:     int      = 0
    last_checked:    float    = 0.0


_BATCH_CMD = r"""
cat /proc/stat | grep '^cpu ';
cat /proc/meminfo | grep -E '^(MemTotal|MemAvailable):';
df -P / 2>/dev/null | awk 'NR==2{sub(/%/,"",$5); print $5}';
cat /proc/loadavg | awk '{print $1}';
cat /proc/net/dev 2>/dev/null | awk 'NR>2 && !/lo/ {rx+=$2; tx+=$10} END {printf "%.0f %.0f\n", rx, tx}';
cat /proc/uptime | awk '{print int($1)}'
"""


class MetricsCollector:
    def __init__(self, pool: ConnectionPool):
        self._pool    = pool
        self._metrics: dict[str, HostMetrics] = {
            hid: HostMetrics(host_id=hid) for hid in pool.host_ids()
        }

    def get(self, host_id: str) -> HostMetrics:
        return self._metrics[host_id]

    def all(self) -> list[HostMetrics]:
        return list(self._metrics.values())

    async def poll_all(self):
        tasks = [self._poll_one(hid) for hid in self._metrics]
        await asyncio.gather(*tasks, return_exceptions=True)

    async def poll_loop(self, interval: int = 5):
        while True:
            await self.poll_all()
            await asyncio.sleep(interval)

    async def _poll_one(self, host_id: str):
        m   = self._metrics[host_id]
        res = await self._pool.run(host_id, _BATCH_CMD)
        if not res.ok:
            m.error = res.error or res.stderr.strip()[:80]
            _log.warning("metrics cmd failed on %s: %s", host_id, m.error)
            return

        lines = [l.strip() for l in res.stdout.strip().splitlines() if l.strip()]
        try:
            m.cpu_pct   = self._parse_cpu(lines[0], m)
            m.ram_pct   = self._parse_ram(lines[1], lines[2])
            m.disk_pct  = float(lines[3].strip("%"))
            m.load1     = float(lines[4])
            m.net_rx_kb, m.net_tx_kb = self._parse_net(lines[5], m)
            m.uptime_s  = int(lines[6]) if len(lines) > 6 else 0
            m.error     = ""
            m.updated_at = time.time()
            m.cpu_history.append(m.cpu_pct)
            m.ram_history.append(m.ram_pct)
            m.net_rx_hist.append(m.net_rx_kb)
            m.net_tx_hist.append(m.net_tx_kb)
        except (IndexError, ValueError) as e:
            _log.error("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            m.error = "parse error"
            _log.warning("metrics parse error on %s: %s | lines=%s",
                         host_id, e, lines)

    def _parse_cpu(self, line: str, m: HostMetrics) -> float:
        parts  = list(map(int, line.split()[1:]))
        now    = time.monotonic()
        if m._prev_cpu is not None:
            delta  = [b - a for a, b in zip(m._prev_cpu, parts)]
            total  = sum(delta)
            # Default idle to total (→ 0% CPU) when /proc/stat has fewer fields
            # (e.g. minimal containers). Using 0 would show 100% CPU which scared me
            # the first time I tested this on a stripped alpine image.
            idle   = delta[3] if len(delta) > 3 else total
            pct    = 100.0 * (1 - idle / total) if total else 0.0
        else:
            pct = 0.0
        m._prev_cpu  = parts
        m._prev_time = now
        return round(pct, 1)

    def _parse_ram(self, line_total: str, line_avail: str) -> float:
        total = int(re.search(r"\d+", line_total).group())
        avail = int(re.search(r"\d+", line_avail).group())
        return round(100.0 * (1 - avail / total), 1) if total else 0.0

    def _parse_net(self, line: str, m: HostMetrics) -> tuple[float, float]:
        try:
            parts = line.split()
            if len(parts) < 2:
                return 0.0, 0.0
            rx_b, tx_b = int(float(parts[0])), int(float(parts[1]))
        except (ValueError, IndexError) as e:
            _log.debug("Failed to parse network metrics line %s: %s: %s", line, type(e).__name__, e)
            return 0.0, 0.0

        now = time.monotonic()
        dt = now - m._prev_time if m._prev_time else 1.0

        # Ensure dt is reasonable (at least 0.5s to avoid division artifacts).
        # Anything smaller and the KB/s numbers go completely insane.
        if dt < 0.5:
            dt = 1.0

        if m._prev_net and rx_b > m._prev_net["rx"]:  # Ensure bytes are increasing
            rx_kb = max(0, (rx_b - m._prev_net["rx"]) / dt / 1024)
            tx_kb = max(0, (tx_b - m._prev_net["tx"]) / dt / 1024)
        else:
            rx_kb = tx_kb = 0.0

        m._prev_net = {"rx": rx_b, "tx": tx_b}
        return round(rx_kb, 1), round(tx_kb, 1)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: security_radar
# ══════════════════════════════════════════════════════════════════════════════

_AUTH_CMD  = "tail -n {n} /var/log/auth.log 2>/dev/null || journalctl -u ssh --no-pager -n {n} 2>/dev/null"
_F2B_CMD   = "fail2ban-client status 2>/dev/null | grep 'Jail list' | sed 's/.*://'"
_F2B_JAIL  = "fail2ban-client status {jail} 2>/dev/null | grep 'Currently banned'"
_UFW_CMD   = "ufw status 2>/dev/null | head -30"

# HTTP log analysis (nginx/apache combined log format)
_NGINX_CMD = "tail -n {n} {log_path} 2>/dev/null"
_NGINX_LOG_DEFAULT = "/var/log/nginx/access.log"
_APACHE_LOG_DEFAULT = "/var/log/apache2/access.log"

# Active connections
_SS_ESTAB_CMD = "ss -tn state established 2>/dev/null | awk 'NR>1{print $4,$5}' | head -200"
_SS_SYNRECV_CMD = "ss -tn state syn-recv 2>/dev/null | awk 'NR>1{print $4,$5}' | head -200"

# Open ports audit
_SS_LISTEN_CMD = "ss -tlnp 2>/dev/null | awk 'NR>1{print $4,$6}'"

# Nginx ban (append IP to blocked.conf and reload)
_NGINX_BAN_CMD = (
    "echo 'deny {ip};' >> /etc/nginx/conf.d/blocked.conf 2>/dev/null; "
    "nginx -t 2>/dev/null && nginx -s reload 2>/dev/null || true"
)

# iptables rate-limit for DDoS mitigation
_IPTABLES_RATELIMIT_CMD = (
    "iptables -I INPUT -p tcp -m hashlimit --hashlimit-name http_flood "
    "--hashlimit-above 100/min --hashlimit-mode srcip --hashlimit-burst 200 "
    "-j DROP 2>/dev/null || true"
)

# HTTP log patterns
_PAT_NGINX_LINE = re.compile(
    r'([\d.a-fA-F:]+)\s+-\s+-\s+\[([^\]]+)\]\s+"(\w+)\s+(\S+)\s+HTTP/[\d.]+"\s+(\d+)'
)
_EXPLOIT_PATHS = re.compile(
    r'(?:/.env|/wp-admin|/wp-login\.php|/phpmyadmin|/etc/passwd|/etc/shadow'
    r'|/\.git/|/xmlrpc\.php|/admin|/manager/html|/solr/|/actuator'
    r'|/shell\?|/cgi-bin/|/\.aws/|/config\.php|/setup\.php)',
    re.IGNORECASE,
)
_BRUTE_PATHS = re.compile(
    r'(?:/login|/api/auth|/api/login|/wp-login\.php|/user/login'
    r'|/signin|/account/login|/auth/login)',
    re.IGNORECASE,
)
_BAD_UA = re.compile(
    r'(?:zgrab|masscan|nikto|sqlmap|nmap|dirbuster|gobuster|wfuzz'
    r'|python-requests/|curl/|Go-http-client|libwww-perl)',
    re.IGNORECASE,
)

# Dangerous open port configurations
_DANGEROUS_PORTS = {
    "6379":  ("Redis",      "bind 127.0.0.1 in redis.conf"),
    "27017": ("MongoDB",    "bindIp: 127.0.0.1 in mongod.conf"),
    "11211": ("Memcached",  "-l 127.0.0.1 in /etc/memcached.conf"),
    "9200":  ("Elasticsearch", "network.host: 127.0.0.1"),
    "5601":  ("Kibana",     "server.host: 127.0.0.1"),
    "2375":  ("Docker API", "do not expose Docker socket publicly"),
    "23":    ("Telnet",     "disable telnet, use SSH"),
    "21":    ("FTP",        "use SFTP instead"),
    "514":   ("RSH",        "disable rsh/rlogin"),
    "3306":  ("MySQL",      "bind-address = 127.0.0.1 in my.cnf"),
    "5432":  ("PostgreSQL", "listen_addresses = 'localhost' in postgresql.conf"),
}

_PAT_INVALID = re.compile(r"Invalid user (\S+) from ([\d.a-fA-F:]+)")
_PAT_FAILED  = re.compile(r"Failed (\S+) for (?:invalid user )?(\S+) from ([\d.a-fA-F:]+)")
_PAT_ACCEPTED= re.compile(r"Accepted (\S+) for (\S+) from ([\d.a-fA-F:]+)")
_PAT_BREAK   = re.compile(r"POSSIBLE BREAK-IN ATTEMPT.*from ([\d.a-fA-F:]+)")
_PAT_TIME    = re.compile(r"(\w{3}\s+\d+\s[\d:]+)")

_GEO_CACHE: dict[str, str] = {}


def _ip_in_net(ip_str: str, network) -> bool:
    """Return True if ip_str belongs to an ipaddress network object."""
    try:
        return ipaddress.ip_address(ip_str) in network
    except ValueError as e:
        _log.debug("IP parsing failed for %s: %s", ip_str, e)
        return False


def _cc_to_flag(cc: str) -> str:
    """Convert ISO 3166-1 alpha-2 country code to Unicode flag emoji."""
    if not cc or len(cc) != 2 or not cc.isalpha():
        return "🌐"
    return chr(0x1F1E6 + ord(cc[0].upper()) - 65) + chr(0x1F1E6 + ord(cc[1].upper()) - 65)


@dataclass
class AttackEvent:
    ts:       str
    host_id:  str
    src_ip:   str
    username: str
    method:   str
    kind:     str      # brute | scan | breakin | accepted
    country:  str = ""
    flag:     str = ""
    campaign: bool = False
    live:     bool = False   # True for real-time connection events (Level 2)
    count:    int  = 1       # raw attempt count from the log window (one IP = one slot)


@dataclass
class RadarState:
    events:      deque      = field(default_factory=lambda: deque(maxlen=200))
    ip_counts:   defaultdict= field(default_factory=lambda: defaultdict(int))
    banned_count: int       = 0
    jails:       list[str]  = field(default_factory=list)
    atk_per_min: float      = 0.0
    _minute_buf: deque      = field(default_factory=lambda: deque(maxlen=60))
    port_warnings: list     = field(default_factory=list)  # [{port, service, bind, fix, host_id}]
    ddos_active:   bool     = False
    ddos_info:     str      = ""


class SecurityRadar:
    def __init__(self, pool: ConnectionPool, log_lines: int = 300):
        self._pool       = pool
        self._log_lines  = log_lines
        self._state      = RadarState()
        self._ip_hosts:  dict[str, set]  = defaultdict(set)
        # ip -> ban date (UTC); events on or before this date are suppressed
        self._banned_ips: dict[str, datetime.date] = {}
        self._http_ip_times: dict[str, list] = defaultdict(list)  # ip -> [timestamps]
        self._host_configs:  dict[str, "SecurityMonitoringConfig"] = {}

    def set_host_configs(self, configs: dict[str, "SecurityMonitoringConfig"]) -> None:
        """Update per-host monitoring config."""
        self._host_configs = configs

    def _mon(self, host_id: str) -> "SecurityMonitoringConfig":
        try:
            cfg = self._pool.state(host_id).config
            if cfg and hasattr(cfg, 'monitoring'):
                return cfg.monitoring
        except Exception as e:
            _log.debug("Failed to get monitoring config for host %s: %s: %s",
                      host_id, type(e).__name__, e)
        return self._host_configs.get(host_id, SecurityMonitoringConfig())

    @property
    def state(self) -> RadarState:
        return self._state

    @property
    def ip_hosts(self) -> dict[str, set]:
        """IP → set of host_ids where this IP was detected."""
        return self._ip_hosts

    async def poll_loop(self, interval: int = 8):
        while True:
            await self._poll_all()
            await asyncio.sleep(interval)

    async def ban_ip(self, ip: str, host_ids: list[str]) -> dict[str, bool]:
        cmd     = f"fail2ban-client set sshd banip {ip} 2>/dev/null || true"
        results = await self._pool.run_on(host_ids, cmd)
        return {hid: r.ok for hid, r in results.items()}

    def remove_ip(self, target: str) -> None:
        """Remove events for a specific IP or CIDR subnet from the deque."""
        if '/' in target:
            try:
                net = ipaddress.ip_network(target, strict=False)
                to_keep = [ev for ev in self._state.events
                           if not _ip_in_net(ev.src_ip, net)]
            except ValueError as e:
                _log.debug("Invalid network format %s: %s", target, e)
                to_keep = list(self._state.events)
        else:
            to_keep = [ev for ev in self._state.events if ev.src_ip != target]
        self._state.events.clear()
        self._state.events.extend(to_keep)

    def set_banned_ips(self, banned: dict) -> None:
        """Load {ip: iso_utc_timestamp} from config; pre-ban events are filtered."""
        result: dict[str, datetime.date] = {}
        for ip, ts_str in banned.items():
            try:
                dt = datetime.datetime.fromisoformat(ts_str.replace("Z", "+00:00"))
                result[ip] = dt.date()
            except Exception as e:
                _log.debug("Failed to parse ban timestamp for %s: %s: %s", ip, type(e).__name__, e)
                result[ip] = datetime.date.today()
        self._banned_ips = result

    @staticmethod
    def _log_date(ts_str: str) -> Optional[datetime.date]:
        """Parse auth.log timestamp 'Mar 28 14:23:45' to a UTC date (current year).
        If the date is in the future, assume it's from last year (year-wrap case)."""
        try:
            now = datetime.datetime.now(datetime.UTC).replace(tzinfo=None)
            dt = datetime.datetime.strptime(f"{now.year} {ts_str.strip()}", "%Y %b %d %H:%M:%S")
            if dt > now + datetime.timedelta(days=1):
                # Log timestamp is in the future? Must be from last year then.
                dt = dt.replace(year=now.year - 1)
            return dt.date()
        except Exception as e:
            _log.debug("Failed to parse log date %s: %s: %s", ts_str, type(e).__name__, e)
            return None

    def _is_banned_event(self, ip: str, ts: str) -> bool:
        """Return True if event should be suppressed (banned IP or subnet, pre-ban date)."""
        ban_date = self._banned_ips.get(ip)
        if ban_date is None:
            # Check subnet membership for CIDR entries
            try:
                addr = ipaddress.ip_address(ip)
                for entry, d in self._banned_ips.items():
                    if '/' in entry:
                        try:
                            if addr in ipaddress.ip_network(entry, strict=False):
                                ban_date = d
                                break
                        except ValueError as e:
                            _log.debug("Invalid ban network entry %s: %s", entry, e)
            except ValueError as e:
                _log.debug("Invalid IP address %s: %s", ip, e)
        if ban_date is None:
            return False
        ev_date = self._log_date(ts)
        # Strict post-ban date → new attack, let it through
        if ev_date is not None and ev_date > ban_date:
            return False
        return True  # same day or earlier → suppress

    async def _poll_all(self):
        tasks = [self._poll_host(hid) for hid in self._pool.host_ids()]
        await asyncio.gather(*tasks, return_exceptions=True)
        self._update_stats()

    async def _poll_host(self, host_id: str):
        cmd = _AUTH_CMD.format(n=self._log_lines)
        res = await self._pool.run(host_id, cmd)
        if not res.ok:
            return
        events = self._parse_log(res.stdout, host_id)
        for ev in events:
            await self._geoip(ev)
            ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1

        # One deque-slot per unique source IP: 200 attempts from one IP should
        # occupy 1 slot, not 200, leaving room for other attack sources.
        # (learned this the hard way when a single botnet filled the entire radar
        # and I couldn't see anything else for 20 minutes)
        # Count raw occurrences within this log window per IP.
        ip_raw: dict[str, int] = {}
        for ev in events:
            ip_raw[ev.src_ip] = ip_raw.get(ev.src_ip, 0) + 1
        # IPs already in the newest part of the deque are skipped (no re-flooding).
        recent_ips = {e.src_ip for e in list(self._state.events)[-50:]}
        seen: set[str] = set()
        unique_evs: list[AttackEvent] = []
        for ev in reversed(events):   # newest-first → keep most recent event per IP
            if ev.src_ip not in seen and ev.src_ip not in recent_ips:
                seen.add(ev.src_ip)
                ev.count = ip_raw[ev.src_ip]
                unique_evs.append(ev)
        unique_evs.reverse()   # restore chronological order (yes, we reversed twice; no, I don't regret it)
        if unique_evs:
            self._state.events.extendleft(reversed(unique_evs))

        f2b_res = await self._pool.run(host_id, _F2B_CMD)
        if f2b_res.ok:
            jails = [j.strip() for j in f2b_res.stdout.strip().split(",") if j.strip()]
            self._state.jails = jails
            total = 0
            for jail in jails:
                jr = await self._pool.run(host_id, _F2B_JAIL.format(jail=jail))
                if jr.ok:
                    m = re.search(r"(\d+)", jr.stdout)
                    if m:
                        total += int(m.group(1))
            self._state.banned_count = total

        mon = self._mon(host_id)
        if mon.http_flood or mon.exploit_scan or mon.http_brute or mon.bot_detection:
            await self._poll_http_logs(host_id, mon)
        if mon.conn_flood or mon.syn_flood:
            await self._poll_connections(host_id, mon)
        if mon.port_audit:
            await self._poll_open_ports(host_id)
        if mon.email_brute or mon.email_scan:
            await self._poll_email_logs(host_id, mon)

    def _parse_log(self, raw: str, host_id: str) -> list[AttackEvent]:
        events = []
        for line in raw.splitlines():
            ev = self._parse_line(line, host_id)
            if ev:
                events.append(ev)
        return events

    def _parse_line(self, line: str, host_id: str) -> Optional[AttackEvent]:
        ts_m = _PAT_TIME.search(line)
        ts   = ts_m.group(1) if ts_m else "--:--:--"

        m = _PAT_FAILED.search(line)
        if m:
            method, user, ip = m.group(1), m.group(2), m.group(3)
            if self._is_banned_event(ip, ts):
                return None
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username=user, method=method, kind="brute")

        m = _PAT_INVALID.search(line)
        if m:
            user, ip = m.group(1), m.group(2)
            if self._is_banned_event(ip, ts):
                return None
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username=user, method="ssh", kind="scan")

        m = _PAT_BREAK.search(line)
        if m:
            ip = m.group(1)
            if self._is_banned_event(ip, ts):
                return None
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method="ssh", kind="breakin")
        return None

    def _update_stats(self):
        now = time.time()
        self._state._minute_buf.append(now)
        cutoff = now - 60
        recent = sum(1 for t in self._state._minute_buf if t > cutoff)
        self._state.atk_per_min = recent

    async def _geoip(self, ev: AttackEvent):
        ip = ev.src_ip
        if ip in _GEO_CACHE:
            ev.country = _GEO_CACHE[ip]
        else:
            try:
                import urllib.request
                def _fetch():
                    with urllib.request.urlopen(
                            f"http://ip-api.com/json/{ip}?fields=countryCode",
                            timeout=3) as r:
                        return json.loads(r.read())
                # Run blocking HTTP in a thread so the event loop is not frozen
                loop = asyncio.get_running_loop()
                data = await loop.run_in_executor(None, _fetch)
                cc   = data.get("countryCode", "??")
                _GEO_CACHE[ip] = cc
                ev.country = cc
            except Exception as e:
                _log.debug("GeoIP lookup failed for IP %s: %s: %s", ip, type(e).__name__, e)
                ev.country = "??"
        ev.flag = _cc_to_flag(ev.country)

    async def _poll_http_logs(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Level 1 - parse nginx/apache access logs."""
        log_path = mon.nginx_log or _NGINX_LOG_DEFAULT
        cmd = _NGINX_CMD.format(n=200, log_path=log_path)
        res = await self._pool.run(host_id, cmd)
        if not res.ok or not res.stdout.strip():
            # try apache (fall back if nginx doesn't exist or has no logs)
            cmd2 = _NGINX_CMD.format(n=200, log_path=mon.apache_log or _APACHE_LOG_DEFAULT)
            res = await self._pool.run(host_id, cmd2)
            if not res.ok:
                return

        now = time.time()
        ip_req_times: dict[str, list] = defaultdict(list)
        ip_statuses:  dict[str, list] = defaultdict(list)
        new_events: list[AttackEvent] = []

        for line in res.stdout.splitlines():
            ev = self._parse_nginx_line(line, host_id, ip_req_times, ip_statuses)
            if ev:
                new_events.append(ev)

        # Detect http_flood: ip with > threshold req in last 60s
        if mon.http_flood:
            cutoff = now - 60
            for ip, times in ip_req_times.items():
                recent = [t for t in times if t > cutoff]
                if len(recent) >= mon.http_flood_threshold:
                    if not any(e.src_ip == ip and e.kind == "http_flood"
                               for e in list(self._state.events)[-50:]):
                        ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")
                        ev = AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                                         username="-", method="http",
                                         kind="http_flood")
                        self._ip_hosts[ip].add(host_id)
                        new_events.append(ev)

        # Detect DDoS: top-5 IPs combined.
        # If the top 5 IPs together are flogging us, time to panic.
        if mon.ddos_detection:
            cutoff = now - 60
            top5_total = sum(
                len([t for t in times if t > cutoff])
                for times in sorted(ip_req_times.values(),
                                    key=lambda x: len(x), reverse=True)[:5]
            )
            if top5_total >= mon.ddos_threshold:
                self._state.ddos_active = True
                self._state.ddos_info = f"{top5_total} req/min across top-5 IPs"
            else:
                self._state.ddos_active = False

        for ev in new_events:
            await self._geoip(ev)
            if mon.campaign_tracking:
                ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events[-30:]))

    def _parse_nginx_line(self, line: str, host_id: str,
                          ip_req_times: dict, ip_statuses: dict
                          ) -> Optional[AttackEvent]:
        """Parse one nginx/apache combined log line, update counters, return event or None."""
        m = _PAT_NGINX_LINE.match(line)
        if not m:
            return None
        ip, ts_raw, method, path, status_str = (
            m.group(1), m.group(2), m.group(3), m.group(4), m.group(5))
        status = int(status_str)

        # Parse timestamp: "02/May/2022:14:23:45 +0000"
        # (nginx really likes to use this format. Historical reasons, probably.)
        try:
            dt = datetime.datetime.strptime(ts_raw[:20], "%d/%b/%Y:%H:%M:%S")
            ts_epoch = dt.timestamp()
            ts = dt.strftime("%b %d %H:%M:%S")
        except Exception as e:
            _log.debug("Failed to parse HTTP timestamp %s: %s: %s", ts_raw[:20], type(e).__name__, e)
            ts_epoch = time.time()
            ts = ts_raw[:20]

        ip_req_times[ip].append(ts_epoch)
        ip_statuses[ip].append(status)

        # Check User-Agent (it's after the status fields; not captured in regex,
        # but we can search the raw line). It's usually a giveaway for bots.
        if _BAD_UA.search(line):
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method="http", kind="bot")

        if method == "POST" and _BRUTE_PATHS.search(path):
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method="POST", kind="http_brute")

        if _EXPLOIT_PATHS.search(path):
            self._ip_hosts[ip].add(host_id)
            self._state.ip_counts[ip] += 1
            return AttackEvent(ts=ts, host_id=host_id, src_ip=ip,
                               username="-", method=method, kind="exploit_scan")

        return None

    async def _poll_connections(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Level 2 - check active TCP connections for floods."""
        new_events: list[AttackEvent] = []
        ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")

        if mon.conn_flood:
            res = await self._pool.run(host_id, _SS_ESTAB_CMD)
            if res.ok:
                ip_conns: dict[str, int] = defaultdict(int)
                for line in res.stdout.splitlines():
                    parts = line.split()
                    if len(parts) >= 2:
                        # remote addr is second field: "ip:port"
                        remote = parts[1].rsplit(":", 1)[0].strip("[]")
                        if remote:
                            ip_conns[remote] += 1
                for ip, count in ip_conns.items():
                    if count >= mon.conn_flood_threshold:
                        self._ip_hosts[ip].add(host_id)
                        self._state.ip_counts[ip] += 1
                        new_events.append(AttackEvent(
                            ts=ts, host_id=host_id, src_ip=ip,
                            username="-", method="tcp",
                            kind="conn_flood", live=True))

        if mon.syn_flood:
            res = await self._pool.run(host_id, _SS_SYNRECV_CMD)
            if res.ok:
                syn_ips: dict[str, int] = defaultdict(int)
                for line in res.stdout.splitlines():
                    parts = line.split()
                    if len(parts) >= 2:
                        remote = parts[1].rsplit(":", 1)[0].strip("[]")
                        if remote:
                            syn_ips[remote] += 1
                # Any IP with > 10 SYN_RECV is suspicious.
                # More than 10 hanging SYN means someone is doing a half-open port scan.
                for ip, count in syn_ips.items():
                    if count >= 10:
                        self._ip_hosts[ip].add(host_id)
                        self._state.ip_counts[ip] += 1
                        new_events.append(AttackEvent(
                            ts=ts, host_id=host_id, src_ip=ip,
                            username="-", method="tcp",
                            kind="syn_flood", live=True))

        for ev in new_events:
            await self._geoip(ev)
            ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events))

    async def _poll_open_ports(self, host_id: str):
        """Level 3 - audit listening ports for dangerous configurations."""
        res = await self._pool.run(host_id, _SS_LISTEN_CMD)
        if not res.ok:
            return
        warnings = []
        for line in res.stdout.splitlines():
            # Format: "0.0.0.0:6379" or "*:6379"
            parts = line.split()
            if not parts:
                continue
            addr = parts[0]
            # extract port
            if ":" in addr:
                port = addr.rsplit(":", 1)[-1]
                bind = addr.rsplit(":", 1)[0]
            else:
                continue
            # Only warn if listening on all interfaces (0.0.0.0, * or ::)
            if bind in ("0.0.0.0", "*", "[::]", "::") and port in _DANGEROUS_PORTS:
                svc, fix = _DANGEROUS_PORTS[port]
                warnings.append({
                    "port": port, "service": svc,
                    "bind": bind, "fix": fix, "host_id": host_id
                })
        # Replace warnings for this host
        self._state.port_warnings = [
            w for w in self._state.port_warnings if w["host_id"] != host_id
        ] + warnings

    async def _poll_email_logs(self, host_id: str, mon: "SecurityMonitoringConfig"):
        """Level 5 - parse Exim4/Postfix logs for email brute-force and user enumeration."""
        # Auto-detect log path: try exim4 mainlog, fall back to postfix mail.log
        log_path = mon.email_log or ""
        if log_path:
            cmd = f"tail -n 300 {log_path} 2>/dev/null"
        else:
            cmd = (
                "tail -n 300 /var/log/exim4/mainlog 2>/dev/null || "
                "tail -n 300 /var/log/mail.log 2>/dev/null"
            )
        res = await self._pool.run(host_id, cmd)
        if not res.ok or not res.stdout.strip():
            return

        # Count AUTH failures per IP
        ip_auth_fails:    dict[str, list] = defaultdict(list)
        ip_rcpt_unknown:  dict[str, int]  = defaultdict(int)
        new_events: list[AttackEvent] = []

        # Patterns for Exim4: "[1.2.3.4]" in lines with "535" or "rejected AUTH"
        # Patterns for Postfix: "SASL ... failure" or "reject: RCPT"
        # (email servers are the most creative when it comes to log formats)
        _pat_exim_auth  = re.compile(r'\[(\d{1,3}(?:\.\d{1,3}){3})\].*?(?:535|rejected AUTH|Incorrect authentication)', re.I)
        _pat_exim_rcpt  = re.compile(r'\[(\d{1,3}(?:\.\d{1,3}){3})\].*?Unknown user', re.I)
        _pat_pfix_auth  = re.compile(r'(?:SASL \w+ authentication failed|reject: .* 535).*?\[(\d{1,3}(?:\.\d{1,3}){3})\]', re.I)
        _pat_pfix_rcpt  = re.compile(r'reject: RCPT.*?\[(\d{1,3}(?:\.\d{1,3}){3})\].*?(?:User unknown|no mailbox)', re.I)
        _pat_ts_exim    = re.compile(r'^(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})')
        _pat_ts_pfix    = re.compile(r'^(\w{3}\s+\d+ \d{2}:\d{2}:\d{2})')

        for line in res.stdout.splitlines():
            # Extract timestamp
            ts = ""
            tm = _pat_ts_exim.search(line)
            if tm:
                ts = tm.group(1)[5:]  # "MM-DD HH:MM:SS"
            else:
                tm = _pat_ts_pfix.search(line)
                ts = tm.group(1) if tm else ""

            if mon.email_brute:
                m = _pat_exim_auth.search(line) or _pat_pfix_auth.search(line)
                if m:
                    ip = m.group(1)
                    ip_auth_fails[ip].append(ts)

            if mon.email_scan:
                m = _pat_exim_rcpt.search(line) or _pat_pfix_rcpt.search(line)
                if m:
                    ip = m.group(1)
                    ip_rcpt_unknown[ip] += 1

        now_ts = datetime.datetime.now(datetime.UTC).strftime("%b %d %H:%M:%S")

        # Emit email_brute events for IPs over threshold
        if mon.email_brute:
            for ip, fails in ip_auth_fails.items():
                if len(fails) < mon.email_brute_threshold:
                    continue
                if self._is_banned_event(ip, now_ts):
                    continue
                if any(e.src_ip == ip and e.kind == "email_brute"
                       for e in list(self._state.events)[-50:]):
                    continue
                last_ts = fails[-1] if fails else now_ts
                ev = AttackEvent(ts=last_ts, host_id=host_id, src_ip=ip,
                                 username="-", method="smtp", kind="email_brute")
                self._ip_hosts[ip].add(host_id)
                self._state.ip_counts[ip] += 1
                new_events.append(ev)

        # Emit email_scan events for IPs doing user enumeration
        if mon.email_scan:
            for ip, count in ip_rcpt_unknown.items():
                if count < 3:  # at least 3 unknown RCPT TO = enumeration
                    continue
                if self._is_banned_event(ip, now_ts):
                    continue
                if any(e.src_ip == ip and e.kind == "email_scan"
                       for e in list(self._state.events)[-50:]):
                    continue
                ev = AttackEvent(ts=now_ts, host_id=host_id, src_ip=ip,
                                 username="-", method="smtp", kind="email_scan")
                self._ip_hosts[ip].add(host_id)
                self._state.ip_counts[ip] += 1
                new_events.append(ev)

        for ev in new_events:
            await self._geoip(ev)
            if hasattr(self._mon(host_id), 'campaign_tracking') and self._mon(host_id).campaign_tracking:
                ev.campaign = len(self._ip_hosts.get(ev.src_ip, set())) > 1
        if new_events:
            self._state.events.extendleft(reversed(new_events[-20:]))

    async def ban_ip_http(self, ip: str, host_ids: list[str]) -> dict[str, bool]:
        """Ban IP in nginx (Level 1 mitigation)."""
        cmd = _NGINX_BAN_CMD.format(ip=ip)
        results = await self._pool.run_on(host_ids, cmd)
        return {hid: r.ok for hid, r in results.items()}

    async def apply_ddos_iptables(self, host_ids: list[str]) -> dict[str, bool]:
        """Level 4 mitigation: apply iptables hashlimit rate-limiting."""
        results = await self._pool.run_on(host_ids, _IPTABLES_RATELIMIT_CMD)
        return {hid: r.ok for hid, r in results.items()}


