_BRAILLE: dict[tuple[int,int], str] = {
    (0,0):" ", (0,1):"⢀", (0,2):"⢠", (0,3):"⢰", (0,4):"⢸",
    (1,0):"⡀", (1,1):"⣀", (1,2):"⣠", (1,3):"⣰", (1,4):"⣸",
    (2,0):"⡄", (2,1):"⣄", (2,2):"⣤", (2,3):"⣴", (2,4):"⣼",
    (3,0):"⡆", (3,1):"⣆", (3,2):"⣦", (3,3):"⣶", (3,4):"⣾",
    (4,0):"⡇", (4,1):"⣇", (4,2):"⣧", (4,3):"⣷", (4,4):"⣿",
}

_HEAT_STOPS = [
    (0,   (0x3f, 0xb9, 0x50)),   # green
    (60,  (0xd2, 0x99, 0x22)),   # amber
    (85,  (0xf8, 0x51, 0x49)),   # red
]


def _heat_color(pct: float) -> str:
    pct = max(0.0, min(100.0, pct))
    for i in range(len(_HEAT_STOPS) - 1):
        t0, c0 = _HEAT_STOPS[i]
        t1, c1 = _HEAT_STOPS[i + 1]
        if pct <= t1:
            ratio = (pct - t0) / (t1 - t0)
            r = int(c0[0] + (c1[0] - c0[0]) * ratio)
            g = int(c0[1] + (c1[1] - c0[1]) * ratio)
            b = int(c0[2] + (c1[2] - c0[2]) * ratio)
            return f"#{r:02x}{g:02x}{b:02x}"
    return f"#{_HEAT_STOPS[-1][1][0]:02x}{_HEAT_STOPS[-1][1][1]:02x}{_HEAT_STOPS[-1][1][2]:02x}"


def _to_level(pct: float) -> int:
    return min(4, int(max(0.0, min(100.0, pct)) * 4 / 100 + 0.5))


def braille_sparkline(history: deque | list, width: int) -> Text:
    vals = list(history)
    if not vals:
        return Text(" " * width, style="dim")

    needed = width * 2
    if len(vals) < needed:
        vals = [vals[0]] * (needed - len(vals)) + vals
    vals = vals[-needed:]

    peak = max(vals) if max(vals) > 0 else 1

    result = Text()
    for i in range(0, needed, 2):
        lv = _to_level(vals[i] / peak * 100)
        rv = _to_level(vals[i + 1] / peak * 100) if i + 1 < len(vals) else 0
        sym = _BRAILLE.get((lv, rv), " ")
        dominant = max(vals[i], vals[i + 1] if i + 1 < len(vals) else 0) / peak * 100
        result.append(sym, style=_heat_color(dominant))
    return result


_BAR_FULL  = "●" # "█"
_BAR_EMPTY = "-" # "░"


def gradient_bar(pct: float, width: int) -> Text:
    pct = max(0.0, min(100.0, pct))
    filled = int(round(pct / 100 * width))
    result = Text()
    for i in range(width):
        cell_pct = (i / width) * 100
        if i < filled:
            result.append(_BAR_FULL, style=_heat_color(cell_pct))
        else:
            result.append(_BAR_EMPTY, style="grey23")
    return result


def pct_color(pct: float) -> str:
    return _heat_color(pct)


def _fmt_size_kb(kb: int) -> str:
    """Human-readable size from kilobytes."""
    if kb >= 1024 * 1024 * 1024:
        return f"{kb / 1024 / 1024 / 1024:.1f}T"
    if kb >= 1024 * 1024:
        return f"{kb / 1024 / 1024:.1f}G"
    if kb >= 1024:
        return f"{kb / 1024:.1f}M"
    return f"{kb}K"


def _parse_size_to_mb(s: str) -> float:
    """Parse du-style size string (e.g. '1.2G', '500M', '3.4T') to MB float."""
    s = s.strip().upper()
    if not s or s == "-":
        return 0.0
    try:
        if s.endswith("T"):
            return float(s[:-1]) * 1024 * 1024
        if s.endswith("G"):
            return float(s[:-1]) * 1024
        if s.endswith("M"):
            return float(s[:-1])
        if s.endswith("K"):
            return float(s[:-1]) / 1024
        return float(s) / 1024 / 1024
    except ValueError as e:
        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
        return 0.0


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: ui / dashboard
# ══════════════════════════════════════════════════════════════════════════════

def fmt_uptime(s: int) -> str:
    if s <= 0: return "-"
    d, r = divmod(s, 86400); h, r = divmod(r, 3600); m = r // 60
    return f"{d}d {h}h" if d else (f"{h}h {m}m" if h else f"{m}m")

def fmt_kb(kb: float) -> str:
    return f"{kb/1024:.1f}MB/s" if kb >= 1024 else f"{kb:.0f}KB/s"


# ── Focusable base panel ──────────────────────────────────────────────────────

class Panel(Static, can_focus=True):
    """Base for all dashboard panels - focusable, Tab-navigable."""

    DEFAULT_CSS = """
    Panel { border: solid $primary-darken-3; padding: 0 1; }
    Panel:focus { border: double $accent; }
    """

    def __init__(self, *args, panel_id: str = "", **kwargs):
        super().__init__(*args, **kwargs)
        self._panel_id = panel_id

    def on_focus(self) -> None:
        self.app.notify_panel_focus(self._panel_id)

    # ←→ keys switch panel focus; ↑↓ handled per-panel
    def on_key(self, event: events.Key) -> None:
        if event.key == "left":
            self.app.action_prev_panel(); event.stop()
        elif event.key == "right":
            self.app.action_next_panel(); event.stop()


