class _HostActionScreen(ModalScreen):
    """Popup: choose SSH shell or File Manager for a host."""

    DEFAULT_CSS = """
    _HostActionScreen { align: center middle; }
    #hact-box {
        width: 48; height: 10;
        border: round $accent;
        background: $surface;
        padding: 1 2;
    }
    #hact-box { border-title-color: $accent; border-title-style: bold; }
    #hact-title { height: 2; color: $text; text-style: bold; }
    #hact-list  { height: 5; }
    """

    BINDINGS = [Binding("escape", "dismiss_none", "Cancel", show=False)]

    def __init__(self, label: str, **kwargs):
        super().__init__(**kwargs)
        self._label = label

    def compose(self) -> ComposeResult:
        with Container(id="hact-box"):
            yield Static(f"  {self._label}", id="hact-title")
            with ListView(id="hact-list"):
                yield ListItem(Static("  >_  Open SSH Shell"), id="hact-ssh")
                yield ListItem(Static("  📂  Open File Manager"), id="hact-fm")

    def on_mount(self) -> None:
        self.query_one("#hact-box").border_title = "Connect to host"
        self.query_one("#hact-list").focus()

    def on_list_view_selected(self, event: ListView.Selected) -> None:
        self.dismiss(event.item.id)

    def action_dismiss_none(self) -> None:
        self.dismiss(None)


class ServerCard(Panel):
    DEFAULT_CSS = """
    ServerCard {
        border: solid $primary-darken-2;
        padding: 0 1;
        height: auto;
        min-width: 30;
    }
    ServerCard.online  { border: solid $success-darken-1; }  /* green = all good */
    ServerCard.warn    { border: solid $warning-darken-1; }  /* yellow = "we're watching you" */
    ServerCard.offline { border: solid $error-darken-1; }    /* red = oh no */
    ServerCard:focus   { border: double $accent; }
    """

    def __init__(self, host_id: str, label: str, address: str,
                 cfg: AppConfig, **kwargs):
        super().__init__(" ", panel_id=f"card:{host_id}", **kwargs)
        self.host_id = host_id
        self._label  = label
        self._addr   = address
        self._cfg    = cfg

    def on_resize(self, event) -> None:
        # re-render when the card is resized so bars fill correctly
        self.app.call_after_refresh(self.app._do_tick)

    def on_focus(self) -> None:
        super().on_focus()
        self.border_subtitle = "\\[o]pen \\[a]i \\[m]aint  \\[F2]SSH  \\[f]iles  Enter:menu"

    def on_blur(self) -> None:
        self.border_subtitle = ""

    def on_click(self, event: events.Click) -> None:
        # _show_host_action() disabled — use F2 (SSH) or Ctrl+F (FM) shortcuts instead
        # self._show_host_action()
        event.stop()

    def on_key(self, event: events.Key) -> None:
        if event.key == "m":
            action = getattr(self.app, "action_toggle_maintenance", None)
            if callable(action):
                action()
            event.stop()
        elif event.key == "a":
            action = getattr(self.app, "action_toggle_ai_controlled", None)
            if callable(action):
                action()
            event.stop()
        elif event.key == "o":
            action = getattr(self.app, "action_edit_host", None)
            if callable(action):
                action()
            event.stop()
        elif event.key == "enter":
            # _show_host_action() disabled — use F2 (SSH) or Ctrl+F (FM) shortcuts instead
            # self._show_host_action()
            event.stop()
        elif event.key == "f2":
            self._launch_ssh()
            event.stop()
        elif event.key == "ctrl+f" or event.key == "f":
            self._launch_fm()
            event.stop()
        # ←→ and other keys bubble up to Panel base handler

    def _show_host_action(self) -> None:
        pool = getattr(self.app, "_pool", None)
        if not pool:
            return
        label = self._label
        def _on_action(act: Optional[str]) -> None:
            if act == "hact-ssh":
                self._launch_ssh()
            elif act == "hact-fm":
                self._launch_fm()
        self.app.push_screen(_HostActionScreen(label), _on_action)

    def _launch_ssh(self) -> None:
        pool = getattr(self.app, "_pool", None)
        if pool:
            self.app.push_screen(SshShellScreen(pool, self.host_id))

    def _launch_fm(self) -> None:
        pool = getattr(self.app, "_pool", None)
        if pool:
            self.app.push_screen(FileManagerScreen(pool, initial_host_id=self.host_id))

    def update_data(self, state, metrics: HostMetrics, services: list[ServiceInfo]):
        # size.width is 0 before first paint; fall back to a safe default
        raw_w = self.size.width or self.content_size.width or 38
        w     = max(30, raw_w)
        bar   = max(10, w - 14)
        t   = Text()
        focused = self.has_focus

        if state.state == ConnState.CONNECTED:
            dot, col = "●", "green"
            self.remove_class("offline", "warn"); self.add_class("online")
        elif state.state == ConnState.CONNECTING:
            dot, col = "◌", "yellow"
            self.remove_class("offline", "online"); self.add_class("warn")
        else:
            dot, col = "✗", "red"
            self.remove_class("online", "warn"); self.add_class("offline")

        cursor = "▶ " if focused else "  "
        tag    = f" [{'+'.join(state.config.tags[:2])}]" if state.config.tags else ""
        maint  = " 🔧" if state.config.maintenance else ""
        ai_ctl = " 🤖" if state.config.ai_controlled else ""
        t.append(cursor, style=f"bold {CLR_CURSOR}" if focused else "grey50")
        t.append(f"{dot} ", style=col)
        t.append(f"{self._label}{tag}{maint}{ai_ctl}\n", style="bold white")
        t.append(f"   {self._addr}  {fmt_uptime(metrics.uptime_s)}\n", style="grey50")

        if state.state != ConnState.CONNECTED:
            t.append(f"   {(state.error or state.state.value)[:w-4]}\n", style="red")
            self.update(t); return
        if metrics.error:
            t.append(f"   {metrics.error}\n", style="yellow")
            self.update(t); return

        t.append(" CPU ", style=CLR_METRIC)
        t.append_text(gradient_bar(metrics.cpu_pct, bar))
        t.append(f" {metrics.cpu_pct:4.1f}%  L{metrics.load1:.2f}\n",
                 style=pct_color(metrics.cpu_pct))

        t.append(" RAM ", style=CLR_METRIC)
        t.append_text(gradient_bar(metrics.ram_pct, bar))
        t.append(f" {metrics.ram_pct:4.1f}%\n", style=pct_color(metrics.ram_pct))

        t.append("Disk ", style=CLR_METRIC)
        t.append_text(gradient_bar(metrics.disk_pct, bar))
        t.append(f" {metrics.disk_pct:4.1f}%\n", style=pct_color(metrics.disk_pct))

        t.append(" net ", style=CLR_METRIC)
        t.append_text(braille_sparkline(metrics.net_rx_hist, bar // 2))
        t.append(f" ↑{fmt_kb(metrics.net_tx_kb)} ↓{fmt_kb(metrics.net_rx_kb)}\n",
                 style="grey50")

        # Mail queue (exim4 / postfix) - throughput in msgs/min
        if metrics.mail_mta_type:
            mta_name = "📧" if metrics.mail_mta_type == "exim4" else "📮"
            t.append(" mta ", style=CLR_METRIC)
            t.append_text(braille_sparkline(metrics.mail_queue_hist, bar // 2))
            # Dynamic coloring: red if > 8 msgs/min (~500/h), yellow if trending up
            if metrics.mail_throughput_mpm > 8:
                status_color = "red"
            elif len(metrics.mail_queue_hist) > 1 and metrics.mail_throughput_mpm > metrics.mail_queue_hist[-2]:
                status_color = "yellow"  # throughput increasing
            else:
                status_color = "green"
            t.append(f" {mta_name} {metrics.mail_throughput_mpm:5.1f}msgs/m\n",
                     style=status_color)

        if services:
            t.append(" svc ", style=CLR_METRIC)
            for svc in sorted(services, key=_svc_sort_key)[:8]:
                t.append(f"{svc.status_char}{svc.name[:10]} ", style=svc.status_color)
            if len(services) > 8:
                t.append(f"+{len(services)-8}", style="grey50")
            t.append("\n")

        if metrics.ssl_certs:
            t.append(" ssl ", style=CLR_METRIC)
            for domain, days in list(metrics.ssl_certs.items())[:3]:
                short = domain[:12] if len(domain) > 12 else domain
                if days < 0:
                    t.append(f"{short}:err ", style="red")
                elif days <= 7:
                    t.append(f"{short}:{days}d ", style="bold red")
                elif days <= 14:
                    t.append(f"{short}:{days}d ", style="bold yellow")
                elif days <= 30:
                    t.append(f"{short}:{days}d ", style="yellow")
                else:
                    t.append(f"{short}:{days}d ", style="green")
            t.append("\n")

        if metrics.apt_info:
            ai = metrics.apt_info
            os_short = ai.os_version[:20] if len(ai.os_version) > 20 else ai.os_version
            t.append("  os ", style=CLR_METRIC)
            t.append(f"{os_short}  ", style="grey70")
            if ai.security_count:
                t.append(f"🔒{ai.security_count} ", style="bold red")
            if ai.total_count:
                t.append(f"⬆{ai.total_count}", style="yellow" if not ai.security_count else "bold yellow")
            elif ai.total_count == 0 and ai.last_checked:
                t.append("✓upd", style="green")
            t.append("\n")

        if metrics.docker_containers:
            running = [c for c in metrics.docker_containers if "Up" in c.status]
            total   = len(metrics.docker_containers)
            t.append(" dkr ", style=CLR_METRIC)
            t.append(f"[D] {len(running)}/{total} ", style="cyan" if running else "grey50")
            for c in running[:3]:
                short_name = c.name[:10]
                t.append(f"{short_name} ", style="cyan")
            if len(running) > 3:
                t.append(f"+{len(running)-3}", style="grey50")
            t.append("\n")

        self.update(t)


# ── Ban Scope Selector ────────────────────────────────────────────────────────

class BanSelectScreen(ModalScreen):
    """Modal dialog: choose ban scope (IP/subnet) and host scope (detected/all)."""

    DEFAULT_CSS = """
    BanSelectScreen { align: center middle; }
    #ban-box {
        border: solid $error;
        background: $surface;
        width: 60;
        padding: 1 2;
    }
    """

    _scope: reactive[str] = reactive("detected")   # "detected" | "all"

    def __init__(self, ip: str,
                 detected_hosts: list[str] | None = None,
                 all_hosts:      list[str] | None = None):
        super().__init__()
        self._ip             = ip
        self._detected_hosts = detected_hosts or []
        self._all_hosts      = all_hosts      or []
        self._net24 = self._net16 = None
        try:
            addr = ipaddress.ip_address(ip)
            if isinstance(addr, ipaddress.IPv4Address):
                p = ip.split('.')
                self._net24 = f"{p[0]}.{p[1]}.{p[2]}.0/24"
                self._net16 = f"{p[0]}.{p[1]}.0.0/16"
        except ValueError as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())
            pass
        # Pre-compute safety warnings for each ban scope
        guard = SafetyGuard.get()
        self._warn_ip  = guard.check_ban_target(ip)
        self._warn_24  = guard.check_ban_target(self._net24) if self._net24 else []
        self._warn_16  = guard.check_ban_target(self._net16) if self._net16 else []

    def _scope_text(self) -> str:
        det_n = len(self._detected_hosts)
        all_n = len(self._all_hosts)
        det_lbl = (", ".join(self._detected_hosts[:3]) +
                   (f" +{det_n-3}" if det_n > 3 else "")) if self._detected_hosts else "?"
        if self._scope == "detected":
            return (f"  Hosts: [bold white]\\[d][/] detected ({det_n}: {det_lbl})  "
                    f"[dim]\\[a] all ({all_n})[/]")
        else:
            return (f"  Hosts: [dim]\\[d] detected ({det_n})[/]  "
                    f"[bold white]\\[a][/] [bold yellow]ALL ({all_n} hosts)[/]")

    def _current_hosts(self) -> list[str]:
        if self._scope == "detected" and self._detected_hosts:
            return self._detected_hosts
        return self._all_hosts

    def compose(self) -> ComposeResult:
        with Container(id="ban-box"):
            yield Static(f"[bold red]⚡ Ban scope[/]  [dim]source:[/] [cyan]{self._ip}[/]")
            yield Static(f"[grey23]{'─' * 56}[/]")
            ip_suffix = "  [bold red]⚠ YOUR IP![/]" if self._warn_ip else ""
            yield Static(f"  [bold white]\\[i][/]  Ban this IP      [cyan]{self._ip}[/]{ip_suffix}")
            if self._net24:
                n24_suffix = "  [bold red]⚠ YOUR SUBNET![/]" if self._warn_24 else ""
                yield Static(f"  [bold white]\\[s][/]  Ban /24 subnet   [yellow]{self._net24}[/]{n24_suffix}")
            if self._net16:
                n16_suffix = "  [bold red]⚠ YOUR SUBNET![/]" if self._warn_16 else ""
                yield Static(f"  [bold white]\\[w][/]  Ban /16 subnet   [yellow]{self._net16}[/]{n16_suffix}")
            yield Static(f"[grey23]{'─' * 56}[/]")
            yield Static(self._scope_text(), id="ban-scope-line")
            yield Static(f"[grey23]{'─' * 56}[/]")
            yield Static(f"  [dim]Operator IPs: {SafetyGuard.get().summary()}[/]")
            yield Static("  [dim][Esc] cancel[/]")

    def watch__scope(self, _: str) -> None:
        try:
            self.query_one("#ban-scope-line", Static).update(self._scope_text())
        except Exception:
            pass

    def on_key(self, event: events.Key) -> None:
        if event.key == "d":
            self._scope = "detected"
        elif event.key == "a":
            self._scope = "all"
        elif event.key == "i":
            self.dismiss((self._ip, self._current_hosts()))
        elif event.key == "s" and self._net24:
            self.dismiss((self._net24, self._current_hosts()))
        elif event.key == "w" and self._net16:
            self.dismiss((self._net16, self._current_hosts()))
        elif event.key == "escape":
            self.dismiss(None)
        event.stop()


# ── Attack Radar ──────────────────────────────────────────────────────────────

class AttackRadarPanel(Panel):
    DEFAULT_CSS = """
    AttackRadarPanel {
        border: solid $error-darken-1;
        padding: 0 1;
        height: 1fr;
    }
    AttackRadarPanel:focus { border: double $accent; }
    """

    selected: reactive[int] = reactive(0)

    def __init__(self, **kwargs):
        super().__init__(" ", panel_id="radar", **kwargs)
        self._events:  list[AttackEvent] = []
        self._grouped: list[tuple[str, dict]] = []  # [(ip, info), ...] newest first
        self._rate   = 0.0
        self._banned = 0
        self._host_labels: dict[str, str] = {}
        self._ddos_active: bool = False
        self._ddos_info:   str  = ""
        self._port_warnings: list = []
        self._ip_hosts: dict[str, set] = {}   # ip → set of host_ids where detected
        # (useful for spotting coordinated attacks across multiple servers)

    def on_mount(self) -> None:
        self._redraw()

    def on_resize(self, event) -> None:
        self._redraw()

    def update_data(self, events: list[AttackEvent], rate: float, banned: int,
                    host_labels: dict[str, str] | None = None,
                    ddos_active: bool = False, ddos_info: str = "",
                    port_warnings: list | None = None,
                    ip_hosts: dict[str, set] | None = None):
        self._events = list(events)
        self._rate   = rate
        if ip_hosts is not None:
            self._ip_hosts = ip_hosts
        self._banned = banned
        self._ddos_active = ddos_active
        self._ddos_info   = ddos_info
        if port_warnings is not None:
            self._port_warnings = port_warnings
        if host_labels is not None:
            self._host_labels = host_labels
        # Build grouped view: one entry per source IP (newest-first by kind/time)
        groups: dict[str, dict] = {}
        for ev in self._events:
            if ev.src_ip not in groups:
                groups[ev.src_ip] = {
                    'cc': ev.country or '??',
                    'count': 0,
                    'last_ts': ev.ts,
                    'kind': ev.kind,
                    'campaign': False,
                    'host_id': ev.host_id,
                    'live': ev.live,
                }
            g = groups[ev.src_ip]
            g['count'] += ev.count
            g['last_ts'] = ev.ts  # events are oldest-first; last seen = most recent
            g['host_id'] = ev.host_id  # track most recent target host
            if ev.country and ev.country not in ('??', ''):
                g['cc'] = ev.country
            if ev.kind == "brute":  # escalate severity
                g['kind'] = "brute"
            if ev.campaign:
                g['campaign'] = True
        self._grouped = sorted(groups.items(), key=lambda x: x[1]['last_ts'], reverse=True)
        if self._grouped:
            self.selected = min(self.selected, len(self._grouped) - 1)
        self._redraw()

    def watch_selected(self, _: int) -> None:
        self._redraw()

    # Header occupies: border-top(1) + title line(1) + separator line(1) = 3 rows
    _HEADER_ROWS = 3

    def on_click(self, event: events.Click) -> None:
        row = event.y - self._HEADER_ROWS  # rows are now always 1 line each (content is trimmed)
        if not self._grouped or row < 0:
            return
        if row < min(len(self._grouped), 16):
            self.selected = row
            self.focus()   # focus after selected so on_focus redraws with correct row
            event.stop()

    def on_focus(self) -> None:
        super().on_focus()
        self.border_subtitle = "\\[b]an  \\[a]i  \\[l]ogs  \\[1-4]mitigate"
        self._redraw()

    def on_blur(self) -> None:
        self.border_subtitle = ""
        self._redraw()

    def on_key(self, event: events.Key) -> None:
        if event.key == "up":
            self.selected = max(0, self.selected - 1)
            event.stop()
        elif event.key == "down":
            max_idx = min(len(self._grouped), 16) - 1 if self._grouped else 0
            self.selected = min(max_idx, self.selected + 1) if self._grouped else 0
            event.stop()
        elif event.key in ("enter", "b"):
            self._ban_selected(); event.stop()
        elif event.key == "1":
            asyncio.create_task(self._mitigate_iptables()); event.stop()
        elif event.key == "2":
            asyncio.create_task(self._mitigate_nginx_ban()); event.stop()
        elif event.key == "3":
            self._ban_top_ip(); event.stop()
        elif event.key == "4":
            self._ban_top_subnet24(); event.stop()
        elif event.key == "a":
            asyncio.create_task(self._ai_analyze_selected()); event.stop()
        elif event.key == "l":
            asyncio.create_task(self._show_log_lines_selected()); event.stop()
        # ←→ bubbles to base Panel → app nav

    def _ban_selected(self):
        if not self._grouped: return
        visible = self._grouped[:16]
        if 0 <= self.selected < len(visible):
            ip = visible[self.selected][0]
            detected = sorted(self._ip_hosts.get(ip, set()))
            all_hosts = sorted(self.app._pool.host_ids())
            def _do_ban(result):
                if result:
                    target, host_ids = result
                    self.app.trigger_ban(target, host_ids=host_ids)
            self.app.push_screen(
                BanSelectScreen(ip, detected_hosts=detected, all_hosts=all_hosts),
                _do_ban)

    async def _mitigate_iptables(self):
        try:
            host_ids = list(self.app._pool.host_ids())
            results = await self.app._radar.apply_ddos_iptables(host_ids)
            ok = sum(1 for v in results.values() if v)
            self.app.notify(f"iptables rate-limit applied on {ok}/{len(results)} hosts",
                            severity="information")
        except Exception as e:
            _log.warning("iptables rate-limit application failed: %s: %s", type(e).__name__, e)
            self.app.notify(f"iptables mitigation failed: {e}", severity="error")

    async def _mitigate_nginx_ban(self):
        try:
            if not self._grouped:
                return
            top_ip = self._grouped[0][0]
            host_ids = list(self.app._pool.host_ids())
            results = await self.app._radar.ban_ip_http(top_ip, host_ids)
            ok = sum(1 for v in results.values() if v)
            self.app.notify(f"nginx ban {top_ip} on {ok}/{len(results)} hosts",
                            severity="information")
        except Exception as e:
            _log.warning("nginx IP ban failed: %s: %s", type(e).__name__, e)
            self.app.notify(f"nginx ban failed: {e}", severity="error")

    def _ban_top_ip(self):
        if not self._grouped:
            return
        ip = self._grouped[0][0]
        def _do_ban(target):
            if target:
                self.app.trigger_ban(target)
        self.app.push_screen(BanSelectScreen(ip), _do_ban)

    async def _ai_analyze_selected(self):
        """'a' key - AI instant analysis popup for the selected IP."""
        if not self._grouped:
            return
        visible = self._grouped[:16]
        if not (0 <= self.selected < len(visible)):
            return
        ip, info = visible[self.selected]
        try:
            engine = self.app._pool.ai_engine
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify("AI engine not available", severity="warning")
            return
        if not engine.enabled:
            self.app.notify("AI disabled - configure in F6 → 🤖 AI", severity="warning")
            return
        self.app.notify(f"⟳ AI analyzing {ip}…")
        events_for_ip = [e for e in self._events if e.src_ip == ip][-20:]
        host_id = info.get("host_id", "")
        ctx = AIAttackContext(
            host_id       = host_id,
            label         = self._host_labels.get(host_id, host_id),
            address       = "",
            attack_events = events_for_ip,
        )
        raw = await engine.call(
            ctx.to_prompt_block(max_events=20),
            system = ctx.format_system(),
            tier   = "fast",
        )
        if raw == engine.DISABLED:
            self.app.notify("AI disabled", severity="warning")
            return
        title = f"🤖 AI Analysis - {ip}  ({info.get('cc','?')})"
        self.app.push_screen(AiAnalysisPopup(title, raw))

    async def _show_log_lines_selected(self):
        """'l' key - show last raw log lines mentioning the selected IP."""
        if not self._grouped:
            return
        visible = self._grouped[:16]
        if not (0 <= self.selected < len(visible)):
            return
        ip, info = visible[self.selected]
        host_id = info.get("host_id", "")
        self.app.notify(f"⟳ Loading logs for {ip}…")
        cmd = (
            f"grep -F '{ip}' "
            "/var/log/auth.log /var/log/fail2ban.log /var/log/ufw.log "
            "/var/log/nginx/access.log /var/log/nginx/error.log "
            "/var/log/syslog 2>/dev/null | tail -50"
        )
        try:
            res = await self.app._pool.run(host_id, cmd)
        except Exception as e:
            self.app.notify(f"Log fetch failed: {e}", severity="error")
            return
        raw_lines = res.stdout.strip() if res.ok and res.stdout.strip() else "(no log lines found)"
        # Escape Rich markup brackets so log lines render literally
        body = raw_lines.replace("[", "\\[")
        host_lbl = self._host_labels.get(host_id, host_id)
        title = f"📋 Logs for {ip}  ({info.get('cc','?')})  [{host_lbl}]"
        self.app.push_screen(AiAnalysisPopup(title, body))

    def _ban_top_subnet24(self):
        if not self._grouped:
            return
        ip = self._grouped[0][0]
        try:
            parts = ip.split('.')
            if len(parts) == 4:
                subnet = f"{parts[0]}.{parts[1]}.{parts[2]}.0/24"
                self.app.trigger_ban(subnet)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _redraw(self):
        focused  = self.has_focus
        rate_col = "red" if self._rate > 10 else "yellow" if self._rate > 3 else "green"
        # Available width: panel width minus border (2) and padding (2)
        avail_w = max(30, self.size.width - 4) if self.size.width else 60
        t = Text()

        cursor = "▶ " if focused else "  "
        t.append(f"{cursor}⚡ ATTACK RADAR  ", style="bold red")
        t.append(f"{self._rate:.0f}/min", style=rate_col)
        t.append(f"  banned:{self._banned}", style="grey50")
        if focused:
            t.append("  ↑↓:select  b/Enter:ban IP", style="grey35")
        t.append("\n─" + "─" * (avail_w - 1) + "\n", style="grey23")

        if self._ddos_active:
            t.append(f"  ⚠ DDoS: {self._ddos_info}\n", style="bold red")
            t.append("  [1]iptables  [2]nginx-limit  [3]ban-top  [4]+/24\n",
                     style="grey50")

        _KIND_COLOR = {
            "brute": "red", "breakin": "red", "http_brute": "red", "syn_flood": "red",
            "http_flood": "bold yellow", "conn_flood": "yellow",
            "exploit_scan": "magenta", "bot": "cyan",
            "scan": "yellow",
            "email_brute": "bold red", "email_scan": "magenta",
        }

        if not self._grouped:
            t.append("  No events yet...\n", style="grey50 italic")
        else:
            visible = self._grouped[:16]
            for i, (ip, info) in enumerate(visible):
                sel  = focused and i == self.selected
                ts   = info['last_ts'].split()[-1] if " " in info['last_ts'] else info['last_ts']
                ts   = ts[-8:] if len(ts) > 8 else ts
                kc   = _KIND_COLOR.get(info['kind'], "yellow")
                camp = "⚡" if info['campaign'] else " "
                live_flag = info.get('live', False)
                cnt  = info['count']
                # Build row as plain string to measure/trim to avail_w, then append styled parts
                # Fixed layout: 2+2+1+15+6+6+9+8 = 49 chars minimum
                # Dynamically shrink host_lbl if panel is narrow
                host_lbl = self._host_labels.get(info['host_id'], info['host_id'])
                # row = 2(sel) + 3(cc+sp) + 15(ip) + 6(kind) + 6(cnt) + host + 1(sp) + 8(ts)
                fixed_w = 2 + 3 + 15 + 6 + 6 + 1 + 8  # = 41
                host_max = max(1, avail_w - fixed_w)
                host_lbl = host_lbl[:host_max]
                # Pad or truncate
                host_lbl = f"{host_lbl:<{host_max}}"
                if sel:
                    t.append("▶ ", style=f"bold {CLR_CURSOR}")
                elif live_flag:
                    t.append(" 🔴", style="red")
                else:
                    t.append(f" {camp}",
                             style=("red" if info['campaign'] else "grey50"))
                t.append(f"{info['cc']:>2} ", style="bold grey70" if sel else "grey50")
                t.append(f"{ip:<15}", style=f"bold {CLR_ACCENT}" if sel else CLR_ACCENT)
                t.append(f"{info['kind'][:5]:<6}", style=kc)
                t.append(f"{cnt:>3}×  ", style="bold white" if sel else "grey85")
                t.append(host_lbl + " ", style=f"bold {CLR_HOST_SEL}" if sel else CLR_HOST_LBL)
                t.append(f"{ts}\n", style="grey50")

        if self._port_warnings:
            t.append("\n─ Port Audit ─\n", style="grey23")
            for w in self._port_warnings[:5]:
                t.append(f"  ⚠ :{w['port']} {w['service']} on {w['bind']}\n",
                         style="yellow")
                t.append(f"    Fix: {w['fix']}\n", style="grey50")

        self.update(t)


