# SECTION: notification_manager  (v0.2)
# Sends alerts on HOST_DOWN / HOST_UP / SERVICE_FAILED / SERVICE_RECOVERED
# Channels: sound (built-in beep), Telegram, email (SMTP), webhook (HTTP POST)
# ══════════════════════════════════════════════════════════════════════════════

def _beep():
    """
    Cross-platform terminal beep - no external files or tools needed.
    Plays two short tones using the ANSI BEL character via sys.stdout.
    On most terminals and OSes this triggers the system notification sound.
    On Windows also tries winsound for a cleaner двотональний сигнал.
    """
    try:
        if platform.system() == "Windows":
            import winsound as _ws
            _ws.Beep(880, 120)   # A5 - короткий високий
            _ws.Beep(660, 180)   # E5 - трохи нижче, довший
        else:
            # ANSI BEL twice with a small gap - більшість терміналів програють системний звук
            sys.stdout.write("\a")
            sys.stdout.flush()
            import time as _t; _t.sleep(0.15)
            sys.stdout.write("\a")
            sys.stdout.flush()
    except Exception as e:
        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
        pass

import smtplib
import urllib.request
from email.mime.text import MIMEText


class NotificationManager:
    """
    Subscribes to AgentPool events and dispatches notifications.
    Channels controlled by AppConfig flags.
    Call attach(pool) once after pool.start().
    """

    # Events that trigger alerts
    _ALERT_KINDS = {
        "HOST_DOWN", "HOST_UP",
        "SERVICE_FAILED", "SERVICE_RECOVERED",
        "CPU_WARN", "CPU_CRITICAL",
        "RAM_WARN", "RAM_CRITICAL",
        "DISK_WARN", "DISK_CRITICAL",
        "AI_NOTIFICATION",   # send_notification / escalate_to_human from _ai_managed_loop
    }

    def __init__(self, app_cfg: AppConfig):
        self._cfg = app_cfg

    def attach(self, pool: "AgentPool"):
        """Register event handlers on every agent in the pool."""
        for agent in pool.all_agents():
            self._subscribe(agent)
        # also hook into future add_host calls
        pool._notif_manager = self

    def _subscribe(self, agent: "HostAgent"):
        for kind_str in self._ALERT_KINDS:
            try:
                kind = EventKind[kind_str]
                agent.on_event(kind, self._handle)
            except (KeyError, AttributeError) as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    async def _handle(self, event: "AgentEvent"):
        cfg = self._cfg
        host  = event.host_id
        kind  = event.kind.name if hasattr(event.kind, "name") else str(event.kind)
        payload = getattr(event, "payload", {})
        # threshold events carry a human-readable detail in payload
        detail = payload.get("detail", "") if isinstance(payload, dict) else ""
        if not detail:
            detail = getattr(event, "detail", "")
        msg   = f"[Deflect One] {kind} on {host}"
        if detail:
            msg += f": {detail}"

        loop = asyncio.get_running_loop()

        if cfg.sound_enabled:
            await loop.run_in_executor(None, _beep)

        if cfg.tg_token and cfg.tg_chat:
            asyncio.create_task(self._send_telegram(cfg.tg_token, cfg.tg_chat, msg))

        if cfg.smtp_host and cfg.smtp_to:
            asyncio.create_task(self._send_email(cfg, msg))

        if cfg.webhook_url:
            asyncio.create_task(self._send_webhook(cfg.webhook_url, host, kind, detail))

    @staticmethod
    async def _send_telegram(token: str, chat_id: str, text: str):
        try:
            url  = f"https://api.telegram.org/bot{token}/sendMessage"
            data = json.dumps({"chat_id": chat_id, "text": text}).encode()
            req  = urllib.request.Request(url, data=data,
                                          headers={"Content-Type": "application/json"})
            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, lambda: urllib.request.urlopen(req, timeout=10))
        except Exception as e:
            _log.error("Failed to send Telegram notification: %s: %s", type(e).__name__, e)

    @staticmethod
    async def _send_email(cfg: "AppConfig", body: str):
        try:
            msg       = MIMEText(body)
            msg["Subject"] = body[:80]
            msg["From"]    = cfg.smtp_from or cfg.smtp_user
            msg["To"]      = cfg.smtp_to

            def _smtp():
                with smtplib.SMTP(cfg.smtp_host, cfg.smtp_port, timeout=15) as s:
                    s.ehlo()
                    s.starttls()
                    if cfg.smtp_user:
                        s.login(cfg.smtp_user, cfg.smtp_password)
                    s.sendmail(msg["From"], [cfg.smtp_to], msg.as_string())

            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, _smtp)
        except Exception as e:
            _log.error("Failed to send email notification to %s: %s: %s",
                      cfg.smtp_to, type(e).__name__, e)

    @staticmethod
    async def _send_webhook(url: str, host: str, kind: str, detail: str):
        try:
            payload = json.dumps({
                "host": host, "event": kind, "detail": detail,
                "ts":   time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
            }).encode()
            req = urllib.request.Request(url, data=payload,
                                         headers={"Content-Type": "application/json"})
            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, lambda: urllib.request.urlopen(req, timeout=10))
        except Exception as e:
            _log.error("Failed to send webhook notification to %s: %s: %s",
                      url, type(e).__name__, e)


