# ── Safety footer - appended to every system prompt ──────────────────────────
# Non-negotiable constraints injected into every LLM instruction set.
# Must never be omitted or weakened in any template.
_SAFE_FOOTER = (
    "\n\nSafety constraints - non-negotiable:\n"
    "· Never suggest commands that permanently delete data (rm -rf, DROP TABLE, "
    "truncate, wipefs, shred) without a ⚠️ WARNING prefix on the same line.\n"
    "· Never recommend banning, blocking, or rate-limiting the administrator's "
    "own IP address or subnet.\n"
    "· Never recommend disabling SSH, the firewall, fail2ban, or any active "
    "security service.\n"
    "· When uncertain - state your uncertainty explicitly instead of inventing facts."
)

