# SECTION: docker_port_editor  (v0.1)
# "p" key in DockerScreen - edit port mappings of an existing container.
# Since Docker doesn't support live port changes, the container is stopped,
# committed to a temp image, removed, then re-run with the new port list.
# ══════════════════════════════════════════════════════════════════════════════

class DockerPortEditorScreen(ModalScreen):
    """
    Edit port mappings of an existing Docker container.
    Keys:
      Tab / Shift+Tab  - move between fields
      Enter            - add port / apply
      Esc              - cancel
    """

    DEFAULT_CSS = """
    DockerPortEditorScreen { align: center middle; }
    #dpe-box {
        width: 72; height: auto;
        border: double $accent;
        background: $surface;
        padding: 1 2;
    }
    #dpe-title  { text-style: bold; color: $accent; margin-bottom: 1; }
    #dpe-warn   { color: $warning; margin-bottom: 1; }
    #dpe-list   { height: auto; min-height: 2; margin-bottom: 1; }
    .dpe-row    { height: 1; }
    .dpe-lbl    { color: #888780; margin-top: 1; height: 1; }
    #dpe-inputs { height: 3; margin-top: 1; }
    #dpe-hport  { width: 12; }
    #dpe-sep    { width: 3; content-align: center middle; color: $text-muted; }
    #dpe-cport  { width: 12; }
    #dpe-proto  { width: 8; }
    #dpe-add-btn { min-width: 8; margin-left: 1; }
    #dpe-btn-row { margin-top: 2; height: 3; }
    Button { margin-right: 1; min-width: 14; }
    """

    def __init__(self, pool, host_id: str, container: ContainerInfo, **kwargs):
        super().__init__(**kwargs)
        self._pool      = pool
        self._host_id   = host_id
        self._container = container
        self._ports     = self._parse_ports(container.ports)  # list of [hport, cport, proto]

    # ── helpers ───────────────────────────────────────────────────────────────

    @staticmethod
    def _parse_ports(ports_str: str) -> list:
        import re
        result = []
        seen   = set()
        for m in re.finditer(r"(?:[0-9.:]+):(\d+)->(\d+)/(tcp|udp)", ports_str or ""):
            key = (m.group(1), m.group(2), m.group(3))
            if key not in seen:
                seen.add(key)
                result.append(list(key))
        return result

    def _render_port_list(self):
        try:
            lst = self.query_one("#dpe-list")
            lst.remove_children()
            if not self._ports:
                lst.mount(Static("  (no port mappings)", classes="dpe-row"))
            for i, (hp, cp, proto) in enumerate(self._ports):
                row = Horizontal(classes="dpe-row")
                row.mount(Static(f"  {hp}:{cp}/{proto}", classes="dpe-row"))
                btn = Button("✕", id=f"dpe-rm-{i}", variant="error")
                btn.styles.min_width = 4
                row.mount(btn)
                lst.mount(row)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── compose ───────────────────────────────────────────────────────────────

    def compose(self) -> ComposeResult:
        with Container(id="dpe-box"):
            yield Static(f"🐳  Port Mappings: {self._container.name}", id="dpe-title")
            yield Static(
                "⚠  Container will be stopped and recreated to apply changes.",
                id="dpe-warn")
            yield Static("Current mappings:", classes="dpe-lbl")
            yield Container(id="dpe-list")
            yield Static("Add mapping  (host_port : container_port)", classes="dpe-lbl")
            with Horizontal(id="dpe-inputs"):
                yield Input(placeholder="2222", id="dpe-hport", max_length=5)
                yield Static("→", id="dpe-sep")
                yield Input(placeholder="22",   id="dpe-cport", max_length=5)
                yield Input(value="tcp",        id="dpe-proto", max_length=4)
                yield Button("Add", id="dpe-add-btn", variant="primary")
            with Horizontal(id="dpe-btn-row"):
                yield Button("▶ Apply & Recreate", variant="primary",  id="dpe-apply")
                yield Button("Cancel",             variant="error",    id="dpe-cancel")

    def on_mount(self):
        self._render_port_list()
        try:
            self.query_one("#dpe-hport", Input).focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── events ────────────────────────────────────────────────────────────────

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id or ""
        if bid == "dpe-cancel":
            self.dismiss(None)
        elif bid == "dpe-apply":
            self.dismiss(None)
            asyncio.create_task(self._recreate())
        elif bid == "dpe-add-btn":
            self._add_port()
        elif bid.startswith("dpe-rm-"):
            idx = int(bid.split("-")[-1])
            if 0 <= idx < len(self._ports):
                self._ports.pop(idx)
                self._render_port_list()

    def on_input_submitted(self, event) -> None:
        if event.input.id == "dpe-hport":
            try:
                self.query_one("#dpe-cport", Input).focus()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        elif event.input.id == "dpe-cport":
            try:
                self.query_one("#dpe-proto", Input).focus()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        elif event.input.id == "dpe-proto":
            self._add_port()

    def _add_port(self):
        def _v(wid):
            try:
                return self.query_one(wid, Input).value.strip()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                return ""
        hp    = _v("#dpe-hport")
        cp    = _v("#dpe-cport")
        proto = _v("#dpe-proto") or "tcp"
        if not hp.isdigit() or not cp.isdigit():
            self.app.notify("Fill in both port fields (e.g. host: 2222, container: 22)", severity="warning")
            return
        self._ports.append([hp, cp, proto])
        self._render_port_list()
        # clear inputs
        for wid in ("#dpe-hport", "#dpe-cport"):
            try:
                self.query_one(wid, Input).value = ""
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        try:
            self.query_one("#dpe-hport", Input).focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── recreate logic ────────────────────────────────────────────────────────

    async def _recreate(self):
        import json as _json
        cid  = self._container.id
        name = self._container.name
        hs   = self._pool.state(self._host_id)
        if not hs.client:
            self.app.notify("Host not connected", severity="error")
            return

        loop = asyncio.get_running_loop()

        def _ssh(cmd, timeout=30):
            _, stdout, stderr = hs.client.exec_command(cmd, timeout=timeout)
            out = stdout.read().decode(errors="replace").strip()
            err = stderr.read().decode(errors="replace").strip()
            code = stdout.channel.recv_exit_status()
            return out, err, code

        self.app.notify(f"Inspecting {name}…", severity="information")
        try:
            inspect_out, _, _ = await loop.run_in_executor(
                None, _ssh, f"docker inspect {cid}", 15)
            cfg = _json.loads(inspect_out)[0]
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"docker inspect failed: {e}", severity="error")
            return

        # build new docker run command from inspect data
        hc      = cfg.get("HostConfig", {})
        config  = cfg.get("Config", {})
        image   = config.get("Image", self._container.image)
        restart = hc.get("RestartPolicy", {}).get("Name", "") or ""

        parts = ["docker run -d"]
        parts.append(f"--name {name}")
        if restart and restart != "no":
            max_retry = hc["RestartPolicy"].get("MaximumRetryCount", 0)
            if restart == "on-failure" and max_retry:
                parts.append(f"--restart {restart}:{max_retry}")
            else:
                parts.append(f"--restart {restart}")

        # new port mappings from editor
        for hp, cp, proto in self._ports:
            parts.append(f"-p {hp}:{cp}/{proto}")

        # volumes
        for bind in (hc.get("Binds") or []):
            parts.append(f"-v {bind}")

        # env vars (skip internal Docker ones)
        for env in (config.get("Env") or []):
            if not env.startswith("PATH=") and not env.startswith("HOME="):
                parts.append(f"-e '{env}'")

        # network (skip default bridge - it's implicit)
        net = hc.get("NetworkMode", "")
        if net and net not in ("bridge", "default"):
            parts.append(f"--network {net}")

        parts.append(image)
        new_run_cmd = " ".join(parts)
        _log.info("docker port-recreate: %s\nCMD: %s", name, new_run_cmd)

        # stop → remove → run
        _record_screen_exec("docker")
        self.app.notify(f"Stopping {name}…", severity="warning")
        _, err, code = await loop.run_in_executor(
            None, _ssh, f"docker stop {cid}", 30)
        if code != 0:
            self.app.notify(f"Stop failed: {err[:100]}", severity="error")
            return

        _, err, code = await loop.run_in_executor(
            None, _ssh, f"docker rm {cid}", 15)
        if code != 0:
            self.app.notify(f"Remove failed: {err[:100]}", severity="error")
            return

        self.app.notify(f"Starting {name} with new ports…", severity="information")
        out, err, code = await loop.run_in_executor(
            None, lambda: _ssh(new_run_cmd, 120))
        if code != 0:
            err_lines = [l for l in err.splitlines() if l.strip()]
            self.app.notify(
                f"Recreate failed: {(err_lines[-1] if err_lines else err)[:120]}",
                severity="error")
            return

        self.app.notify(
            f"✓ {name} recreated: {out[:12]}", severity="information")

        # refresh docker metrics immediately
        try:
            await self._pool.agent(self._host_id)._fetch_docker()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: network_recon_screen  (v0.3)
# Ctrl+R - run nmap / dig / whois / traceroute on a target via SSH proxy
# ══════════════════════════════════════════════════════════════════════════════

_RECON_PRESETS: list[tuple[str, str, str]] = [
    # (label, description, command template)  - {target} is replaced at runtime
    ("Quick scan",      "nmap top-1000 ports",
     "timeout 45 nmap -T4 --open {target} 2>/dev/null || echo 'nmap not found - apt install nmap'"),
    ("Service scan",    "nmap -sV version detect",
     "timeout 60 nmap -T4 -sV --open {target} 2>/dev/null || echo 'nmap not found'"),
    ("Full port scan",  "nmap all 65535 ports",
     "timeout 120 nmap -T4 -p- --open {target} 2>/dev/null || echo 'nmap not found'"),
    ("OS detect",       "nmap OS fingerprint (root)",
     "timeout 45 nmap -T4 -O {target} 2>/dev/null || echo 'nmap not found or need root'"),
    ("dig DNS",         "dig A/MX/NS records",
     "dig +noall +answer A {target}; dig +noall +answer MX {target}; dig +noall +answer NS {target}"),
    ("dig trace",       "dig +trace full DNS path",
     "timeout 15 dig +trace {target} 2>/dev/null | tail -20"),
    ("whois",           "WHOIS lookup",
     "timeout 15 whois {target} 2>/dev/null | head -40 || echo 'whois not found'"),
    ("traceroute",      "traceroute to target",
     "timeout 30 traceroute -m 20 {target} 2>/dev/null || timeout 30 tracepath {target} 2>/dev/null || echo 'no traceroute'"),
    ("HTTP headers",    "curl -I response headers",
     "curl -sI --max-time 10 http://{target} 2>/dev/null | head -20"),
    ("HTTPS cert",      "SSL cert info",
     "timeout 15 sh -c 'echo | openssl s_client -connect {target}:443 -servername {target} 2>/dev/null "
     "| openssl x509 -noout -subject -issuer -dates 2>/dev/null || echo openssl error'"),
    ("Ping sweep",      "fping / ping alive check",
     "timeout 20 fping -a -g {target}/24 2>/dev/null || timeout 10 ping -c 3 {target}"),
]


class NetworkReconScreen(ModalScreen):
    """
    Network recon panel - runs nmap/dig/whois/traceroute on a chosen host via SSH.
    Ctrl+R - Network recon.

    Layout: top = host selector + target input + scan presets
            main = scrollable output
    Keys:
      Click buttons / TAB   - select source host
      Enter / F5           - run selected scan
      ↑ ↓                  - move through scan presets
      Esc                  - close
    """

    DEFAULT_CSS = """
    NetworkReconScreen { align: center middle; background: $background 85%; }
    #recon-box {
        width: 100%; height: 100%;
        border: double $warning;
        background: $surface;
        layout: vertical;
    }
    #recon-box {
        border-title-color: $warning;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #recon-host-bar {
        height: 3;
        background: $panel-darken-1;
        padding: 0 1;
    }
    #recon-host-bar Button { min-width: 14; margin-right: 1; }
    #recon-host-bar Button.active { background: $warning 30%; color: $warning; text-style: bold; }
    #recon-controls {
        height: 3;
        background: $panel-darken-1;
        padding: 0 1;
    }
    #lbl-target { width: 12; content-align: left middle; color: $text-muted; }
    #recon-target { width: 1fr; }
    #recon-presets {
        height: 3;
        background: $panel;
        padding: 0 1;
        content-align: left middle;
    }
    #recon-output {
        height: 1fr;
        overflow-y: auto;
        padding: 0 1;
    }
    #recon-status {
        height: 1;
        background: $panel;
        padding: 0 2;
    }
    """

    BINDINGS = [
        Binding("escape", "close_recon",  "Close",  show=False),
        Binding("f5",     "run_scan",     "Run",    show=False),
        Binding("up",     "preset_up",   "Up",      show=False),
        Binding("down",   "preset_down", "Down",    show=False),
        Binding("left",   "preset_up",   "Prev",    show=False),
        Binding("right",  "preset_down", "Next",    show=False),
    ]

    def __init__(self, pool: "AgentPool", host_id: Optional[str] = None, **kwargs):
        super().__init__(**kwargs)
        self._pool      = pool
        self._host_ids  = list(pool.host_ids())
        self._preset_idx = 0
        self._scan_running   = False
        self._output_buf = ""
        # default source = focused host
        self._sel_hid = host_id or (self._host_ids[0] if self._host_ids else "")

    def compose(self) -> ComposeResult:
        with Container(id="recon-box"):
            with Horizontal(id="recon-host-bar"):
                for hid in self._host_ids:
                    label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
                    cls   = "active" if hid == self._sel_hid else ""
                    yield Button(label, id=f"rh-{hid}", classes=cls)
            with Horizontal(id="recon-controls"):
                yield Static("Target:", id="lbl-target")
                yield Input(
                    placeholder="IP, domain, or CIDR  e.g. 8.8.8.8 / example.com",
                    id="recon-target",
                )
                yield Button("▶ Run", id="recon-run-btn", variant="warning")
            yield Static("", id="recon-presets")
            yield Static("", id="recon-output")
            yield Static("", id="recon-status")

    def on_mount(self):
        self.query_one("#recon-box").border_title = "🔍  NETWORK RECON"
        self._render_presets()
        self._render_fkey()
        self.call_after_refresh(self._focus_input)

    def _focus_input(self):
        try:
            self.query_one("#recon-target", Input).focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id or ""
        _log.info("recon: on_button_pressed bid=%r", bid)
        if bid == "recon-run-btn":
            event.stop()
            self.run_worker(self._do_scan(), exclusive=True)
        elif bid.startswith("rh-"):
            self._sel_hid = bid[3:]
            for hid in self._host_ids:
                try:
                    self.query_one(f"#rh-{hid}").set_class(hid == self._sel_hid, "active")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass

    def _render_presets(self):
        t = Text()
        for i, (label, desc, _) in enumerate(_RECON_PRESETS):
            if i == self._preset_idx:
                t.append(f" [{i}]{label} ", style=f"bold white on {CLR_TAB_ACTIVE}")
            else:
                t.append(f"  {label}  ", style="grey50")
            if i < len(_RECON_PRESETS) - 1:
                t.append("│", style="grey35")
        try:
            self.query_one("#recon-presets", Static).update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _render_fkey(self):
        preset = _RECON_PRESETS[self._preset_idx]
        subtitle = f" ← → :select scan   F5/Enter:run   Esc:close   {preset[0]} - {preset[1]}"
        try:
            self.query_one("#recon-box").border_subtitle = subtitle
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_preset_up(self):
        self._preset_idx = (self._preset_idx - 1) % len(_RECON_PRESETS)
        self._render_presets()
        self._render_fkey()

    def action_preset_down(self):
        self._preset_idx = (self._preset_idx + 1) % len(_RECON_PRESETS)
        self._render_presets()
        self._render_fkey()

    def on_input_submitted(self, event: Input.Submitted) -> None:
        _log.info("recon: on_input_submitted id=%r val=%r", event.input.id, event.input.value)
        if event.input.id == "recon-target":
            self.run_worker(self._do_scan(), exclusive=True)

    def action_run_scan(self):
        _log.info("recon: action_run_scan fired")
        self.run_worker(self._do_scan(), exclusive=True)

    async def _do_scan(self):
        _log.info("recon: _do_scan entered  running=%s", self._scan_running)
        try:
            await self._do_scan_inner()
        except Exception as e:
            _log.error("recon: _do_scan unhandled exception: %s", e, exc_info=True)
            self._set_status(f"[red]✗ Unhandled: {e}[/]")

    async def _do_scan_inner(self):
        self._scan_running = False  # reset in case previous worker was cancelled

        target = self.query_one("#recon-target", Input).value.strip()
        _log.info("recon: target=%r sel_hid=%r", target, self._sel_hid)

        if not target:
            self._set_status("[yellow]Enter a target IP or domain[/]")
            return

        host_id = self._sel_hid
        if not host_id:
            self._set_status("[red]No source host selected[/]")
            return

        hs = self._pool.state(host_id)
        _log.info("recon: host state=%s client=%s", getattr(hs, 'state', '?'), bool(getattr(hs, 'client', None)))
        if hs.state != ConnState.CONNECTED or not hs.client:
            self._set_status(f"[red]Host {host_id} not connected[/]")
            return

        label, _, cmd_tpl = _RECON_PRESETS[self._preset_idx]
        cmd = cmd_tpl.replace("{target}", target)

        try:
            src_label = hs.config.label
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            src_label = host_id

        self._scan_running = True
        self._output_buf = ""
        _log.info("recon: [%s] %s → %s  cmd=%s", src_label, label, target, cmd)
        self.notify(f"{label} → {target}\nvia {src_label}", title="Recon: sending command", timeout=4)
        self._set_status(f"[yellow]⏳ Connecting (recon session) to {src_label}…[/]")
        self._set_output(f"[grey50]$ {cmd}\n[/]")

        loop = asyncio.get_running_loop()
        cfg = hs.config

        def _run():
            recon_client = paramiko.SSHClient()
            recon_client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            kwargs: dict = dict(
                hostname=cfg.address,
                port=cfg.port,
                username=cfg.username,
                timeout=15,
            )
            if cfg.auth == "password":
                kwargs["password"] = cfg.password
            elif cfg.auth in ("key", "vault_key"):
                key_path = os.path.expanduser(cfg.key_path) if cfg.key_path else None
                if key_path and os.path.exists(key_path):
                    kwargs["key_filename"] = key_path
                    if cfg.password:
                        kwargs["passphrase"] = cfg.password
            _log.info("recon: opening dedicated SSH session  host=%s", host_id)
            recon_client.connect(**kwargs)
            try:
                _log.info("recon: exec_command start  host=%s  cmd=%s", host_id, cmd)
                _record_screen_exec("recon")
                _, stdout, stderr = recon_client.exec_command(cmd, timeout=150)
                out = stdout.read().decode(errors="replace")
                err = stderr.read().decode(errors="replace")
                _log.info("recon: exec_command done   host=%s  out=%d chars  err=%d chars",
                          host_id, len(out), len(err))
                return out, err
            finally:
                try:
                    recon_client.close()
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass

        try:
            self._set_status(f"[yellow]⏳ Running {label} on {target} via {src_label}…[/]")
            out, err = await loop.run_in_executor(None, _run)
            from rich.markup import escape as _escape
            combined = out + (("\n[STDERR]\n" + err) if err.strip() else "")
            self._output_buf = combined
            lines = combined.strip().count("\n") + 1 if combined.strip() else 0
            _log.info("recon: result  host=%s  lines=%d", host_id, lines)
            self._set_output(f"[grey50]$ {cmd}[/]\n\n{_escape(combined)}")
            self._set_status(
                f"[green]✓ Done - {label} → {target} via {src_label}  ({lines} lines)[/]")
        except Exception as e:
            _log.error("recon: failed  host=%s  error=%s", host_id, e, exc_info=True)
            self._set_output(f"[red]✗ Error: {e}[/]")
            self._set_status(f"[red]✗ Failed: {e}[/]")
        finally:
            self._scan_running = False

    def _set_output(self, text: str):
        try:
            self.query_one("#recon-output", Static).update(text)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _set_status(self, text: str):
        try:
            self.query_one("#recon-status", Static).update(text)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close_recon(self):
        self.dismiss(None)


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: fleet_manager_screen  (v0.3)
# F9 - full-screen host table with checkboxes, clone button, bulk-ops launcher
# ══════════════════════════════════════════════════════════════════════════════

from textual.widgets import Checkbox, DataTable, Label, Select, TextArea
from textual.reactive import reactive


class FleetManagerScreen(ModalScreen):
    """
    Full-screen fleet overview.  Opened with F9.
    Hosts displayed in a scrollable table with checkboxes.
    Keys:
      Space      - toggle selected row
      a          - select / deselect all
      c          - clone focused host  → HostEditorScreen(clone_from=…)
      e          - edit focused host   → HostEditorScreen(host_id=…)
      b          - open BulkOpsScreen for checked hosts
      k          - open RotateKeyScreen for checked hosts
      Del        - delete focused host (with confirm)
      Esc/F9     - close
    """

    DEFAULT_CSS = """
    FleetManagerScreen {
        align: center middle;
        background: $background 80%;
    }
    #fleet-box {
        width: 100%; height: 100%;
        border: double $accent;
        background: $surface;
    }
    #fleet-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #fleet-footer {
        dock: bottom;
        height: 1;
        background: $panel;
        padding: 0 2;
        content-align: left middle;
        color: $text-muted;
    }
    #fleet-table {
        height: 1fr;
        margin: 0;
    }
    DataTable > .datatable--header {
        background: $panel;
        color: $text-muted;
        text-style: bold;
    }
    DataTable > .datatable--cursor {
        background: $accent 30%;
    }
    """

    BINDINGS = [
        Binding("escape",    "close",       "Close",      show=False),
        Binding("f9",        "close",       "Close",      show=False),
        Binding("a",         "select_all",  "All",        show=False),
        Binding("c",         "clone_host",  "Clone",      show=False),
        Binding("e",         "edit_host",   "Edit",       show=False),
        Binding("b",         "bulk_ops",    "Bulk Ops",   show=False),
        Binding("k",         "rotate_key",  "Rotate Key", show=False),
        Binding("n",         "new_host",    "New",        show=False),
        Binding("delete",    "del_host",    "Delete",     show=False),
        Binding("h",         "ai_audit",    "AI Audit",   show=False),
        Binding("f2",        "open_ssh",    "SSH",        show=False),
        Binding("ctrl+f",    "open_fm",     "Files",      show=False),
    ]

    def on_key(self, event: events.Key) -> None:
        # Fallback - in case the DataTable patch doesn't cover all code paths
        if event.key == "space":
            event.prevent_default()
            event.stop()
            self.action_toggle_row()
        elif event.key == "escape":
            # Cancel pending delete confirmation (if any)
            self._pending_delete = None

    def __init__(self, pool: "AgentPool", cfgman: "ConfigManager",
                 app_cfg: "AppConfig", **kwargs):
        super().__init__(**kwargs)
        self._pool    = pool
        self._cfgman  = cfgman
        self._app_cfg = app_cfg
        # host_id → checked bool
        self._checked: dict[str, bool] = {}
        # host_id waiting for delete confirmation (second Del press)
        self._pending_delete: Optional[str] = None

    def compose(self) -> ComposeResult:
        with Container(id="fleet-box"):
            yield DataTable(id="fleet-table", cursor_type="row",
                            show_cursor=True)
            yield Static("", id="fleet-footer")

    def on_mount(self):
        box = self.query_one("#fleet-box")
        box.border_title = "⊞  Fleet Manager"
        box.border_subtitle = (
            " Space:toggle  a:all  c:clone  e:edit"
            "  b:bulk-ops  k:rotate-key  n:new  Del:delete  Esc:close"
        )
        tbl = self.query_one("#fleet-table", DataTable)
        tbl.add_columns("✓", "#", "Label", "Address", "Port",
                         "User", "Auth", "Tags", "Status", "CPU", "RAM")
        self._refresh_table()
        tbl.focus()
        self.set_interval(3, lambda: self._refresh_table(keep_cursor=True))
        # Patch DataTable's key handler so Space toggles checkbox instead of
        # bubbling through the table. We capture _screen and _orig_key in the
        # closure so the bound method still works correctly.
        import types as _types
        _screen   = self
        _orig_key = tbl._on_key  # bound method of the instance

        async def _patched_key(_, event: events.Key) -> None:
            if event.key == "space":
                event.prevent_default()
                event.stop()
                _screen.action_toggle_row()
            else:
                await _orig_key(event)  # call original bound method

        tbl._on_key = _types.MethodType(_patched_key, tbl)

    def _refresh_table(self, keep_cursor: bool = False):
        tbl  = self.query_one("#fleet-table", DataTable)
        saved_cursor = tbl.cursor_row if keep_cursor else 0
        tbl.clear()
        states = {hs.config.id: hs for hs in self._pool.all_states()}
        for i, hid in enumerate(self._pool.host_ids(), 1):
            hs  = states.get(hid)
            cfg = hs.config if hs else None
            if not cfg:
                continue
            chk  = "☑" if self._checked.get(hid) else "☐"
            conn = hs.state if hs else ConnState.ERROR
            status_sym = (
                Text("● UP",   style=f"bold {CLR_SUCCESS}") if conn == ConnState.CONNECTED else
                Text("✗ DOWN", style=f"bold {CLR_ERROR}")
            )
            m      = self._pool.metrics_view().get(hid)
            cpu_s  = f"{m.cpu_pct:5.1f}%" if m and m.cpu_pct > 0 else "  -  "
            ram_s  = f"{m.ram_pct:5.1f}%" if m and m.ram_pct > 0 else "  -  "
            tags_s = ", ".join(cfg.tags) if cfg.tags else ""
            auth_s = cfg.auth or "key"

            tbl.add_row(
                chk, str(i), cfg.label, cfg.address,
                str(cfg.port), cfg.username, auth_s,
                tags_s, status_sym, cpu_s, ram_s,
                key=hid,
            )
        row_count = tbl.row_count
        if row_count > 0:
            tbl.move_cursor(row=min(saved_cursor, row_count - 1))
        self._update_footer()

    def _update_footer(self):
        n_checked = sum(1 for v in self._checked.values() if v)
        total     = len(self._pool.host_ids())
        msg = f"[bold {CLR_ACCENT}]▣ {n_checked} selected[/] of {total}"
        try:
            self.query_one("#fleet-footer", Static).update(msg)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _focused_host_id(self) -> Optional[str]:
        return self._host_id_at_cursor()

    def _host_id_at_cursor(self) -> Optional[str]:
        tbl = self.query_one("#fleet-table", DataTable)
        try:
            # get_row_at() returns cell values (list), not a Row object.
            # The correct way to get the RowKey is via tbl.rows ordered dict.
            return list(tbl.rows.keys())[tbl.cursor_row].value
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return None

    def on_data_table_row_selected(self, event: DataTable.RowSelected) -> None:
        """Mouse click or Enter on a row - toggle its checkbox."""
        event.stop()
        hid = event.row_key.value
        if hid:
            self._checked[hid] = not self._checked.get(hid, False)
            self._refresh_table(keep_cursor=True)

    def action_toggle_row(self):
        hid = self._host_id_at_cursor()
        if hid:
            self._checked[hid] = not self._checked.get(hid, False)
            self._refresh_table(keep_cursor=True)

    def action_select_all(self):
        ids  = self._pool.host_ids()
        all_on = all(self._checked.get(h, False) for h in ids)
        for h in ids:
            self._checked[h] = not all_on
        self._refresh_table(keep_cursor=True)

    def action_clone_host(self):
        hid = self._host_id_at_cursor()
        if not hid:
            self.app.notify("No host selected", severity="warning"); return
        def _on_save(cfg):
            if cfg is not None:
                self._refresh_table()
        self.app.push_screen(HostEditorScreen(self._pool, clone_from=hid), _on_save)

    def action_edit_host(self):
        hid = self._host_id_at_cursor()
        if not hid:
            self.app.notify("No host selected", severity="warning"); return
        def _on_save(cfg):
            self._refresh_table()
        self.app.push_screen(HostEditorScreen(self._pool, host_id=hid), _on_save)

    def action_new_host(self):
        def _on_save(cfg):
            if cfg is not None:
                self._refresh_table()
        self.app.push_screen(HostEditorScreen(self._pool), _on_save)

    def action_bulk_ops(self):
        selected = [h for h, v in self._checked.items() if v]
        fallback = False
        if not selected:
            hid = self._host_id_at_cursor()
            if hid:
                selected = [hid]
                fallback = True
        if not selected:
            self.app.notify(
                "Select at least one host (Space to toggle, a = all)",
                severity="warning")
            return
        if fallback:
            self.app.notify("No hosts checked - using highlighted host",
                            severity="information")
        self.app.push_screen(
            BulkOpsScreen(self._pool, self._cfgman, self._app_cfg, selected))

    def action_rotate_key(self):
        selected = [h for h, v in self._checked.items() if v]
        if not selected:
            # fall back to cursor host
            hid = self._host_id_at_cursor()
            if hid:
                selected = [hid]
        if not selected:
            self.app.notify("Select at least one host", severity="warning"); return
        self.app.push_screen(
            RotateKeyScreen(self._pool, self._cfgman, selected))

    def action_del_host(self):
        hid = self._host_id_at_cursor()
        if not hid:
            return
        label = self._pool.state(hid).config.label
        if self._pending_delete == hid:
            # Second Del press on the same host - confirmed
            self._pending_delete = None
            asyncio.create_task(self._do_delete(hid, label))
        else:
            # First press - ask for confirmation
            self._pending_delete = hid
            self.app.notify(
                f"Delete '{label}'? Press Del again to confirm or Esc to cancel.",
                severity="warning", timeout=5)

    async def _do_delete(self, hid: str, label: str):
        await self._pool.remove_host(hid)
        self._checked.pop(hid, None)
        self.app.notify(f"✓ Host '{label}' removed", severity="information")
        self._refresh_table()

    def action_ai_audit(self):
        engine = self._pool.ai_engine
        if not engine.enabled:
            self.app.notify("AI disabled - configure in F6 → 🤖 AI", severity="warning")
            return
        host_ids = [h for h, v in self._checked.items() if v]
        if not host_ids:
            host_ids = self._pool.host_ids()
        if not host_ids:
            self.app.notify("No hosts to audit", severity="warning")
            return
        self.app.push_screen(AiHealthAuditScreen(self._pool, host_ids))

    def action_open_ssh(self):
        """F2 — open SSH shell for the host at cursor."""
        hid = self._host_id_at_cursor()
        if not hid:
            self.app.notify("Select a host first", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(SshShellScreen(self._pool, hid))

    def action_open_fm(self):
        """Ctrl+F — open File Manager for the host at cursor."""
        hid = self._host_id_at_cursor()
        if not hid:
            self.app.notify("Select a host first", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool, initial_host_id=hid))

    def action_close(self):
        self.dismiss(None)


