class BulkOpsScreen(ModalScreen):
    """
    Bulk operations screen - execute commands on multiple hosts in parallel.
    Left column: host list with live per-host status.
    Right panel: operation categories + custom command textarea.
    """

    DEFAULT_CSS = """
    BulkOpsScreen { align: center middle; background: $background 75%; }
    #bulk-box {
        width: 100%; height: 100%;
        border: double $accent;
        background: $surface;
    }
    #bulk-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #bulk-footer {
        dock: bottom; height: 1;
        background: $panel;
        padding: 0 2; content-align: left middle; color: $text-muted;
    }
    #bulk-layout { layout: horizontal; height: 1fr; }
    #bulk-hosts-col {
        width: 28; border-right: solid $primary;
        overflow-y: auto;
    }
    #bulk-ops-col { width: 1fr; overflow-y: auto; }
    .bulk-section-title {
        background: $panel; color: $text-muted;
        text-style: bold; padding: 0 1; height: 1;
    }
    .bulk-op-btn {
        margin: 0 1 0 1; height: 3;
        background: $surface;
        color: $text;
        border: tall $surface;
        text-align: left;
        content-align: left middle;
        padding: 0 1;
    }
    .bulk-op-btn:hover { background: $accent 20%; color: $accent; border: tall $accent 20%; }
    .bulk-op-btn.active { background: $accent 40%; color: $accent; border: tall $accent; text-style: bold; }
    .bulk-host-row { height: 2; padding: 0 1; border-bottom: solid $primary; }
    #custom-cmd { height: 4; margin: 0 1; }
    #exec-btn {
        dock: bottom; margin: 0 1 1 1; height: 3;
        background: $success 50%; color: $success;
        border: solid $success;
    }
    #exec-btn:hover { background: $success 70%; }
    """

    BINDINGS = [
        Binding("escape", "close",   "Close",   show=False, priority=True),
        Binding("f5",     "execute", "Execute", show=False, priority=True),
    ]

    def __init__(self, pool: "AgentPool", cfgman: "ConfigManager",
                 app_cfg: "AppConfig", host_ids: list[str], **kwargs):
        super().__init__(**kwargs)
        self._pool      = pool
        self._cfgman    = cfgman
        self._app_cfg   = app_cfg
        self._host_ids  = host_ids
        self._active_op: Optional[tuple[str,str,str]] = None  # (cat, label, cmd)
        # host_id → status string
        self._status: dict[str, str] = {h: "waiting" for h in host_ids}
        self._output: dict[str, str] = {h: ""        for h in host_ids}
        self._exec_running = False

    def compose(self) -> ComposeResult:
        n = len(self._host_ids)
        with Container(id="bulk-box"):
            with Horizontal(id="bulk-layout"):
                with Vertical(id="bulk-hosts-col"):
                    yield Static(f"[bold {CLR_ACCENT}]Target hosts[/]",
                                 classes="bulk-section-title")
                    for hid in self._host_ids:
                        try:
                            label = self._pool.state(hid).config.label
                        except Exception as e:
                            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                            label = hid
                        yield Static(
                            f"● {label[:18]}",
                            id=self._host_widget_id(hid),
                            classes="bulk-host-row")
                with Vertical(id="bulk-ops-col"):
                    # render category groups
                    cat = None
                    for op in _BULK_OPS:
                        if op[0] != cat:
                            cat = op[0]
                            yield Static(f"  {cat}",
                                         classes="bulk-section-title")
                        op_id = self._op_widget_id(op)
                        btn = Button(f"  {op[1]}", id=op_id,
                                     classes="bulk-op-btn")
                        yield btn
                    yield Static("  Custom command",
                                 classes="bulk-section-title")
                    yield Input(placeholder="systemctl restart myapp && echo done",
                                id="custom-cmd")
                    yield Button("▶  Execute on selected hosts",
                                 id="exec-btn", variant="success")
            yield Static("", id="bulk-footer")

    def on_mount(self) -> None:
        n = len(self._host_ids)
        box = self.query_one("#bulk-box")
        box.border_title = f"⚡  Bulk Operations  -  {n} host{'s' if n != 1 else ''}"
        box.border_subtitle = " F5:execute  Esc:close"
        self._update_footer()

    @staticmethod
    def _op_widget_id(op: tuple) -> str:
        safe = re.sub(r"[^a-z0-9]", "-", op[1].lower())[:32]
        return f"op-{safe}"

    @staticmethod
    def _host_widget_id(hid: str) -> str:
        safe = re.sub(r"[^a-z0-9]", "-", hid.lower())
        return f"bulk-hs-{safe}"

    def on_button_pressed(self, event: Button.Pressed):
        event.stop()
        bid = event.button.id or ""
        _log.debug("BulkOps on_button_pressed: bid=%r _exec_running=%s\n%s",
                   bid, self._exec_running, "".join(traceback.format_stack()))
        if bid == "exec-btn":
            self.action_execute()
            return
        # check if it's an op button
        for op in _BULK_OPS:
            if bid == self._op_widget_id(op):
                # toggle selection
                if self._active_op == op:
                    self._active_op = None
                    event.button.remove_class("active")
                else:
                    # deactivate previous
                    if self._active_op:
                        try:
                            prev_id = self._op_widget_id(self._active_op)
                            self.query_one(f"#{prev_id}").remove_class("active")
                        except Exception as e:
                            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                            pass
                    self._active_op = op
                    event.button.add_class("active")
                self._update_footer()
                return

    def _update_footer(self):
        if self._active_op:
            msg = (f"[dim]Selected:[/] [bold]{self._active_op[1]}[/]  "
                   "[dim]Enter/F5 to execute[/]")
        else:
            msg = "[dim]Select an operation above or type a custom command[/]"
        try:
            self.query_one("#bulk-footer", Static).update(msg)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_execute(self):
        _log.debug("BulkOps action_execute: _exec_running=%s\n%s",
                   self._exec_running, "".join(traceback.format_stack()))
        # Guard here (synchronously) so rapid/duplicate F5 presses never
        # create a second task before the first one starts.
        if self._exec_running:
            self.app.notify("Already running…", severity="warning")
            return
        self._exec_running = True
        asyncio.create_task(self._do_execute())

    async def _do_execute(self):
        _log.debug("BulkOps _do_execute entered: _exec_running=%s", self._exec_running)
        try:
            # determine command
            custom = self.query_one("#custom-cmd", Input).value.strip()
            if custom:
                cmd  = custom
                name = "Custom"
            elif self._active_op:
                cmd  = self._active_op[2]
                name = self._active_op[1]
            else:
                self.app.notify("Select an operation or type a command",
                                severity="warning")
                return

            n = len(self._host_ids)
            _log.info("BulkOps: executing [%s] on %d host(s): cmd=%r", name, n, cmd)
            self.app.notify(f"⚡ {name} → {n} host(s)…", severity="information")

            # Reset status
            for hid in self._host_ids:
                self._status[hid] = "running"
                self._output[hid] = ""
                self._update_host_widget(hid)

            # Run all in parallel
            _record_screen_exec("fleet")
            tasks = {hid: asyncio.create_task(self._pool.run(hid, cmd))
                     for hid in self._host_ids}

            for hid, task in tasks.items():
                try:
                    result = await task
                    if result.ok:
                        self._status[hid] = "done"
                        self._output[hid] = (result.stdout or "").strip()
                        _log.info("BulkOps: [%s] ✓ host=%s  stdout=%r",
                                  name, hid, self._output[hid][:120])
                    else:
                        self._status[hid] = "error"
                        self._output[hid] = (result.stderr or result.stdout or
                                             result.error or "failed")
                        _log.warning("BulkOps: [%s] ✗ host=%s  err=%r",
                                     name, hid, self._output[hid][:120])
                except Exception as e:
                    self._status[hid] = "error"
                    self._output[hid] = str(e)
                    _log.error("BulkOps: [%s] exception host=%s: %s: %s",
                               name, hid, type(e).__name__, e)
                self._update_host_widget(hid)

            ok_n  = sum(1 for s in self._status.values() if s == "done")
            err_n = sum(1 for s in self._status.values() if s == "error")
            _log.info("BulkOps: [%s] finished — %d ok, %d error(s)", name, ok_n, err_n)
            self.app.notify(
                f"✓ {ok_n} ok  ✗ {err_n} error(s)  —  Enter to view output",
                severity="information" if err_n == 0 else "warning")

            # Build result list for the output screen
            results_for_screen = []
            for hid in self._host_ids:
                try:
                    lbl = self._pool.state(hid).config.label
                except Exception:
                    lbl = hid
                results_for_screen.append(
                    (lbl, hid, self._status.get(hid, "error"),
                     self._output.get(hid, ""))
                )
            self.app.push_screen(BulkOpsResultScreen(name, cmd, results_for_screen))
        except Exception as e:
            _log.error("BulkOps: _do_execute unhandled exception: %s: %s\n%s",
                       type(e).__name__, e, traceback.format_exc())
        finally:
            self._exec_running = False

    def _update_host_widget(self, hid: str):
        icons = {"waiting": "◌", "running": "⟳", "done": "✓", "error": "✗"}
        colors = {
            "waiting": CLR_IDLE, "running": CLR_WARNING,
            "done": CLR_SUCCESS,    "error":   CLR_ERROR,
        }
        st    = self._status.get(hid, "waiting")
        icon  = icons.get(st, "?") 
        color = colors.get(st, CLR_TEXT)
        try:
            label = self._pool.state(hid).config.label
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            label = hid
        out_snip = self._output.get(hid, "")[:30]
        txt = Text()
        txt.append(f"{icon} ", style=f"bold {color}")
        txt.append(label[:16], style=color)
        if out_snip:
            txt.append(f"\n  {out_snip}", style=f"dim {CLR_TEXT_DIM}")
        try:
            self.query_one(f"#{self._host_widget_id(hid)}", Static).update(txt)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_close(self):
        self.dismiss(None)


class BulkOpsResultScreen(ModalScreen):
    """Scrollable, selectable per-host output after a BulkOps execution."""

    DEFAULT_CSS = """
    BulkOpsResultScreen { align: center middle; background: $background 75%; }
    #bor-box {
        width: 95%; height: 90%;
        border: double $accent;
        background: $surface;
    }
    #bor-box {
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #bor-text { margin: 0; height: 1fr; }
    """

    BINDINGS = [
        Binding("escape", "close", "Close", show=False, priority=True),
    ]

    def __init__(self, op_name: str, cmd: str,
                 results: list, **kwargs):
        # results: list of (label, hid, status, output)
        super().__init__(**kwargs)
        self._op_name = op_name
        self._cmd     = cmd
        self._results = results

    def compose(self) -> ComposeResult:
        ok_n  = sum(1 for _, _, s, _ in self._results if s == "done")
        err_n = sum(1 for _, _, s, _ in self._results if s == "error")
        cmd_preview = self._cmd if len(self._cmd) <= 55 else self._cmd[:52] + "…"
        with Container(id="bor-box"):
            yield TextArea(
                self._build_text(),
                id="bor-text",
                read_only=True,
                show_line_numbers=False,
            )

    def on_mount(self) -> None:
        ok_n  = sum(1 for _, _, s, _ in self._results if s == "done")
        err_n = sum(1 for _, _, s, _ in self._results if s == "error")
        cmd_preview = self._cmd if len(self._cmd) <= 55 else self._cmd[:52] + "…"
        box = self.query_one("#bor-box")
        box.border_title = f"⚡ {self._op_name}  ·  ✓ {ok_n} ok  ✗ {err_n} error(s)  {cmd_preview}"
        box.border_subtitle = " Esc:close  ↑↓/PgUp/PgDn:scroll  Ctrl+A:select all  Ctrl+C:copy"

    def _build_text(self) -> str:
        lines = []
        for label, hid, status, output in self._results:
            icon = "✓" if status == "done" else "✗"
            lines.append(f"{icon} {label}  [{hid}]")
            lines.append("─" * 72)
            lines.append(output.strip() if output.strip() else "(no output)")
            lines.append("")
        return "\n".join(lines)

    def action_close(self):
        self.dismiss(None)


