# SECTION: rotate_key_screen  (v0.3)
# Step-by-step SSH key rotation UI with live progress per host.
# Opened from FleetManagerScreen (k) or BulkOpsScreen.
# ══════════════════════════════════════════════════════════════════════════════

_ROTATE_STEP_LABELS = {
    "generate":        "Generate new ed25519 keypair",
    "push_pubkey":     "Append pubkey to authorized_keys",
    "verify":          "Verify new key authenticates",
    "remove_old":      "Remove old pubkey",
    "backup":          "Backup old key locally",
    "save_config":     "Update deflect.json",
    "permit_root":     "Enable PermitRootLogin (root user)",
    "disable_password":"Disable PasswordAuthentication",
    "done":            "Rotation complete",
}

# Steps that always run (non-conditional) - shown as pending in the UI from the start
_ROTATE_BASE_STEPS: frozenset[str] = frozenset({
    "generate", "push_pubkey", "verify",
    "remove_old", "backup", "save_config", "done",
})


class RotateKeyScreen(ModalScreen):
    """
    SSH key rotation wizard.
    Shows per-host progress steps with ✓/✗/⟳ indicators.
    """

    DEFAULT_CSS = """
    RotateKeyScreen { align: center middle; background: $background 75%; }
    #rk-box {
        width: 80; height: auto; max-height: 90%;
        border: double $warning;
        background: $surface;
        padding: 0 0 1 0;
    }
    #rk-box {
        border-title-color: $warning;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #rk-options { padding: 1 2 0 2; height: auto; }
    #rk-pw-label { height: 1; }
    #rk-pw-btns { height: 3; layout: horizontal; margin-top: 0; }
    #rk-progress { padding: 1 2; height: auto; max-height: 50%; overflow-y: auto; }
    #rk-btn-row { height: 3; layout: horizontal; padding: 0 2; margin-top: 1; }
    Button { min-width: 16; margin-right: 1; }
    """

    BINDINGS = [
        Binding("escape", "close", "Close", show=False),
    ]

    def __init__(self, pool: "AgentPool", cfgman: "ConfigManager",
                 host_ids: list[str], **kwargs):
        super().__init__(**kwargs)
        self._pool     = pool
        self._cfgman   = cfgman
        self._host_ids = host_ids
        self._keymgr          = SshKeyManager(pool, cfgman)
        self._rotation_active = False   # True while _do_rotate is running
        self._disable_pw: bool = False
        # host_id → {step → (ok, detail)}
        self._progress: dict[str, dict[str, tuple]] = {
            h: {} for h in host_ids}

    @staticmethod
    def _prog_id(hid: str) -> str:
        """Return a CSS-safe widget ID for a host's progress Static."""
        safe = "".join(c if c.isalnum() or c in "-_" else "_" for c in hid)
        return f"rk-prog-{safe}"

    def compose(self) -> ComposeResult:
        n = len(self._host_ids)
        labels = [
            (self._pool.state(h).config.label
             if h in self._pool.host_ids() else h)
            for h in self._host_ids
        ]
        with Container(id="rk-box"):
            with Container(id="rk-options"):
                yield Static(
                    f"[bold {CLR_WARNING}]What this does:[/]\n"
                    "  1. Generate new ed25519 keypair locally\n"
                    "  2. Push new pubkey to remote authorized_keys\n"
                    "  3. Verify new key works (test connect)\n"
                    "  4. Remove old pubkey from remote\n"
                    "  5. Backup old + new keys → key_backups/<host>_<ts>/\n"
                    "  6. Update deflect.json with new key path",
                    id="rk-info")
                yield Static("", id="rk-spacer")
                yield Static(
                    "Also disable PasswordAuthentication in sshd_config:",
                    id="rk-pw-label")
                with Horizontal(id="rk-pw-btns"):
                    yield Button("No  (safe default)",
                                 id="btn-pw-no",  variant="primary")
                    yield Button("Yes (more secure)",
                                 id="btn-pw-yes", variant="default")
            with Container(id="rk-progress"):
                for hid in self._host_ids:
                    try:
                        label = self._pool.state(hid).config.label
                    except Exception as e:
                        _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                        label = hid
                    pending_lines = "\n".join(
                        f"  [dim]○ {_ROTATE_STEP_LABELS[s]}[/]"
                        for s in _ROTATE_STEP_LABELS
                        if s in _ROTATE_BASE_STEPS
                    )
                    yield Static(
                        f"[bold {CLR_ACCENT}][{label}][/]\n{pending_lines}",
                        id=self._prog_id(hid))
            with Horizontal(id="rk-btn-row"):
                yield Button("▶ Start Rotation", id="btn-start",
                             variant="warning")
                yield Button("Cancel", id="btn-cancel",
                             variant="default")

    def on_mount(self) -> None:
        n = len(self._host_ids)
        labels = [
            (self._pool.state(h).config.label
             if h in self._pool.host_ids() else h)
            for h in self._host_ids
        ]
        box = self.query_one("#rk-box")
        box.border_title = (
            f"🔑  Rotate SSH Keys  -  {n} host{'s' if n!=1 else ''}: "
            + ", ".join(labels[:3]) + ("…" if n > 3 else "")
        )
        box.border_subtitle = " Esc:close"

    def on_button_pressed(self, event: Button.Pressed):
        bid = event.button.id
        _log.debug("[RotateKeyScreen] on_button_pressed: bid=%r hosts=%s",
                   bid, self._host_ids)
        if bid == "btn-cancel":
            self.dismiss(None)
        elif bid == "btn-pw-no":
            self._disable_pw = False
            _log.debug("[RotateKeyScreen] disable_pw set to False")
        elif bid == "btn-pw-yes":
            self._disable_pw = True
            _log.debug("[RotateKeyScreen] disable_pw set to True")
        elif bid == "btn-start":
            if self._rotation_active:
                _log.warning("[RotateKeyScreen] btn-start ignored - rotation already active")
                return
            _log.info("[RotateKeyScreen] Starting rotation: hosts=%s disable_pw=%s",
                      self._host_ids, self._disable_pw)
            # Disable button synchronously before handing off to worker
            try:
                event.button.disabled = True
                self.query_one("#btn-pw-yes").disabled = True
                self.query_one("#btn-pw-no").disabled  = True
            except Exception as e:
                _log.warning("[RotateKeyScreen] could not disable buttons: %s", e)
            self.run_worker(self._do_rotate(self._disable_pw), exclusive=False)
            _log.debug("[RotateKeyScreen] run_worker called")

    async def _do_rotate(self, disable_pw: bool):
        _log.info("[RotateKeyScreen._do_rotate] started: disable_pw=%s", disable_pw)
        self._rotation_active = True

        try:
            if len(self._host_ids) == 1:
                # single host - sequential
                hid = self._host_ids[0]
                _log.info("[RotateKeyScreen._do_rotate] single-host mode: %s", hid)
                async for step, ok, detail in self._keymgr.rotate_key(
                        hid, disable_pw):
                    _log.debug("[rotate_key] %s  step=%-20s ok=%s  %s",
                               hid, step, ok, detail)
                    self._update_host_progress(hid, step, ok, detail)
            else:
                # multiple hosts - parallel via bulk generator
                _log.info("[RotateKeyScreen._do_rotate] bulk mode: %s", self._host_ids)
                async for hid, step, ok, detail in self._keymgr.rotate_keys_bulk(
                        self._host_ids, disable_pw):
                    _log.debug("[rotate_key] %s  step=%-20s ok=%s  %s",
                               hid, step, ok, detail)
                    self._update_host_progress(hid, step, ok, detail)

            done_ok  = sum(
                1 for pr in self._progress.values()
                if pr.get("done", (False,))[0] is True)
            done_err = len(self._host_ids) - done_ok
            _log.info("[RotateKeyScreen._do_rotate] finished: ok=%d err=%d",
                      done_ok, done_err)
            self.app.notify(
                f"Key rotation: {done_ok} ✓  {done_err} ✗",
                severity="information" if done_err == 0 else "warning",
                timeout=8)
        except Exception as e:
            _log.exception("[RotateKeyScreen._do_rotate] UNHANDLED EXCEPTION: %s", e)
            self.app.notify(f"Rotation error: {e}", severity="error", timeout=12)
        finally:
            self._rotation_active = False
            _log.debug("[RotateKeyScreen._do_rotate] finished")
            try:
                self.query_one("#btn-start").disabled = False
                self.query_one("#btn-cancel", Button).label = "Close"
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

    def _update_host_progress(self, hid: str, step: str,
                               ok: Optional[bool], detail: str):
        _log.debug("[_update_host_progress] hid=%s step=%s ok=%s detail=%s",
                   hid, step, ok, detail)
        self._progress[hid][step] = (ok, detail)
        # Build a summary line for the widget
        pr = self._progress[hid]
        parts = []
        for s, lbl in _ROTATE_STEP_LABELS.items():
            if s not in pr:
                # Show base steps as pending; skip conditional steps not yet started
                if s in _ROTATE_BASE_STEPS:
                    line = Text("○ ", style="dim")
                    line.append(lbl, style="dim")
                    parts.append(line)
                continue
            o, d = pr[s]
            if o is None:
                sym = Text("⟳ ", style=f"bold {CLR_WARNING}")
            elif o:
                sym = Text("✓ ", style=f"bold {CLR_SUCCESS}")
            else:
                sym = Text("✗ ", style=f"bold {CLR_ERROR}")
            line = Text()
            line.append_text(sym)
            line.append(f"{lbl}", style="dim" if o is True else CLR_TEXT)
            if not o and d:
                line.append(f"\n  {d[:55]}", style=CLR_ERROR)
            parts.append(line)

        try:
            label = self._pool.state(hid).config.label
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            label = hid

        out = Text(f"[{label}]\n", style=f"bold {CLR_ACCENT}")
        for p in parts:
            out.append_text(p)
            out.append("\n")

        widget_id = self._prog_id(hid)
        try:
            self.query_one(f"#{widget_id}", Static).update(out)
            _log.debug("[_update_host_progress] widget #%s updated OK", widget_id)
        except Exception as e:
            _log.error("[_update_host_progress] query_one(#%s) FAILED: %s", widget_id, e)

    def action_close(self):
        if self._rotation_active:
            self.app.notify("Rotation in progress - please wait…",
                            severity="warning")
            return
        self.dismiss(None)


