class HostEditorScreen(ModalScreen):
    """
    TUI overlay for adding or editing an SSH host.
    Opened via Ctrl+N (new) or from a future host-list panel.
    """

    DEFAULT_CSS = """
    HostEditorScreen { align: center middle; }
    #editor-box {
        width: 62; height: auto; max-height: 92vh;
        border: double $accent;
        background: $surface;
        padding: 1 2;
    }
    #editor-title { text-style: bold; color: $accent; margin-bottom: 1; }
    .lbl { color: #888780; margin-top: 1; height: 1; }
    Input { margin-bottom: 0; }
    #auth-row { height: 3; margin-top: 1; }
    #auth-row Button { min-width: 12; margin-right: 1; }
    #auth-row Button.active { background: $accent 40%; color: $accent; text-style: bold; }
    .editor-tabs { height: 3; margin-bottom: 1; margin-top: 1; }
    .editor-tabs Button { min-width: 14; margin-right: 1; }
    .editor-tabs Button.active { background: $accent 40%; color: $accent; text-style: bold; }
    .editor-section { display: none; }
    .editor-section.visible { display: block; }
    #esec-general { max-height: 60vh; }
    #ai-instr-lbl { color: #888780; margin-top: 1; }
    #ai-instructions { height: 10; border: solid $primary; }
    #ai-examples { color: #888780; margin-top: 1; height: auto; }
    #btn-row { margin-top: 2; height: 3; }
    Button { margin-right: 1; min-width: 12; }
    #btn-row Button { min-width: 10; margin-right: 1; }
    """

    def __init__(self, pool: AgentPool,
                 host_id: Optional[str] = None,
                 clone_from: Optional[str] = None,
                 **kwargs):
        super().__init__(**kwargs)
        self._pool       = pool
        self._host_id    = host_id
        self._clone_from = clone_from
        self._editing    = host_id is not None
        self._cloning    = clone_from is not None and not self._editing
        self._auth_mode  = "key"      # updated by on_mount and auth buttons
        self._editor_tab = "general"  # "general" | "ai"

    def on_mount(self):
        e: Optional[HostConfig] = None
        if self._editing:
            try:
                e = self._pool.state(self._host_id).config
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        elif self._cloning:
            try:
                e = self._pool.state(self._clone_from).config
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        self._auth_mode = (e.auth if e and e.auth else "key")
        self._apply_auth_visibility()

    def _apply_auth_visibility(self):
        try:
            key_lbl  = self.query_one("#lbl-keypath")
            key_inp  = self.query_one("#inp-keypath")
            pw_lbl   = self.query_one("#lbl-password")
            pw_inp   = self.query_one("#inp-password")
            if self._auth_mode == "password":
                key_lbl.display = False
                key_inp.display = False
                pw_lbl.update("Password")
                pw_lbl.display  = True
                pw_inp.placeholder = "SSH password"
                pw_inp.display  = True
            else:
                key_lbl.display = True
                key_inp.display = True
                pw_lbl.update("Key Passphrase (optional)")
                pw_lbl.display  = True
                pw_inp.placeholder = "passphrase if key is encrypted"
                pw_inp.display  = True
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _auto_increment_label(self, label: str) -> str:
        """web-prod-01 → web-prod-02, myhost → myhost-2"""
        m = re.search(r"(\d+)$", label)
        if m:
            n   = int(m.group(1))
            pad = len(m.group(1))
            return label[: m.start()] + str(n + 1).zfill(pad)
        return label + "-2"

    def compose(self) -> ComposeResult:
        # source config: editing → host_id,  cloning → clone_from,  new → None
        e: Optional[HostConfig] = None
        if self._editing:
            try:
                e = self._pool.state(self._host_id).config
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        elif self._cloning:
            try:
                e = self._pool.state(self._clone_from).config
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

        if self._editing:
            title = "✎  Edit Host"
        elif self._cloning:
            src_label = e.label if e else self._clone_from
            title = f"⊕  Clone Host  [dim](from: {src_label})[/]"
        else:
            title = "+  New Host"

        # For clone: auto-increment label, clear address
        label_val   = e.label   if e else ""
        address_val = e.address if e else ""
        if self._cloning:
            label_val   = self._auto_increment_label(label_val)
            address_val = ""          # must be filled in by user

        auth_val = (e.auth if e and e.auth else "key")

        ai_instructions_val = getattr(e, "ai_instructions", "") if e else ""

        with Container(id="editor-box"):
            yield Static(title, id="editor-title")
            if self._cloning and e:
                yield Static(
                    f"[dim]Inherited:[/] port={e.port}  user={e.username}  "
                    f"key={e.key_path}  tags={','.join(e.tags) or '-'}",
                    classes="lbl")
            # Tab bar
            with Horizontal(classes="editor-tabs"):
                yield Button("⚙ General", id="etab-general", classes="active")
                yield Button("🤖 AI",     id="etab-ai")

            # ── General section ──
            with ScrollableContainer(id="esec-general", classes="editor-section visible"):
                yield Static("Label", classes="lbl")
                yield Input(value=label_val,
                            placeholder="My VPS", id="inp-label")
                yield Static("Address", classes="lbl")
                yield Input(value=address_val,
                            placeholder="192.168.1.100", id="inp-address")
                yield Static("Port", classes="lbl")
                yield Input(value=str(e.port if e else 22),
                            placeholder="22", id="inp-port")
                yield Static("Username", classes="lbl")
                yield Input(value=e.username if e else "root",
                            placeholder="root", id="inp-username")
                yield Static("Auth method", classes="lbl")
                with Horizontal(id="auth-row"):
                    yield Button("Key file", id="auth-btn-key",
                                 classes="active" if auth_val == "key" else "")
                    yield Button("Password", id="auth-btn-password",
                                 classes="active" if auth_val == "password" else "")
                yield Static("SSH Key path", classes="lbl", id="lbl-keypath")
                yield Input(value=e.key_path if e else "~/.ssh/id_rsa",
                            placeholder="~/.ssh/id_rsa", id="inp-keypath")
                yield Static(
                    "Password" if auth_val == "password"
                    else "Key Passphrase (optional)",
                    classes="lbl", id="lbl-password")
                yield Input(value=e.password if e and e.password and
                            not e.password.startswith("enc:") else "",
                            placeholder="SSH password" if auth_val == "password"
                                        else "passphrase if key is encrypted",
                            id="inp-password", password=True)
                yield Static("Tags (comma-separated)", classes="lbl")
                yield Input(value=", ".join(e.tags) if e else "",
                            placeholder="web, prod", id="inp-tags")

            # ── AI section ──
            with Container(id="esec-ai", classes="editor-section"):
                yield Static(
                    "AI Instructions  (freeform goals for 🤖 AI Managed Host loop)",
                    id="ai-instr-lbl")
                yield TextArea(
                    text=ai_instructions_val,
                    id="ai-instructions",
                )
                yield Static(
                    "[dim]Examples (all are actionable and work with the current engine):[/dim]\n"
                    "[dim]  Restart nginx if it stops. If nginx was restarted in the last 10 min"
                    " (check history) - send_notification 'nginx keeps crashing' instead.[/dim]\n"
                    "[dim]  If disk > 85%%: run 'find /var/log -name \"*.gz\" -mtime +30"
                    " -delete 2>/dev/null; df -h / | tail -1' and send_notification with result.[/dim]\n"
                    "[dim]  If RAM > 90%%: run 'ps aux --sort=-%%mem | head -4'"
                    " and send_notification with the output.[/dim]\n"
                    "[dim]  Every check: run 'systemctl is-active mysql 2>&1'. If failed -"
                    " restart it once. If history shows prior restart - escalate_to_human.[/dim]",
                    id="ai-examples",
                )

            with Horizontal(id="btn-row"):
                yield Button("Test",   variant="default", id="btn-test")
                yield Button("Save",   variant="primary",  id="btn-save")
                if self._editing:
                    yield Button("Delete", variant="warning", id="btn-delete")
                yield Button("Cancel", variant="error",    id="btn-cancel")

    def on_button_pressed(self, event: Button.Pressed) -> None:
        bid = event.button.id
        if bid == "btn-cancel":
            self.dismiss(None)
        elif bid == "btn-save":
            cfg = self._build_config()
            if cfg:
                asyncio.create_task(self._do_save(cfg))
        elif bid == "btn-test":
            cfg = self._build_config()
            if cfg:
                asyncio.create_task(self._do_test(cfg))
        elif bid == "btn-delete":
            asyncio.create_task(self._do_delete())
        elif bid in ("etab-general", "etab-ai"):
            self._editor_tab = bid[len("etab-"):]
            for t in ("general", "ai"):
                try:
                    self.query_one(f"#esec-{t}").set_class(
                        t == self._editor_tab, "visible")
                    self.query_one(f"#etab-{t}").set_class(
                        t == self._editor_tab, "active")
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
        elif bid in ("auth-btn-key", "auth-btn-password"):
            self._auth_mode = "password" if bid == "auth-btn-password" else "key"
            try:
                self.query_one("#auth-btn-key").set_class(
                    self._auth_mode == "key", "active")
                self.query_one("#auth-btn-password").set_class(
                    self._auth_mode == "password", "active")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            self._apply_auth_visibility()

    def _build_config(self) -> Optional[HostConfig]:
        try:
            label    = self.query_one("#inp-label",   Input).value.strip()
            address  = self.query_one("#inp-address", Input).value.strip()
            port     = int(self.query_one("#inp-port",    Input).value.strip() or "22")
            username = self.query_one("#inp-username",Input).value.strip() or "root"
            keypath  = self.query_one("#inp-keypath", Input).value.strip()
            password = self.query_one("#inp-password", Input).value.strip()
            tags_raw = self.query_one("#inp-tags",    Input).value.strip()
            tags     = [t.strip() for t in tags_raw.split(",") if t.strip()]
            if not address:
                self.app.notify("Address is required", severity="error")
                return None
            if self._auth_mode == "password" and not password:
                self.app.notify("Password is required for password auth",
                                severity="error")
                return None
            host_id = (self._host_id
                       or address.replace(".", "-").replace(":", "-"))
            ai_instructions = ""
            try:
                ai_instructions = self.query_one(
                    "#ai-instructions", TextArea).text.strip()
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            # Preserve existing monitoring config when editing
            existing_mon = SecurityMonitoringConfig()
            if self._editing and self._host_id:
                try:
                    existing_mon = self._pool.state(
                        self._host_id).config.monitoring
                except Exception as e:
                    _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                    pass
            return HostConfig(
                id=host_id, label=label or address,
                address=address, port=port,
                username=username,
                auth=self._auth_mode,
                key_path=keypath if self._auth_mode == "key" else "",
                # For key auth: password field holds optional key passphrase
                password=password,
                tags=tags,
                monitoring=existing_mon,
                ai_instructions=ai_instructions,
            )
        except ValueError as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"Invalid input: {e}", severity="error")
            return None

    async def _do_delete(self):
        if not self._editing or not self._host_id:
            return
        try:
            label = self._pool.state(self._host_id).config.label
        except Exception:
            label = self._host_id
        def _confirmed(confirmed: bool) -> None:
            if confirmed:
                asyncio.create_task(self._do_delete_confirmed(label))
        self.app.push_screen(
            _ConfirmDeleteDialog(label),
            _confirmed,
        )

    async def _do_delete_confirmed(self, label: str):
        await self._pool.remove_host(self._host_id)
        self.app.notify(f"✓ Host '{label}' deleted", severity="information")
        self.dismiss(None)

    async def _do_save(self, cfg: HostConfig):
        # When editing an existing host, stop the old agent first to avoid
        # running two concurrent agents for the same host ID.
        if self._editing and self._host_id:
            await self._pool.remove_host(self._host_id)
        await self._pool.add_host(cfg)
        self.app.notify(f"✓ Host '{cfg.label}' saved - connecting…",
                        severity="information")
        self.dismiss(cfg)

    async def _do_test(self, cfg: HostConfig):
        self.app.notify(f"Testing {cfg.address}:{cfg.port}…")
        loop = asyncio.get_running_loop()

        def _try(passphrase: Optional[str] = None):
            c = paramiko.SSHClient()
            c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            kw: dict = dict(hostname=cfg.address, port=cfg.port,
                            username=cfg.username, timeout=5)
            if cfg.auth == "password" and cfg.password:
                kw["password"] = cfg.password
            else:
                kp = os.path.expanduser(cfg.key_path) if cfg.key_path else None
                if kp and os.path.exists(kp):
                    kw["key_filename"] = kp
                    ph = passphrase if passphrase is not None else cfg.password
                    if ph:
                        kw["passphrase"] = ph
            c.connect(**kw); c.close()

        try:
            await loop.run_in_executor(None, _try)
            self.app.notify(f"✓ Connected to {cfg.address}!",
                            severity="information")
        except paramiko.ssh_exception.PasswordRequiredException as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            # Key is encrypted and no passphrase was provided - ask the user
            def _after_passphrase(pp: Optional[str]) -> None:
                if pp is None:
                    self.app.notify("Test cancelled.", severity="warning")
                    return
                async def _retry():
                    try:
                        await loop.run_in_executor(None, lambda: _try(pp))
                        self.app.notify(
                            f"✓ Connected to {cfg.address}! "
                            "Passphrase saved to Password field - press Save to keep it.",
                            severity="information",
                        )
                        # Pre-fill the password field so Save will persist it
                        try:
                            self.query_one("#inp-password", Input).value = pp
                        except Exception as e:
                            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                            pass
                    except Exception as e2:
                        _log.warning("Handled exception in block: %s: %s", type(e2).__name__, e2)  # TODO: improve log quality
                        self.app.notify(f"✗ {e2}", severity="error")
                asyncio.create_task(_retry())

            self.app.push_screen(
                PassphraseDialog(cfg.label or cfg.address),
                _after_passphrase,
            )
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            self.app.notify(f"✗ {e}", severity="error")


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: script_runner  (v0.4)
# Ctrl+S - Script library browser, inline editor, run on selected hosts,
#           deploy to remote path via SFTP, optionally schedule with cron.
# ══════════════════════════════════════════════════════════════════════════════

class ScriptScreen(ModalScreen):
    """
    Script Runner & Deploy.

    Layout:
      Left  (30) - file list from scripts_dir (.sh / .py / .rb / .pl)
      Right (1fr) - live preview of selected file (read-only Static)
      Bottom strip - env vars input, target path input, cron input, host selector

    Keys:
      ↑ ↓          - select script file
      Tab          - cycle panel focus (file list → options → output)
      p            - preview selected file content
      r / F5       - run selected script on checked hosts (via SSH stdin pipe)
      d            - deploy (SFTP upload) to remote_path + optional chmod +x
      c            - deploy + add cron entry
      e            - open inline editor for the selected script (TextArea)
      n            - new script (blank inline editor)
      s            - save inline editor buffer as a local file in scripts_dir
      Esc          - close
    """

    DEFAULT_CSS = """
    ScriptScreen { align: center middle; background: $background 80%; }
    #scr-box {
        width: 100%; height: 100%;
        border: double $warning;
        background: $surface;
    }
    #scr-box {
        border-title-color: $warning;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    #scr-layout { layout: horizontal; height: 1fr; }
    #scr-file-col {
        width: 32; border-right: solid $primary;
        overflow-y: auto;
    }
    #scr-right-col { width: 1fr; layout: vertical; }
    #scr-preview {
        height: 1fr;
        overflow-y: auto;
        overflow-x: auto;
        padding: 0 1;
        background: $background;
    }
    #scr-editor {
        height: 1fr;
        display: none;
    }
    #scr-options {
        height: auto;
        max-height: 12;
        border-top: solid $primary;
        padding: 0 1 1 1;
        background: $panel;
        overflow-y: auto;
    }
    #scr-output {
        height: 10;
        border-top: solid $primary;
        background: $background;
        overflow-y: auto;
        padding: 0 1;
    }
    .scr-file-row {
        height: 2; padding: 0 1;
        border-bottom: solid $primary;
    }
    .scr-file-row.selected {
        background: $accent 30%;
        color: $accent;
        text-style: bold;
    }
    .scr-opt-label {
        height: 1; color: grey;
        content-align: left middle;
        padding: 0 0;
    }
    #scr-opt-env    { height: 3; margin-bottom: 1; }
    #scr-opt-path   { height: 3; margin-bottom: 1; }
    #scr-opt-cron   { height: 3; margin-bottom: 1; }
    #scr-opt-hosts  { height: 3; margin-bottom: 1; }
    #scr-ai-desc    { height: 3; }
    """

    BINDINGS = [
        Binding("escape",  "close_scripts",  "Close",   show=False),
        Binding("up",      "file_up",        "Up",      show=False),
        Binding("down",    "file_down",       "Down",    show=False),
        Binding("r",       "run_script",      "Run",     show=False),
        Binding("f5",      "run_script",      "Run",     show=False),
        Binding("d",       "deploy_script",   "Deploy",  show=False),
        Binding("c",       "deploy_cron",     "Cron",    show=False),
        Binding("e",       "edit_script",     "Edit",    show=False),
        Binding("n",       "new_script",      "New",     show=False),
        Binding("s",       "save_script",     "Save",    show=False),
        Binding("p",       "preview_script",  "Preview", show=False),
        Binding("g",       "ai_generate",     "AI Gen",  show=False),
    ]

    def __init__(self, pool: "AgentPool", cfg: "AppConfig", **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._cfg         = cfg
        self._scripts_dir = (DEFLECT_DIR / cfg.scripts_dir).resolve()
        self._files: list[Path] = []          # list of script file paths
        self._sel_idx: int      = 0           # selected file index
        self._editing: bool     = False       # inline editor visible
        self._editor_buf: str   = ""          # current editor content
        self._editor_name: str  = ""          # filename being edited
        self._script_running: bool     = False
        self._output_lines: list[str] = []

    # ── Helpers ───────────────────────────────────────────────────────────────

    def _scan_files(self) -> list[Path]:
        """Return sorted list of .sh/.py/.rb/.pl files from scripts_dir."""
        if not self._scripts_dir.exists():
            return []
        exts = {".sh", ".py", ".rb", ".pl", ".bash"}
        return sorted(
            [p for p in self._scripts_dir.iterdir()
             if p.is_file() and p.suffix in exts],
            key=lambda p: p.name.lower())

    def _fmt_size(self, p: Path) -> str:
        try:
            s = p.stat().st_size
            return f"{s}B" if s < 1024 else f"{s//1024}K"
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return "?"

    def _file_icon(self, p: Path) -> str:
        return {"py": "🐍", "sh": "📜", "bash": "📜",
                "rb": "💎", "pl": "🦪"}.get(p.suffix.lstrip("."), "📄")

    def _host_ids_from_input(self, raw: str) -> list[str]:
        """Parse host selector: empty/all → all; comma-list of ids/labels.
        Returns empty list if a non-empty selector matches nothing (no silent fallback).
        """
        raw = raw.strip()
        if not raw or raw.lower() == "all":
            return self._pool.host_ids()
        ids_all = self._pool.host_ids()
        result = []
        for token in raw.split(","):
            token = token.strip()
            if not token:
                continue
            if token in ids_all:
                result.append(token)
            else:
                # match by label prefix
                for hid in ids_all:
                    try:
                        lbl = self._pool.state(hid).config.label.lower()
                        if lbl.startswith(token.lower()):
                            result.append(hid)
                            break
                    except Exception as e:
                        _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                        pass
        # Do NOT fall back to ids_all - if user typed something and it matched
        # nothing, return empty so the caller can show an error.
        return result

    def _get_script_content(self) -> Optional[str]:
        """Return content from editor buffer (if editing) or selected file."""
        if self._editing and self._editor_buf:
            return self._editor_buf
        if not self._files:
            return None
        try:
            return self._files[self._sel_idx].read_text(encoding="utf-8", errors="replace")
        except Exception as e:
            _log.debug("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            return f"# Error reading file: {e}"

    def _get_script_name(self) -> str:
        if self._editing and self._editor_name:
            return self._editor_name
        if self._files:
            return self._files[self._sel_idx].name
        return "script.sh"

    # ── Compose ───────────────────────────────────────────────────────────────

    def compose(self) -> ComposeResult:
        self._files = self._scan_files()
        scripts_dir_str = str(self._scripts_dir)

        with Container(id="scr-box"):
            with Horizontal(id="scr-layout"):
                # ── Left: file list
                with Vertical(id="scr-file-col"):
                    yield Static(
                        f"[bold {CLR_WARNING}]Scripts[/]  "
                        f"[dim]{len(self._files)} files[/]",
                        classes="scr-opt-label",
                        markup=True)
                    if self._files:
                        for i, p in enumerate(self._files):
                            sz   = self._fmt_size(p)
                            icon = self._file_icon(p)
                            txt  = Text()
                            txt.append(f"{icon} ", style=CLR_WARNING)
                            txt.append(p.name[:22], style="bold" if i == 0 else "")
                            txt.append(f"  {sz}", style=f"dim {CLR_TEXT_DIM}")
                            yield Static(
                                txt,
                                id=f"scr-file-{i}",
                                classes="scr-file-row" + (" selected" if i == 0 else ""))
                    else:
                        yield Static(
                            f"[dim]No scripts found\nin {self._scripts_dir.name}/[/]",
                            classes="scr-file-row",
                            markup=True)

                # ── Right: preview / editor + options + output
                with Vertical(id="scr-right-col"):
                    if self._files:
                        try:
                            preview_txt = self._files[0].read_text(
                                encoding="utf-8", errors="replace")[:4000]
                        except Exception as e:
                            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                            preview_txt = "# (unreadable)"
                        yield Static(
                            f"[dim]{self._files[0].name}[/]\n" +
                            preview_txt,
                            id="scr-preview",
                            markup=False)
                    else:
                        yield Static(
                            "# No script selected\n# Press n to create a new script",
                            id="scr-preview")
                    yield TextArea(
                        "",
                        id="scr-editor",
                        show_line_numbers=True)
                    with Vertical(id="scr-options"):
                        yield Static("Env vars (KEY=val KEY2=val2):",
                                     classes="scr-opt-label")
                        yield Input(
                            placeholder="DEPLOY_ENV=prod VERSION=1.2",
                            id="scr-opt-env")
                        yield Static("Remote deploy path (optional):",
                                     classes="scr-opt-label")
                        yield Input(
                            placeholder="/opt/deflect-scripts/cleanup.sh",
                            id="scr-opt-path")
                        yield Static(
                            "Cron schedule (optional, e.g. 0 3 * * *):",
                            classes="scr-opt-label")
                        yield Input(
                            placeholder="0 3 * * *",
                            id="scr-opt-cron")
                        yield Static("Target hosts (empty=all, or id1,id2):",
                                     classes="scr-opt-label")
                        yield Input(
                            placeholder="all",
                            id="scr-opt-hosts")
                        yield Static(
                            "AI script description (g = generate):",
                            classes="scr-opt-label")
                        yield Input(
                            placeholder="Monthly nginx log rotation with gzip archive",
                            id="scr-ai-desc")
                    yield Static("", id="scr-output")

    def on_mount(self) -> None:
        box = self.query_one("#scr-box")
        box.border_title = f"📜  SCRIPT RUNNER  -  {self._scripts_dir}"
        box.border_subtitle = (
            " r/F5:run  d:deploy  c:deploy+cron  e:edit  n:new  s:save"
            "  g:AI gen  ↑↓:select  Esc:close"
        )

    # ── File navigation ───────────────────────────────────────────────────────

    def action_file_up(self):
        if not self._files:
            return
        self._set_sel(max(0, self._sel_idx - 1))

    def action_file_down(self):
        if not self._files:
            return
        self._set_sel(min(len(self._files) - 1, self._sel_idx + 1))

    def _set_sel(self, idx: int):
        old = self._sel_idx
        self._sel_idx = idx
        # update CSS classes
        for i in range(len(self._files)):
            try:
                w = self.query_one(f"#scr-file-{i}", Static)
                if i == idx:
                    w.add_class("selected")
                elif i == old:
                    w.remove_class("selected")
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        # auto-preview
        self.action_preview_script()

    def action_preview_script(self):
        """Show selected file content in the preview pane."""
        if not self._files or self._editing:
            return
        p = self._files[self._sel_idx]
        try:
            content = p.read_text(encoding="utf-8", errors="replace")[:6000]
        except Exception as e:
            _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            content = f"# Error: {e}"
        try:
            self.query_one("#scr-preview", Static).update(
                f"── {p.name} ({self._fmt_size(p)}) ──\n{content}")
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── Inline editor ─────────────────────────────────────────────────────────

    def action_edit_script(self):
        """Load selected file into inline editor."""
        content = self._get_script_content() or ""
        self._editor_buf  = content
        self._editor_name = self._get_script_name()
        self._editing     = True
        try:
            ta = self.query_one("#scr-editor", TextArea)
            ta.load_text(content)
            ta.display = True
            self.query_one("#scr-preview", Static).display = False
            ta.focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_new_script(self):
        """Open blank inline editor for a new script."""
        self._editor_buf  = "#!/usr/bin/env bash\nset -euo pipefail\n\n"
        self._editor_name = "new_script.sh"
        self._editing     = True
        try:
            ta = self.query_one("#scr-editor", TextArea)
            ta.load_text(self._editor_buf)
            ta.display = True
            self.query_one("#scr-preview", Static).display = False
            ta.focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_save_script(self):
        """Save inline editor buffer to scripts_dir."""
        if not self._editing:
            return
        try:
            ta = self.query_one("#scr-editor", TextArea)
            self._editor_buf = ta.text
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass
        if not self._editor_buf:
            self.app.notify("Nothing to save", severity="warning")
            return
        try:
            self._scripts_dir.mkdir(parents=True, exist_ok=True)
            out_path = self._scripts_dir / self._editor_name
            out_path.write_text(self._editor_buf, encoding="utf-8")
            self.app.notify(f"✓ Saved {self._editor_name}", severity="information")
            _log.info("Saved script to %s", out_path)
            # refresh file list
            self._files = self._scan_files()
            # exit editor mode
            self._editing = False
            try:
                self.query_one("#scr-editor", TextArea).display = False
                self.query_one("#scr-preview", Static).display = True
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
        except Exception as e:
            _log.error("Failed to save script %s: %s: %s",
                      self._scripts_dir / self._editor_name, type(e).__name__, e)
            self.app.notify(f"✗ Save failed: {e}", severity="error")

    # ── Run ───────────────────────────────────────────────────────────────────

    def action_run_script(self):
        asyncio.create_task(self._do_run())

    async def _do_run(self):
        if self._script_running:
            self.app.notify("Already running…", severity="warning")
            return
        content = self._get_script_content()
        if not content:
            self.app.notify("No script selected or editor empty", severity="warning")
            return

        try:
            raw_hosts = self.query_one("#scr-opt-hosts", Input).value
            env_raw   = self.query_one("#scr-opt-env",   Input).value.strip()
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            raw_hosts = ""
            env_raw   = ""

        host_ids = self._host_ids_from_input(raw_hosts)
        if not host_ids:
            msg = (f"No hosts matched '{raw_hosts}'" if raw_hosts.strip()
                   else "No hosts available")
            self.app.notify(msg, severity="warning")
            return

        name = self._get_script_name()
        self._script_running = True
        self._output_lines = []
        self.app.notify(
            f"▶ Running {name} on {len(host_ids)} host(s)…",
            severity="information")

        # Build env prefix
        env_prefix = ""
        if env_raw:
            env_prefix = " ".join(
                f"export {pair};" for pair in env_raw.split() if "=" in pair
            ) + " "

        # Run in parallel - pipe script via stdin (bash -s)
        loop = asyncio.get_running_loop()

        async def _run_one(hid: str) -> tuple[str, bool, str]:
            try:
                agent = self._pool.agent(hid)
                hs    = agent._host_state
                if not hs.client:
                    return hid, False, "not connected"

                def _exec_via_stdin():
                    transport = hs.client.get_transport()
                    if not transport or not transport.is_active():
                        raise RuntimeError("transport not active")
                    chan = transport.open_session()
                    chan.settimeout(60)
                    cmd = f"{env_prefix}bash -s"
                    _record_screen_exec("script")
                    chan.exec_command(cmd)
                    # send script via stdin
                    chan.sendall(content.encode("utf-8", errors="replace"))
                    chan.shutdown_write()
                    out = chan.makefile("r").read(65536)
                    err = chan.makefile_stderr("r").read(8192)
                    rc  = chan.recv_exit_status()
                    chan.close()
                    return rc, out.strip(), err.strip()

                rc, out, err = await loop.run_in_executor(None, _exec_via_stdin)
                ok = (rc == 0)
                snippet = (out if ok else err or out)[:200]
                if not ok:
                    _log.warning("script_run %s on %s rc=%s: %s", name, hid, rc, (err or out)[:200])
                return hid, ok, snippet
            except Exception as e:
                _log.error("script_run %s on %s: %s", name, hid, e)
                return hid, False, str(e)[:120]

        tasks = [asyncio.create_task(_run_one(hid)) for hid in host_ids]
        results = await asyncio.gather(*tasks, return_exceptions=True)

        ok_n = 0
        for r in results:
            if isinstance(r, Exception):
                self._output_lines.append(f"✗ (exception) {r}")
                continue
            hid, ok, snippet = r
            try:
                label = self._pool.state(hid).config.label
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                label = hid
            icon = "✓" if ok else "✗"
            self._output_lines.append(f"{icon} {label}: {snippet or '(no output)'}")
            if ok:
                ok_n += 1

        err_n = len(host_ids) - ok_n
        self._update_output()
        self.app.notify(
            f"✓ {ok_n} ok  ✗ {err_n} error(s)",
            severity="information" if err_n == 0 else "warning")
        self._script_running = False

    # ── Deploy ────────────────────────────────────────────────────────────────

    def action_deploy_script(self):
        asyncio.create_task(self._do_deploy(with_cron=False))

    def action_deploy_cron(self):
        asyncio.create_task(self._do_deploy(with_cron=True))

    async def _do_deploy(self, with_cron: bool):
        if self._script_running:
            self.app.notify("Already running…", severity="warning")
            return
        content = self._get_script_content()
        if not content:
            self.app.notify("No script selected or editor empty", severity="warning")
            return

        try:
            remote_path = self.query_one("#scr-opt-path",  Input).value.strip()
            cron_sched  = self.query_one("#scr-opt-cron",  Input).value.strip()
            raw_hosts   = self.query_one("#scr-opt-hosts", Input).value
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            remote_path = ""
            cron_sched  = ""
            raw_hosts   = ""

        if not remote_path:
            name = self._get_script_name()
            remote_path = f"/opt/deflect-scripts/{name}"

        host_ids = self._host_ids_from_input(raw_hosts)
        if not host_ids:
            msg = (f"No hosts matched '{raw_hosts}'" if raw_hosts.strip()
                   else "No hosts available")
            self.app.notify(msg, severity="warning")
            return

        self._script_running = True
        self._output_lines = []
        action_word = "Deploy+Cron" if with_cron else "Deploy"
        self.app.notify(
            f"📤 {action_word}: {remote_path} → {len(host_ids)} host(s)…",
            severity="information")

        loop = asyncio.get_running_loop()
        script_bytes = content.encode("utf-8", errors="replace")
        name = self._get_script_name()

        async def _deploy_one(hid: str) -> tuple[str, bool, str]:
            try:
                agent = self._pool.agent(hid)
                hs    = agent._host_state
                if not hs.client:
                    return hid, False, "not connected"

                def _do_sftp():
                    import io
                    transport = hs.client.get_transport()
                    if not transport or not transport.is_active():
                        raise RuntimeError("transport not active")

                    sftp = paramiko.SFTPClient.from_transport(transport)
                    try:
                        # ensure remote directory exists
                        remote_dir = remote_path.rsplit("/", 1)[0]
                        if remote_dir:
                            # mkdir -p equivalent via exec_command
                            chan = transport.open_session()
                            chan.exec_command(f"mkdir -p {remote_dir}")
                            chan.recv_exit_status()
                            chan.close()

                        # upload
                        with sftp.open(remote_path, "wb") as f:
                            f.write(script_bytes)

                        # chmod +x
                        sftp.chmod(remote_path, 0o755)
                    finally:
                        sftp.close()

                    # Add cron if requested
                    cron_msg = ""
                    if with_cron and cron_sched:
                        cron_entry = f"{cron_sched} {remote_path} # deflect-{name}"
                        chan2 = transport.open_session()
                        chan2.exec_command(
                            f"(crontab -l 2>/dev/null | grep -v '# deflect-{name}'; "
                            f"echo '{cron_entry}') | crontab -")
                        chan2.recv_exit_status()
                        chan2.close()
                        cron_msg = f"  cron: {cron_sched}"

                    return cron_msg

                cron_msg = await loop.run_in_executor(None, _do_sftp)
                _log.info("deploy %s → %s%s", hid, remote_path, cron_msg)
                return hid, True, f"→ {remote_path}{cron_msg}"
            except Exception as e:
                _log.error("deploy %s → %s: %s", hid, remote_path, e)
                return hid, False, str(e)[:120]

        tasks   = [asyncio.create_task(_deploy_one(hid)) for hid in host_ids]
        results = await asyncio.gather(*tasks, return_exceptions=True)

        ok_n = 0
        for r in results:
            if isinstance(r, Exception):
                self._output_lines.append(f"✗ (exception) {r}")
                continue
            hid, ok, msg = r
            try:
                label = self._pool.state(hid).config.label
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                label = hid
            icon = "✓" if ok else "✗"
            self._output_lines.append(f"{icon} {label}: {msg}")
            if ok:
                ok_n += 1

        err_n = len(host_ids) - ok_n
        self._update_output()

        # persist deployed scripts to config if cfgman available
        if ok_n > 0:
            try:
                import time as _t
                for r in results:
                    if isinstance(r, tuple) and r[1]:
                        hid = r[0]
                        cfg_data = self._pool._cfgman._data if hasattr(
                            self._pool, "_cfgman") else None
                        if cfg_data is not None:
                            deployed = cfg_data.setdefault("deployed_scripts", [])
                            deployed.append({
                                "host": hid,
                                "path": remote_path,
                                "cron": cron_sched if with_cron else "",
                                "script": name,
                                "deployed_at": _t.strftime("%Y-%m-%dT%H:%M:%SZ",
                                                           _t.gmtime()),
                            })
                            self._pool._cfgman._save()
            except Exception as e:
                _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                pass  # non-critical

        self.app.notify(
            f"✓ {ok_n} deployed  ✗ {err_n} error(s)",
            severity="information" if err_n == 0 else "warning")
        self._script_running = False

    # ── Output ────────────────────────────────────────────────────────────────

    def _update_output(self):
        txt = Text()
        for line in self._output_lines[-20:]:
            color = CLR_SUCCESS if line.startswith("✓") else CLR_ERROR
            txt.append(line + "\n", style=color)
        try:
            self.query_one("#scr-output", Static).update(txt)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    # ── AI Generate ──────────────────────────────────────────────────────────

    def action_ai_generate(self):
        asyncio.create_task(self._do_ai_generate())

    async def _do_ai_generate(self):
        """
        Read the AI description input, call the LLM via script_gen prompt,
        strip markdown fences, auto-detect .sh/.py, and open result in the
        inline editor so the user can review, tweak, save, and run/deploy.
        """
        if self._script_running:
            self.app.notify("Already running…", severity="warning")
            return
        try:
            description = self.query_one("#scr-ai-desc", Input).value.strip()
            raw_hosts   = self.query_one("#scr-opt-hosts", Input).value
        except Exception as e:
            _log.warning("Exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            description = ""
            raw_hosts   = ""

        if not description:
            self.app.notify(
                "Enter a script description in the 'AI script description' field first",
                severity="warning")
            return

        engine = self._pool.ai_engine
        if not engine.enabled:
            self.app.notify(
                "AI disabled - enable in F6 → 🤖 AI", severity="warning")
            return

        # Pick first matched host for context; fallback to first pool host
        host_ids = self._host_ids_from_input(raw_hosts)
        hid = host_ids[0] if host_ids else next(iter(self._pool.host_ids()), None)

        label = address = os_info = inv_str = ""
        if hid:
            try:
                hs      = self._pool.state(hid)
                label   = hs.config.label
                address = hs.config.address
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass
            try:
                m = self._pool.metrics_view().get(hid)
                if m:
                    os_info = getattr(m, "os_info",   "") or ""
                    inv     = getattr(m, "inventory",  {}) or {}
                    inv_str = ", ".join(
                        f"{k}={v}" for k, v in
                        list(inv.items())[:self._cfg.ai.ctx_max_inv_entries]
                    ) or "-"
            except Exception as e:
                _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
                pass

        system = _AI_PROMPTS["script_gen"].format(
            label         = label   or "server",
            address       = address or "-",
            os_info       = os_info or "Linux",
            inventory_str = inv_str or "-",
            safe_footer   = _SAFE_FOOTER,
        )

        self.app.notify("⟳ Generating script…", severity="information")
        raw = await engine.call(description, system=system, tier="smart")

        if raw == engine.DISABLED:
            self.app.notify("AI disabled - enable in F6 → 🤖 AI", severity="warning")
            return
        if raw.startswith("✗"):
            self.app.notify(f"AI error: {raw}", severity="error")
            return

        # Strip markdown code fences (```bash, ```python, ```)
        text = raw.strip()
        if text.startswith("```"):
            first_nl = text.find("\n")
            if first_nl != -1:
                text = text[first_nl + 1:]
            if text.rstrip().endswith("```"):
                text = text.rstrip()[:-3].rstrip()

        # Auto-detect extension from shebang
        if text.lstrip().startswith(("#!/usr/bin/env python", "#!/usr/bin/python")):
            ext = ".py"
        else:
            ext = ".sh"

        # Build filename from description slug
        slug = re.sub(r"[^a-z0-9]+", "_", description.lower()[:30]).strip("_")
        self._editor_name = f"ai_{slug}{ext}"
        self._editor_buf  = text
        self._editing     = True

        try:
            ta = self.query_one("#scr-editor", TextArea)
            ta.load_text(text)
            ta.display = True
            self.query_one("#scr-preview", Static).display = False
            ta.focus()
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

        self.app.notify(
            f"✓ AI generated: {self._editor_name}   s=save  r=run",
            severity="information")

    def action_close_scripts(self):
        self.dismiss(None)


