    def action_show_netconn(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("Network connections not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        hid = ids[self._focus_idx % len(ids)] if ids else ""
        self.push_screen(NetConnectionsScreen(self._pool, self._metrics, focused_host_id=hid))

    def action_show_db(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("DB monitor not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        hid = ids[self._focus_idx % len(ids)] if ids else ""
        self.push_screen(DBScreen(self._pool, self._metrics, focused_host_id=hid))

    def action_show_git(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("Git/Deploy not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        hid = ids[self._focus_idx % len(ids)] if ids else ""
        self.push_screen(DeployScreen(self._pool, self._metrics, focused_host_id=hid))

    def action_show_backup(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("Backup monitor not available in demo mode", severity="warning")
            return
        ids = self._pool.host_ids()
        hid = ids[self._focus_idx % len(ids)] if ids else ""
        self.push_screen(BackupScreen(self._pool, self._metrics, focused_host_id=hid))

    def action_show_logagg(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("Log aggregation not available in demo mode", severity="warning")
            return
        self.push_screen(LogAggScreen(self._pool))

    def action_show_env(self):
        if not hasattr(self._pool, "add_host"):
            self.notify("Env diff not available in demo mode", severity="warning")
            return
        self.push_screen(EnvScreen(self._pool, self._metrics))


