# SECTION: net_connections_screen  (v0.5)
# ══════════════════════════════════════════════════════════════════════════════


class NetConnectionsScreen(ModalScreen):
    """
    Ctrl+B - Network Connections Monitor.

    Tabs: Connections | Summary
    Keys:
      1 / 2      - switch tab
      f          - cycle state filter (ALL / ESTAB / TIME-WAIT / CLOSE-WAIT / LISTEN)
      h          - toggle host filter (all / focused host)
      r          - refresh
      Esc        - close
    """

    DEFAULT_CSS = """
    NetConnectionsScreen { align: center middle; }
    #netconn-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    NetConnectionsScreen #tab-bar { height: 1; }
    NetConnectionsScreen DataTable { height: 1fr; }
    NetConnectionsScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close",        "Close"),
        Binding("r",      "refresh",      "Refresh"),
        Binding("f",      "cycle_filter", "Filter"),
        Binding("h",      "toggle_host",  "Host"),
        Binding("1",      "tab_conns",    "Connections"),
        Binding("2",      "tab_summary",  "Summary"),
    ]

    _STATES = ["ALL", "ESTAB", "TIME-WAIT", "CLOSE-WAIT", "LISTEN"]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool         = pool
        self._metrics      = metrics
        self._focused      = focused_host_id
        self._filter_state = 0      # index into _STATES
        self._filter_host  = False
        self._tab          = "conns"

    def compose(self):
        with Vertical(id="netconn-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-conns"):
                with Vertical(id="view-conns"):
                    yield DataTable(id="conn-table", zebra_stripes=True)
                with Vertical(id="view-summary"):
                    yield DataTable(id="summary-table", zebra_stripes=True)
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#netconn-box")
        box.border_title = "🌐  Network Connections"
        box.border_subtitle = " 1:Connections  2:Summary  f:filter state  h:filter host  r:refresh  Esc:close"
        self._build_tables()
        self._refresh_data()

    def _build_tables(self):
        ct: DataTable = self.query_one("#conn-table", DataTable)
        ct.clear(columns=True)
        ct.add_columns("Host", "State", "Local Port", "Remote IP", "Remote Port", "Process")
        st: DataTable = self.query_one("#summary-table", DataTable)
        st.clear(columns=True)
        st.add_columns("Host", "ESTAB", "TIME-WAIT", "CLOSE-WAIT", "LISTEN", "Total", "⚠")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_conn_table()
        self._fill_summary_table()
        self._update_tab_bar()
        self._update_status()

    def _fill_conn_table(self):
        t: DataTable = self.query_one("#conn-table", DataTable)
        t.clear()
        state_filter = self._STATES[self._filter_state]
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            for conn in m.net_connections:
                state = conn.get("state", "")
                if state_filter != "ALL" and state != state_filter:
                    continue
                state_style = (
                    "green"    if state == "ESTAB"      else
                    "yellow"   if state == "TIME-WAIT"  else
                    "bold red" if state == "CLOSE-WAIT" else
                    "grey70"
                )
                remote_ip = conn.get("remote_ip", "")
                # highlight external IPs
                is_external = remote_ip and not remote_ip.startswith(
                    ("10.", "172.", "192.168.", "127.", "*", "0.0.0.0", "::")
                )
                ip_style = "cyan" if is_external else "default"
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(state, style=state_style),
                    Text(conn.get("local_port", ""), style="grey70"),
                    Text(remote_ip[:22], style=ip_style),
                    Text(conn.get("remote_port", ""), style="grey70"),
                    Text(conn.get("process", "")[:20], style="default"),
                )

    def _fill_summary_table(self):
        t: DataTable = self.query_one("#summary-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            by_state: dict[str, int] = {}
            for c in m.net_connections:
                s = c.get("state", "?")
                by_state[s] = by_state.get(s, 0) + 1
            estab  = by_state.get("ESTAB",      0)
            tw     = by_state.get("TIME-WAIT",  0)
            cw     = by_state.get("CLOSE-WAIT", 0)
            listen = by_state.get("LISTEN",     0)
            total  = len(m.net_connections)
            warnings = []
            if cw > 50:
                warnings.append(f"CLOSE_WAIT:{cw} (leak?)")
            if tw > 200:
                warnings.append(f"TIME_WAIT:{tw} (high load)")
            warn_str = ", ".join(warnings)
            t.add_row(
                Text(label[:14], style="cyan"),
                Text(str(estab),  style="green"),
                Text(str(tw),     style="yellow"   if tw > 100 else "default"),
                Text(str(cw),     style="bold red" if cw > 50  else "default"),
                Text(str(listen), style="grey70"),
                Text(str(total),  style="default"),
                Text(warn_str[:40], style="bold red" if warnings else "grey50"),
            )

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [("1", "Connections", "conns"), ("2", "Summary", "summary")]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        state_filter = self._STATES[self._filter_state]
        total = sum(
            len(self._metrics.get(hid).net_connections)
            for hid in self._host_ids()
            if self._metrics.get(hid)
        )
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused)
            host_label = st.config.label if st else self._focused
        t = Text()
        t.append(f" {total} connections", style="grey70")
        t.append(f"  filter: {state_filter}", style="bold cyan")
        t.append(f"  host: {host_label}", style="grey70")
        t.append("  | f:filter  h:host  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def action_close(self):
        self.dismiss(None)

    def action_refresh(self):
        self._refresh_data()
        self.notify("Refreshed", severity="information")

    def action_cycle_filter(self):
        self._filter_state = (self._filter_state + 1) % len(self._STATES)
        self._refresh_data()

    def action_toggle_host(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_conns(self):
        self._tab = "conns"
        self.query_one(ContentSwitcher).current = "view-conns"
        self._update_tab_bar()

    def action_tab_summary(self):
        self._tab = "summary"
        self.query_one(ContentSwitcher).current = "view-summary"
        self._update_tab_bar()


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: db_screen  (v0.5)
# ══════════════════════════════════════════════════════════════════════════════


class DBScreen(ModalScreen):
    """
    Ctrl+Y - Database Monitor.

    Auto-detects PostgreSQL / MySQL / Redis / MongoDB on each host.
    Tabs: Overview | Slow Log
    Keys:
      1 / 2      - switch tab
      h          - toggle host filter (all / focused host)
      r          - refresh (re-poll immediately)
      Esc        - close
    """

    DEFAULT_CSS = """
    DBScreen { align: center middle; }
    #db-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    DBScreen #tab-bar  { height: 1; }
    DBScreen DataTable { height: 1fr; }
    DBScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close",       "Close"),
        Binding("r",      "refresh",     "Refresh"),
        Binding("h",      "toggle_host", "Host"),
        Binding("1",      "tab_overview","Overview"),
        Binding("2",      "tab_slowlog", "Slow Log"),
    ]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._metrics     = metrics
        self._focused     = focused_host_id
        self._filter_host = False
        self._tab         = "overview"

    def compose(self):
        with Vertical(id="db-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-overview"):
                with Vertical(id="view-overview"):
                    yield DataTable(id="overview-table", zebra_stripes=True)
                with Vertical(id="view-slowlog"):
                    yield DataTable(id="slow-table", zebra_stripes=True)
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#db-box")
        box.border_title = "🗄  Database Monitor"
        box.border_subtitle = " 1:Overview  2:Slow Log  h:filter host  r:refresh  Esc:close"
        self._build_tables()
        self._refresh_data()

    def _build_tables(self):
        ot: DataTable = self.query_one("#overview-table", DataTable)
        ot.clear(columns=True)
        ot.add_columns("Host", "Engine", "Port", "Status", "Conn", "Size MB", "QPS", "Hit%", "⚠")

        st: DataTable = self.query_one("#slow-table", DataTable)
        st.clear(columns=True)
        st.add_columns("Host", "Engine", "Slow Query")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_overview()
        self._fill_slowlog()
        self._update_tab_bar()
        self._update_status()

    def _fill_overview(self):
        t: DataTable = self.query_one("#overview-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            if not m.db_instances:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("-", style="grey50"),
                    Text(""), Text("no DB detected", style="grey50"),
                    Text(""), Text(""), Text(""), Text(""), Text(""),
                )
                continue
            for db in m.db_instances:
                engine = db.get("engine", "?")
                status = db.get("status", "?")
                conns  = db.get("connections", -1)
                maxc   = db.get("max_connections", -1)
                size   = db.get("size_mb", 0)
                qps    = db.get("qps", -1)
                hit    = db.get("hit_rate", -1)

                status_style = "green" if status == "ok" else "bold red"
                conn_str = f"{conns}" if conns >= 0 else "?"
                if maxc > 0:
                    conn_pct = conns / maxc * 100
                    conn_style = "bold red" if conn_pct > 80 else ("yellow" if conn_pct > 60 else "green")
                else:
                    conn_style = "default"
                size_str = f"{size:.0f}" if size else "?"
                qps_str  = f"{qps}" if qps >= 0 else "?"
                hit_str  = f"{hit:.1f}" if hit >= 0 else "?"
                hit_style = "bold red" if (hit >= 0 and hit < 90) else ("yellow" if (hit >= 0 and hit < 95) else "green")

                # warnings
                warns = []
                if maxc > 0 and conns / maxc > 0.8:
                    warns.append("conn>80%")
                if hit >= 0 and hit < 90:
                    warns.append(f"hit<90%")
                warn_str = ",".join(warns)

                engine_icons = {"postgresql": "🐘", "redis": "🔴", "mysql": "🐬", "mongodb": "🍃"}
                icon = engine_icons.get(engine, "🗄")

                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(f"{icon} {engine}", style="default"),
                    Text(str(db.get("port", "")), style="grey70"),
                    Text(status, style=status_style),
                    Text(conn_str, style=conn_style),
                    Text(size_str, style="default"),
                    Text(qps_str, style="default"),
                    Text(hit_str, style=hit_style),
                    Text(warn_str, style="bold red" if warns else "grey50"),
                )

    def _fill_slowlog(self):
        t: DataTable = self.query_one("#slow-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            for db in m.db_instances:
                engine = db.get("engine", "?")
                for entry in db.get("slowlog", []):
                    t.add_row(
                        Text(label[:14], style="cyan"),
                        Text(engine, style="yellow"),
                        Text(str(entry)[:120], style="default"),
                    )

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [("1", "Overview", "overview"), ("2", "Slow Log", "slowlog")]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        total_dbs = sum(
            len(self._metrics.get(hid).db_instances)
            for hid in self._host_ids()
            if self._metrics.get(hid)
        )
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused)
            host_label = st.config.label if st else self._focused
        t = Text()
        t.append(f" {total_dbs} DB instance(s)", style="grey70")
        t.append(f"  host: {host_label}", style="grey70")
        t.append("  | h:host  r:refresh  2:slow log  Esc:close", style="grey50")
        sb.update(t)

    def action_close(self):
        self.dismiss(None)

    def action_refresh(self):
        # trigger immediate re-fetch on all visible hosts
        async def _refetch():
            for hid in self._host_ids():
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_db()
            self._refresh_data()
        self.run_worker(_refetch(), exclusive=False)
        self.notify("Refreshing…", severity="information")

    def action_toggle_host(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_overview(self):
        self._tab = "overview"
        self.query_one(ContentSwitcher).current = "view-overview"
        self._update_tab_bar()

    def action_tab_slowlog(self):
        self._tab = "slowlog"
        self.query_one(ContentSwitcher).current = "view-slowlog"
        self._update_tab_bar()


# ══════════════════════════════════════════════════════════════════════════════
# SECTION: deploy_screen  (v0.5)
# ══════════════════════════════════════════════════════════════════════════════


class DeployScreen(ModalScreen):
    """
    Ctrl+G - Git / Deploy Manager.

    Shows git repositories found on each host.
    Tabs: Repos | Deploy Output
    Keys:
      1 / 2      - switch tab
      p          - git pull on selected repo
      R          - restart service after pull (systemctl restart <service>)
      b          - git log - choose commit for rollback
      h          - toggle host filter
      r          - refresh (re-scan repos)
      Esc        - close
    """

    DEFAULT_CSS = """
    DeployScreen { align: center middle; }
    #deploy-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    DeployScreen #tab-bar  { height: 1; }
    DeployScreen DataTable { height: 1fr; }
    DeployScreen #output-log { height: 1fr; overflow-y: auto; }
    DeployScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape",  "close",        "Close"),
        Binding("r",       "refresh",      "Refresh"),
        Binding("p",       "pull",         "git pull"),
        Binding("shift+r", "restart_svc",  "Restart svc"),
        Binding("h",       "toggle_host",  "Host"),
        Binding("1",       "tab_repos",    "Repos"),
        Binding("2",       "tab_output",   "Output"),
        Binding("f2",      "open_ssh",     "SSH",   show=False),
        Binding("ctrl+f",  "open_fm",      "Files", show=False),
    ]

    def __init__(self, pool, metrics, focused_host_id: str = "", **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._metrics     = metrics
        self._focused     = focused_host_id
        self._filter_host = False
        self._tab         = "repos"
        self._output_lines: list[str] = []

    def compose(self):
        with Vertical(id="deploy-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-repos"):
                with Vertical(id="view-repos"):
                    yield DataTable(id="repo-table", zebra_stripes=True)
                with Vertical(id="view-output"):
                    yield Static("", id="output-log")
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#deploy-box")
        box.border_title = "🔀  Git / Deploy Manager"
        box.border_subtitle = " 1:Repos  2:Output  p:pull  R:restart  h:filter  r:refresh  Esc:close"
        self._build_table()
        self._refresh_data()

    def _build_table(self):
        t: DataTable = self.query_one("#repo-table", DataTable)
        t.clear(columns=True)
        t.add_columns("Host", "Path", "Branch", "⬇Behind", "⬆Ahead", "Dirty", "Last Commit")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_table()
        self._update_tab_bar()
        self._update_status()

    def _fill_table(self):
        t: DataTable = self.query_one("#repo-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            if not m.git_repos:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("no repos found", style="grey50"),
                    Text(""), Text(""), Text(""), Text(""), Text(""),
                    key=f"{hid}:",
                )
                continue
            for repo in m.git_repos:
                behind = repo.get("behind", 0)
                ahead  = repo.get("ahead",  0)
                dirty  = repo.get("dirty",  0)
                behind_style = "bold red" if behind > 0 else "grey50"
                ahead_style  = "yellow"   if ahead  > 0 else "grey50"
                dirty_style  = "yellow"   if dirty  > 0 else "grey50"
                path = repo.get("path", "")
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(path[-40:], style="default"),
                    Text(repo.get("branch", "?"), style="green"),
                    Text(str(behind), style=behind_style),
                    Text(str(ahead),  style=ahead_style),
                    Text(str(dirty),  style=dirty_style),
                    Text(repo.get("last_commit", "")[:50], style="grey70"),
                    key=f"{hid}:{path}",
                )

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [("1", "Repos", "repos"), ("2", "Output", "output")]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        total = sum(
            len(self._metrics.get(hid).git_repos)
            for hid in self._host_ids()
            if self._metrics.get(hid)
        )
        host_label = "all hosts"
        if self._filter_host and self._focused:
            st = self._pool.state(self._focused)
            host_label = st.config.label if st else self._focused
        t = Text()
        t.append(f" {total} repo(s)", style="grey70")
        t.append(f"  host: {host_label}", style="grey70")
        t.append("  | p:pull  Shift+R:restart  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def _append_output(self, line: str):
        self._output_lines.append(line)
        try:
            log = self.query_one("#output-log", Static)
            log.update("\n".join(self._output_lines[-80:]))
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _selected_repo(self):
        """Return (hid, repo_path) of the currently selected row, or (None, None)."""
        if self._tab != "repos":
            return None, None
        t: DataTable = self.query_one("#repo-table", DataTable)
        if t.cursor_row is None:
            return None, None
        # row key was set as "hid:path"
        try:
            rows = list(t._row_locations.keys())
            if t.cursor_row >= len(rows):
                return None, None
            key_str = str(rows[t.cursor_row])
            if ":" not in key_str:
                return None, None
            hid, _, path = key_str.partition(":")
            return hid, path
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            return None, None

    def action_pull(self):
        hid, path = self._selected_repo()
        if not hid or not path:
            self.notify("Select a repo first", severity="warning")
            return
        async def _do_pull():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self._append_output(f"[ERROR] {hid}: not connected")
                return
            label = hs.config.label
            self._append_output(f"[{label}] git pull {path} ...")
            self._tab = "output"
            self.query_one(ContentSwitcher).current = "view-output"
            self._update_tab_bar()
            import asyncio as _aio
            loop = _aio.get_running_loop()
            _record_screen_exec("deploy")
            cmd = f"cd {path!r} && git pull 2>&1"
            def _run():
                _, stdout, _ = hs.client.exec_command(cmd, timeout=60)
                return stdout.read().decode(errors="replace")
            try:
                out = await loop.run_in_executor(None, _run)
                for line in out.splitlines():
                    self._append_output(f"  {line}")
                self._append_output(f"[{label}] pull done ✓")
                # refresh git data
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_git()
                self._fill_table()
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._append_output(f"[ERROR] {e}")
        self.run_worker(_do_pull(), exclusive=False)

    def action_restart_svc(self):
        hid, path = self._selected_repo()
        if not hid or not path:
            self.notify("Select a repo first", severity="warning")
            return
        # try to guess service name from repo dir basename
        import os as _os
        svc_name = _os.path.basename(path.rstrip("/"))
        async def _do_restart():
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                self._append_output(f"[ERROR] {hid}: not connected")
                return
            label = hs.config.label
            self._append_output(f"[{label}] systemctl restart {svc_name} ...")
            self._tab = "output"
            self.query_one(ContentSwitcher).current = "view-output"
            self._update_tab_bar()
            import asyncio as _aio
            loop = _aio.get_running_loop()
            cmd = f"systemctl restart {svc_name} 2>&1 && echo 'restarted OK' || docker compose -f {path!r}/docker-compose.yml up -d 2>&1 | tail -5"
            def _run():
                _, stdout, _ = hs.client.exec_command(cmd, timeout=30)
                return stdout.read().decode(errors="replace")
            try:
                out = await loop.run_in_executor(None, _run)
                for line in out.splitlines():
                    self._append_output(f"  {line}")
                self._append_output(f"[{label}] restart done ✓")
            except Exception as e:
                _log.warning("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                self._append_output(f"[ERROR] {e}")
        self.run_worker(_do_restart(), exclusive=False)

    def action_refresh(self):
        async def _refetch():
            for hid in self._host_ids():
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_git()
            self._refresh_data()
        self.run_worker(_refetch(), exclusive=False)
        self.notify("Scanning repos…", severity="information")

    def action_open_ssh(self):
        """F2 — SSH shell into selected repo's directory (or just the host)."""
        hid, path = self._selected_repo()
        if not hid:
            hid = self._focused
        if not hid:
            self.app.notify("No host selected", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(SshShellScreen(self._pool, hid,
                                            init_cmd=f"cd {path}" if path else None))

    def action_open_fm(self):
        """Ctrl+F — File Manager for selected repo's host and directory."""
        hid, path = self._selected_repo()
        if not hid:
            hid = self._focused
        if not hid:
            self.app.notify("No host selected", severity="warning")
            return
        self.dismiss(None)
        self.app.push_screen(FileManagerScreen(self._pool, initial_host_id=hid,
                                               initial_path=path or None))

    def action_close(self):
        self.dismiss(None)

    def action_toggle_host(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_repos(self):
        self._tab = "repos"
        self.query_one(ContentSwitcher).current = "view-repos"
        self._update_tab_bar()

    def action_tab_output(self):
        self._tab = "output"
        self.query_one(ContentSwitcher).current = "view-output"
        self._update_tab_bar()


