# SECTION: log_agg_screen  (v0.5)
# ══════════════════════════════════════════════════════════════════════════════

_LOG_PRESETS = [
    ("syslog",         "/var/log/syslog"),
    ("auth.log",       "/var/log/auth.log"),
    ("nginx/access",   "/var/log/nginx/access.log"),
    ("nginx/error",    "/var/log/nginx/error.log"),
    ("journalctl err", ""),       # special: uses journalctl
    ("custom",         ""),
]


class LogAggScreen(ModalScreen):
    """
    Ctrl+L - Cross-host Log Aggregation.

    Runs a regex grep in parallel across all hosts against a chosen log file.
    Results stream in real time with host labels.

    Keys:
      Enter      - run search
      Tab        - move between inputs
      ↑ ↓        - scroll results
      c          - clear results
      Esc        - close
    """

    DEFAULT_CSS = """
    LogAggScreen { align: center middle; }
    #logagg-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    LogAggScreen #form-bar { height: 3; layout: horizontal; }
    LogAggScreen #form-bar Label { width: auto; margin-right: 1; }
    LogAggScreen #pattern-input { width: 30; }
    LogAggScreen #file-input    { width: 30; }
    LogAggScreen #preset-label  { width: auto; color: $text-muted; }
    LogAggScreen #results-view  { height: 1fr; overflow-y: auto; }
    LogAggScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close",   "Close"),
        Binding("c",      "clear",   "Clear"),
        Binding("ctrl+r", "run",     "Run"),
    ]

    def __init__(self, pool, **kwargs):
        super().__init__(**kwargs)
        self._pool          = pool
        self._results: list[str] = []
        self._search_running       = False
        self._preset_idx    = 0

    def compose(self):
        with Vertical(id="logagg-box"):
            with Horizontal(id="form-bar"):
                yield Label("Regex:")
                yield Input(placeholder="error|warn|fail", id="pattern-input")
                yield Label("  File/Preset:")
                yield Input(placeholder="/var/log/syslog", id="file-input",
                            value=_LOG_PRESETS[0][1])
                yield Label("  [Tab=next preset  Ctrl+R=run]", id="preset-label", markup=False)
            yield Static("", id="results-view")
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#logagg-box")
        box.border_title = "🔍  Cross-Host Log Aggregation"
        box.border_subtitle = " Tab:next preset  Ctrl+R:run  c:clear  Esc:close"
        self._update_status()
        self.query_one("#pattern-input", Input).focus()

    def on_key(self, event) -> None:
        if event.key == "tab":
            # cycle log presets
            event.stop()
            self._preset_idx = (self._preset_idx + 1) % len(_LOG_PRESETS)
            name, path = _LOG_PRESETS[self._preset_idx]
            self.query_one("#preset-label", Label).update(f"  [{name}]  Ctrl+R=run")
            if name != "custom":
                self.query_one("#file-input", Input).value = path
            return
        if event.key == "enter":
            self.action_run()

    def action_run(self):
        if self._search_running:
            self.notify("Already running…", severity="warning")
            return
        pattern = self.query_one("#pattern-input", Input).value.strip()
        log_file = self.query_one("#file-input", Input).value.strip()
        if not pattern:
            self.notify("Enter a regex pattern", severity="warning")
            return
        self._results = []
        self._search_running = True
        self._update_results_view()
        self._update_status()
        self.run_worker(self._do_search(pattern, log_file), exclusive=False)

    async def _do_search(self, pattern: str, log_file: str):
        import asyncio as _aio
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        # preset: journalctl errors
        name, _ = _LOG_PRESETS[self._preset_idx]
        if name == "journalctl err":
            cmd_tmpl = "journalctl -p err --since '1 hour ago' --no-pager 2>/dev/null | grep -iE {pat} | head -50"
        elif log_file:
            safe_pat = pattern.replace("'", r"'\''")
            cmd_tmpl = f"grep -iE '{safe_pat}' {log_file} 2>/dev/null | tail -50"
        else:
            self._results.append("[ERROR] No log file specified")
            self._search_running = False
            self._update_results_view()
            self._update_status()
            return

        async def _fetch_one(hid: str):
            hs = self._pool.state(hid)
            if not hs or not hs.client:
                return hid, f"[not connected]", []
            label = hs.config.label if hs else hid
            if name == "journalctl err":
                safe_pat = pattern.replace("'", r"'\''")
                cmd = f"journalctl -p err --since '1 hour ago' --no-pager 2>/dev/null | grep -iE '{safe_pat}' | head -50"
            else:
                cmd = cmd_tmpl
            loop = _aio.get_running_loop()
            def _run():
                _, stdout, _ = hs.client.exec_command(cmd, timeout=30)
                return stdout.read().decode(errors="replace")
            try:
                raw = await loop.run_in_executor(None, _run)
                lines = [l for l in raw.splitlines() if l.strip()]
                return hid, label, lines
            except Exception as e:
                _log.debug("Handled exception in block: %s: %s", type(e).__name__, e)  # TODO: improve log quality
                return hid, label, [f"[ERROR] {e}"]

        tasks = [_aio.create_task(_fetch_one(hid)) for hid in ids]
        for coro in _aio.as_completed(tasks):
            hid, label, lines = await coro
            if lines:
                self._results.append(f"── {label} ({'%d matches' % len(lines)}) ──")
                for line in lines:
                    self._results.append(f"  {line}")
            else:
                self._results.append(f"── {label}: no matches ──")
            self._update_results_view()
            self._update_status()

        self._search_running = False
        self._update_status()

    def _update_results_view(self):
        try:
            view = self.query_one("#results-view", Static)
            lines = self._results[-200:]
            t = Text()
            for line in lines:
                if line.startswith("──"):
                    t.append(line + "\n", style="bold cyan")
                elif "[ERROR]" in line:
                    t.append(line + "\n", style="bold red")
                else:
                    t.append(line + "\n", style="default")
            view.update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def _update_status(self):
        try:
            sb = self.query_one("#status-bar", Static)
            state = "searching…" if self._search_running else f"{len(self._results)} lines"
            t = Text()
            t.append(f" {state}", style="bold yellow" if self._search_running else "grey70")
            t.append("  | Enter/Ctrl+R:search  Tab:next preset  c:clear  Esc:close",
                      style="grey50")
            sb.update(t)
        except Exception as e:
            _log.debug("Exception: %s: %s\n%s", type(e).__name__, e, traceback.format_exc())  # TODO: improve log quality
            pass

    def action_clear(self):
        self._results = []
        self._update_results_view()
        self._update_status()

    def action_close(self):
        self.dismiss(None)


