class EnvScreen(ModalScreen):
    """
    Ctrl+E - Environment / Config Diff.

    Tabs: .env Files | Diff | SSH Keys
    Keys:
      1 / 2 / 3  - switch tab
      h          - toggle host filter
      r          - refresh (re-fetch)
      Esc        - close

    Diff tab: shows which .env keys differ between hosts (values hidden).
    SSH Keys tab: authorized_keys across all hosts.
    """

    DEFAULT_CSS = """
    EnvScreen { align: center middle; }
    #env-box {
        width: 98%; height: 95%; background: $surface;
        border: double $accent; padding: 0 1;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: left;
    }
    EnvScreen #tab-bar  { height: 1; }
    EnvScreen DataTable { height: 1fr; }
    EnvScreen #status-bar { height: 1; color: $text-muted; }
    """

    BINDINGS = [
        Binding("escape", "close",       "Close"),
        Binding("r",      "refresh",     "Refresh"),
        Binding("h",      "toggle_host", "Host"),
        Binding("1",      "tab_env",     ".env Files"),
        Binding("2",      "tab_diff",    "Diff"),
        Binding("3",      "tab_keys",    "SSH Keys"),
    ]

    def __init__(self, pool, metrics, **kwargs):
        super().__init__(**kwargs)
        self._pool        = pool
        self._metrics     = metrics
        self._filter_host = False
        self._focused     = ""
        self._tab         = "env"

    def compose(self):
        with Vertical(id="env-box"):
            yield Static("", id="tab-bar")
            with ContentSwitcher(initial="view-env"):
                with Vertical(id="view-env"):
                    yield DataTable(id="env-table", zebra_stripes=True)
                with Vertical(id="view-diff"):
                    yield DataTable(id="diff-table", zebra_stripes=True)
                with Vertical(id="view-keys"):
                    yield DataTable(id="keys-table", zebra_stripes=True)
            yield Static("", id="status-bar")

    def on_mount(self):
        box = self.query_one("#env-box")
        box.border_title = "🔐  Environment / Config Diff"
        box.border_subtitle = " 1:.env  2:Diff  3:SSH Keys  h:filter  r:refresh  Esc:close"
        self._build_tables()
        self._refresh_data()

    def _build_tables(self):
        et: DataTable = self.query_one("#env-table", DataTable)
        et.clear(columns=True)
        et.add_columns("Host", "File", "Key", "Value (masked)")

        dt: DataTable = self.query_one("#diff-table", DataTable)
        dt.clear(columns=True)
        dt.add_columns("Key", "Status", "Hosts with key")

        kt: DataTable = self.query_one("#keys-table", DataTable)
        kt.clear(columns=True)
        kt.add_columns("Host", "Type", "Key ID", "Comment")

    def _host_ids(self):
        ids = self._pool.host_ids() if hasattr(self._pool, "host_ids") else []
        if self._filter_host and self._focused:
            return [self._focused] if self._focused in ids else ids
        return ids

    def _refresh_data(self):
        self._fill_env()
        self._fill_diff()
        self._fill_keys()
        self._update_tab_bar()
        self._update_status()

    def _mask(self, value: str) -> str:
        """Mask sensitive values - show length only."""
        low = value.lower()
        sensitive = ("pass", "secret", "key", "token", "pwd", "auth", "cred")
        if any(s in low for s in sensitive):
            return f"[{len(value)} chars hidden]"
        # show first 8 chars
        return value[:8] + ("…" if len(value) > 8 else "")

    def _fill_env(self):
        t: DataTable = self.query_one("#env-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            if not m.env_vars:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("-", style="grey50"),
                    Text("no .env files found", style="grey50"), Text(""),
                )
                continue
            for path, kvs in m.env_vars.items():
                short_path = path[-35:] if len(path) > 35 else path
                for key, val in list(kvs.items())[:50]:
                    t.add_row(
                        Text(label[:14], style="cyan"),
                        Text(short_path, style="grey70"),
                        Text(key, style="green"),
                        Text(self._mask(val), style="grey70"),
                    )

    def _fill_diff(self):
        t: DataTable = self.query_one("#diff-table", DataTable)
        t.clear()
        ids = self._host_ids()
        # Collect all keys per host (union of all .env files on that host)
        host_keys: dict[str, set] = {}
        for hid in ids:
            m = self._metrics.get(hid)
            if not m:
                continue
            keys: set[str] = set()
            for kvs in m.env_vars.values():
                keys.update(kvs.keys())
            host_keys[hid] = keys

        if len(host_keys) < 2:
            t.add_row(
                Text("Need ≥2 hosts to diff", style="grey50"),
                Text(""), Text(""),
            )
            return

        all_keys = set()
        for keys in host_keys.values():
            all_keys.update(keys)

        for key in sorted(all_keys):
            present_in = [hid for hid, keys in host_keys.items() if key in keys]
            missing_in = [hid for hid, keys in host_keys.items() if key not in keys]
            if missing_in:
                status = "MISSING on some"
                status_style = "bold red"
            else:
                status = "present all"
                status_style = "green"
            labels = ", ".join(
                self._pool.state(hid).config.label if self._pool.state(hid) else hid
                for hid in present_in
            )
            t.add_row(
                Text(key, style="default"),
                Text(status, style=status_style),
                Text(labels[:60], style="grey70"),
            )

    def _fill_keys(self):
        t: DataTable = self.query_one("#keys-table", DataTable)
        t.clear()
        for hid in self._host_ids():
            m = self._metrics.get(hid)
            if not m:
                continue
            label = self._pool.state(hid).config.label if self._pool.state(hid) else hid
            if not m.ssh_keys:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text("-", style="grey50"), Text("no keys found", style="grey50"), Text(""),
                )
                continue
            for k in m.ssh_keys:
                t.add_row(
                    Text(label[:14], style="cyan"),
                    Text(k.get("key_type", "?"), style="yellow"),
                    Text(k.get("key_id", ""), style="grey70"),
                    Text(k.get("comment", ""), style="default"),
                )

    def _update_tab_bar(self):
        tb = self.query_one("#tab-bar", Static)
        t = Text()
        for key, lbl, tab_id in [
            ("1", ".env Files", "env"), ("2", "Diff", "diff"), ("3", "SSH Keys", "keys")
        ]:
            is_active = self._tab == tab_id
            style = "bold white on blue" if is_active else "grey70"
            t.append(f" {key}:{lbl} ", style=style)
        tb.update(t)

    def _update_status(self):
        sb = self.query_one("#status-bar", Static)
        t = Text()
        t.append(" 1:.env  2:diff  3:ssh keys", style="grey70")
        t.append("  | h:host filter  r:refresh  Esc:close", style="grey50")
        sb.update(t)

    def action_close(self):
        self.dismiss(None)

    def action_refresh(self):
        async def _refetch():
            for hid in self._host_ids():
                agent = self._pool.agent(hid) if hasattr(self._pool, "agent") else None
                if agent:
                    await agent._fetch_env()
            self._refresh_data()
        self.run_worker(_refetch(), exclusive=False)
        self.notify("Re-fetching env…", severity="information")

    def action_toggle_host(self):
        self._filter_host = not self._filter_host
        self._refresh_data()

    def action_tab_env(self):
        self._tab = "env"
        self.query_one(ContentSwitcher).current = "view-env"
        self._update_tab_bar()

    def action_tab_diff(self):
        self._tab = "diff"
        self.query_one(ContentSwitcher).current = "view-diff"
        self._update_tab_bar()

    def action_tab_keys(self):
        self._tab = "keys"
        self.query_one(ContentSwitcher).current = "view-keys"
        self._update_tab_bar()


