# SECTION: ai_stats_screen
# AiStatsScreen - Ctrl+I  AI token usage statistics by tier (smart/fast) and day
# ══════════════════════════════════════════════════════════════════════════════

class AiStatsScreen(ModalScreen):
    """
    Ctrl+I - AI Token Statistics.
    Shows token usage broken down by tier (smart = expensive model,
    fast = cheap model) for this hour, today, the current session,
    and a per-day table for the last 7 days.
    """

    DEFAULT_CSS = """
    AiStatsScreen { align: center middle; background: $background 80%; }
    #ai-stats-box {
        width: 68; height: auto; max-height: 90vh;
        border: double $accent;
        background: $surface;
        padding: 1 2;
        border-title-color: $accent;
        border-title-style: bold;
        border-subtitle-color: $text-muted;
        border-subtitle-align: center;
    }
    #ai-stats-body { height: auto; }
    """

    BINDINGS = [Binding("escape", "close", "Close", show=False)]

    def __init__(self, engine: "AIEngine", **kwargs):
        super().__init__(**kwargs)
        self._engine = engine

    def compose(self) -> ComposeResult:
        with Container(id="ai-stats-box"):
            yield Static("", id="ai-stats-body")

    def on_mount(self) -> None:
        box = self.query_one("#ai-stats-box")
        box.border_title = "🤖  AI Token Statistics"
        box.border_subtitle = "Esc - close"
        self._refresh_body()

    def _refresh_body(self) -> None:
        engine = self._engine
        body = self.query_one("#ai-stats-body", Static)
        if not engine.enabled:
            body.update(
                "[yellow]AI is disabled.[/]\n"
                "Enable in [bold]F6 → 🤖 AI[/bold]."
            )
            return

        s = engine.token_stats()
        t = Text()

        # Provider / models
        t.append("Provider:    ", style="bold")
        t.append(f"{s['provider']}\n")
        t.append("Smart model: ", style="bold")
        t.append(f"{s['smart_model']}  ")
        t.append("(expensive)\n", style="dim")
        t.append("Fast model:  ", style="bold")
        t.append(f"{s['fast_model']}  ")
        t.append("(cheap)\n", style="dim")
        t.append("\n")

        def _block(label: str, d: dict) -> None:
            t.append(f"── {label} ──\n", style="bold cyan")
            t.append("  Smart (expensive):  ", style="bold")
            t.append(f"{d['smart']:>9,}  tokens\n", style="yellow")
            t.append("  Fast  (cheap):      ", style="bold")
            t.append(f"{d['fast']:>9,}  tokens\n", style="green")
            t.append("  Total:              ", style="dim")
            t.append(f"{d['total']:>9,}  tokens  ", style="")
            t.append(f"({d['calls']} calls)\n", style="dim")
            t.append("\n")

        _block("This Hour",    s["hour"])
        _block("Today",        s["today"])
        _block("This Session", s["session"])

        if s["days"]:
            t.append("── Last 7 Days ──\n", style="bold cyan")
            t.append("  Date          Smart (exp)   Fast (chp)      Total\n", style="bold dim")
            t.append("  " + "─" * 54 + "\n", style="dim")
            for day in s["days"]:
                t.append(f"  {day['date']}  ")
                t.append(f"{day['smart']:>11,}  ", style="yellow")
                t.append(f"{day['fast']:>11,}  ", style="green")
                t.append(f"{day['total']:>9,}\n")

        body.update(t)

    def action_close(self) -> None:
        self.dismiss(None)


