def _check_deps():
    missing = []
    for pkg, imp in [("textual","textual"), ("paramiko","paramiko"),
                     ("cryptography","cryptography")]:
        try:
            __import__(imp)
        except ImportError as e:
            _log.warning("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            missing.append(pkg)
    if missing:
        print(f"\nMissing packages: {', '.join(missing)}")
        print(f"Install with:  pip install {' '.join(missing)}\n")
        sys.exit(1)


async def _run(cfg: AppConfig):
    cfg_manager = ConfigManager()
    pool        = AgentPool(cfg.hosts, cfg_manager, cfg)

    await pool.start()

    # attach notification manager after pool is started
    notif_mgr = NotificationManager(cfg)
    notif_mgr.attach(pool)

    metrics = pool.metrics_view()
    radar   = pool.radar_view()
    watcher = pool.watcher_view()

    async def background():
        await pool.maintain()

    async def _autosave(interval: int = 300):
        """Periodically flush config to disk (default: every 5 minutes)."""
        while True:
            await asyncio.sleep(interval)
            cfg_manager.flush()
            _log.debug("Auto-saved config to disk.")

    bg_task       = asyncio.create_task(background())
    autosave_task = asyncio.create_task(_autosave())
    app = DeflectAppV2(pool, metrics, radar, watcher, cfg, cfgman=cfg_manager)  # Deflect One real mode
    try:
        await app.run_async()
    finally:
        autosave_task.cancel()
        bg_task.cancel()
        await pool.close_all()
        cfg_manager.flush()  # final save on exit


def _run_demo(cfg):
    """Simulated data - no SSH needed."""
    import random, time as _t

    demo_hosts = [
        HostConfig(id="linode-01",  label="Web Server",  address="194.195.1.10",  tags=["web","prod"]),
        HostConfig(id="linode-02",  label="App Server",  address="194.195.1.11",  tags=["app","prod"]),
        HostConfig(id="contabo-db", label="Database",    address="62.84.1.10",    tags=["db","prod"]),
        HostConfig(id="contabo-2",  label="Mail Server", address="62.84.1.11",    tags=["mail"]),
    ]
    cfg.hosts = demo_hosts

    # ── fake pool ──
    pool = ConnectionPool.__new__(ConnectionPool)
    pool._hosts = {}
    pool._lock  = asyncio.Lock()
    pool._loop  = None

    fake_metrics: dict[str, HostMetrics] = {}
    for h in demo_hosts:
        hs           = HostState(config=h)
        hs.state     = ConnState.ERROR if h.id == "contabo-2" else ConnState.CONNECTED
        hs.error     = "Connection refused" if h.id == "contabo-2" else ""
        hs.last_seen = _t.time()
        pool._hosts[h.id] = hs

        m = HostMetrics(host_id=h.id)
        m.cpu_pct    = random.uniform(10, 85)
        m.ram_pct    = random.uniform(30, 90)
        m.disk_pct   = random.uniform(20, 70)
        m.load1      = random.uniform(0.1, 2.5)
        m.uptime_s   = random.randint(86400, 86400 * 30)
        # Initialize network bytes (like /proc/net/dev counters)
        m._prev_net  = {"rx": random.randint(1000000, 50000000), "tx": random.randint(500000, 30000000)}
        m._prev_time = time.monotonic()
        m.net_rx_kb  = 0.0
        m.net_tx_kb  = 0.0
        m.mail_queue_count = 0
        m.mail_throughput_mpm = random.uniform(1, 6)  # msgs/min (1-6 is normal)
        m.mail_mta_type = random.choice(["exim4", "postfix"])
        m.mail_last_timestamp = time.time()
        m.mail_last_count = 0
        for _ in range(40):
            m.cpu_history.append(random.uniform(5, 90))
            m.ram_history.append(random.uniform(30, 90))
            m.net_rx_hist.append(0.0)  # Will be calculated in animation
            m.mail_queue_hist.append(random.uniform(1, 6))  # msgs/min
        fake_metrics[h.id] = m

    pool.host_ids   = lambda: [h.id for h in demo_hosts]
    pool.all_states = lambda: list(pool._hosts.values())

    async def _noop(): pass
    pool.close_all = _noop

    # ── fake metrics ──
    metrics = MetricsCollector.__new__(MetricsCollector)
    metrics._pool    = pool
    metrics._metrics = fake_metrics

    # ── fake radar ──
    radar           = SecurityRadar.__new__(SecurityRadar)
    radar._pool     = pool
    radar._state    = RadarState()
    radar._ip_hosts = defaultdict(set)
    for flag, ip, user, kind, cc in [
        ("🇨🇳", "123.58.182.44",  "root",   "brute", "CN"),
        ("🇷🇺", "91.243.91.211",  "admin",  "scan",  "RU"),
        ("🇧🇷", "177.75.248.33",  "pi",     "brute", "BR"),
        ("🇳🇱", "185.220.101.44", "ubuntu", "brute", "NL"),
        ("🇰🇷", "211.44.33.12",   "deploy", "scan",  "KR"),
        ("🇨🇳", "118.25.196.88",  "root",   "brute", "CN"),
        ("🇩🇪", "46.101.210.55",  "user",   "scan",  "DE"),
    ]:
        radar._state.events.append(AttackEvent(
            ts=_t.strftime("%b %d %H:%M:%S"), host_id="linode-01",
            src_ip=ip, username=user, method="ssh", kind=kind,
            country=cc, flag=flag))
    radar._state.atk_per_min  = 14.0
    radar._state.banned_count = 12

    # ── fake watcher ──
    watcher           = ServiceWatcher.__new__(ServiceWatcher)
    watcher._pool     = pool
    watcher._services = {}
    watcher._baseline = {}
    for hid, svcs in {
        "linode-01":  [("nginx","active"),("postgres","active"),("redis","active")],
        "linode-02":  [("nginx","active"),("celery","failed"),("docker","active")],
        "contabo-db": [("postgres","active"),("redis","active")],
        "contabo-2":  [],
    }.items():
        watcher._services[hid] = [
            ServiceInfo(name=n, host_id=hid, active=a,
                        sub="running" if a == "active" else "failed")
            for n, a in svcs
        ]

    # Patch poll loops - demo has no real SSH, loops must be no-ops
    async def _idle():
        while True:
            await asyncio.sleep(3600)

    metrics.poll_loop = lambda *a, **kw: _idle()
    radar.poll_loop   = lambda *a, **kw: _idle()
    watcher.poll_loop = lambda *a, **kw: _idle()

    # Animate demo data: randomise metrics every 5s so bars move
    async def _animate():
        while True:
            await asyncio.sleep(5)
            for h in demo_hosts:
                m = fake_metrics[h.id]
                if h.id == "contabo-2":
                    continue
                import random as _r
                import time as _time
                m.cpu_pct  = max(2, min(98, m.cpu_pct  + _r.uniform(-8, 8)))
                m.ram_pct  = max(10, min(95, m.ram_pct  + _r.uniform(-4, 4)))

                # Network: simulate real /proc/net/dev bytes counter incrementing
                # Mostly idle (100-500 KB transfer per 5s), occasionally burst (1-5 MB per 5s)
                if _r.random() < 0.3:  # 30% chance of activity
                    transfer_kb = _r.uniform(1024, 5120)  # 1-5 MB
                else:  # 70% idle
                    transfer_kb = _r.uniform(100, 500)   # 100-500 KB

                # Convert to bytes and add to byte counters
                transfer_bytes = int(transfer_kb * 1024)
                m._prev_net["rx"] += transfer_bytes
                m._prev_net["tx"] += int(transfer_bytes * 0.7)  # TX usually less than RX

                # Calculate speed like real code does (bytes / time / 1024)
                now = _time.monotonic()
                dt = now - m._prev_time if m._prev_time else 1.0
                m.net_rx_kb = round(transfer_bytes / dt / 1024, 1)
                m.net_tx_kb = round(int(transfer_bytes * 0.7) / dt / 1024, 1)
                m._prev_time = now

                m.cpu_history.append(m.cpu_pct)
                m.ram_history.append(m.ram_pct)
                m.net_rx_hist.append(m.net_rx_kb)
                # Animate mail throughput: msgs/min varies 1-8
                # Occasional spikes (peak times), normal idle
                if _r.random() < 0.15:  # 15% chance of spike
                    m.mail_throughput_mpm = min(8, m.mail_throughput_mpm + _r.uniform(1, 3))
                else:  # 85% normal/decreasing
                    m.mail_throughput_mpm = max(0.5, m.mail_throughput_mpm - _r.uniform(0.2, 0.5))
                m.mail_queue_hist.append(m.mail_throughput_mpm)
                m.updated_at = _t.time()
            # add a new attack event
            import random as _r
            sample = [
                ("🇨🇳","58.218.92.{}".format(_r.randint(1,254)), "root",   "brute", "CN"),
                ("🇷🇺","91.243.{}.1" .format(_r.randint(1,254)), "admin",  "scan",  "RU"),
                ("🇮🇳","103.{}.1.1"  .format(_r.randint(1,254)), "ubuntu", "brute", "IN"),
            ]
            flag, ip, user, kind, cc = _r.choice(sample)
            radar._state.events.append(AttackEvent(
                ts=_t.strftime("%b %d %H:%M:%S"), host_id="linode-01",
                src_ip=ip, username=user, method="ssh", kind=kind,
                country=cc, flag=flag))
            radar._state.atk_per_min = _r.uniform(8, 20)

    # Build app AFTER all fake objects are ready
    async def _run_demo_async():
        app = DeflectApp(pool, metrics, radar, watcher, cfg)  # Deflect One demo mode
        task = asyncio.create_task(_animate())
        try:
            await app.run_async()
        finally:
            task.cancel()

    asyncio.run(_run_demo_async())


def show_startup_banner(cfg_manager: "ConfigManager") -> None:
    """
    Always prints version + author + site before TUI starts.
    Donate line appears only after 10 days of use with at least one connected host.
    """
    # Header - always shown
    print(
        f"\n"
        f"  \u2694  Deflect One v{APP_VERSION}  by WhitemanV\n"
        f"     {APP_SITE}  |  {APP_GITHUB}\n"
    )
    # Sponsor line - conditional: 10+ days AND at least one connected host
    show_sponsor = False
    first_run = cfg_manager.get_app_stats().get("first_run_date")
    if first_run:
        try:
            days_elapsed = (datetime.date.today() - datetime.date.fromisoformat(first_run)).days
            host_stats   = cfg_manager._data.get("stats", {})
            show_sponsor = days_elapsed >= 10 and any(bool(v) for v in host_stats.values())
        except (ValueError, TypeError) as e:
            _log.debug("Handled exception: %s: %s", type(e).__name__, e)  # TODO: improve log quality
            pass
    if show_sponsor:
        print(f"     \U0001f499 Like Deflect One? \u2192 {APP_SPONSOR}\n")
    import time as _t
    _t.sleep(1)


def _check_single_instance() -> None:
    """Warn if another Deflect One instance is already running (shared config may get overwritten)."""
    lock_file = DEFLECT_DIR / ".deflect.lock"
    current_pid = os.getpid()

    def _pid_alive(pid: int) -> bool:
        try:
            if platform.system() == "Windows":
                import ctypes
                handle = ctypes.windll.kernel32.OpenProcess(0x1000, False, pid)  # PROCESS_QUERY_LIMITED_INFORMATION
                if handle:
                    ctypes.windll.kernel32.CloseHandle(handle)
                    return True
                return False
            else:
                os.kill(pid, 0)
                return True
        except (OSError, PermissionError):
            return False

    existing_pid: int | None = None
    if lock_file.exists():
        try:
            existing_pid = int(lock_file.read_text().strip())
        except (ValueError, OSError):
            existing_pid = None

    if existing_pid and existing_pid != current_pid and _pid_alive(existing_pid):
        print(f"\n⚠️  Deflect One is already running (PID {existing_pid}).")
        print("   Running two instances simultaneously may cause config file conflicts.")
        try:
            answer = input("   Continue anyway? [y/N]: ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            answer = ""
        if answer not in ("y", "yes"):
            print("Aborted.")
            sys.exit(0)

    # Write current PID
    try:
        lock_file.write_text(str(current_pid))
    except OSError:
        pass  # Non-fatal: skip locking if dir is read-only

    import atexit
    def _cleanup_lock():
        try:
            if lock_file.exists() and lock_file.read_text().strip() == str(current_pid):
                lock_file.unlink()
        except OSError:
            pass
    atexit.register(_cleanup_lock)


def main():
    _check_deps()
    _check_single_instance()

    parser = argparse.ArgumentParser(description="Deflect One - Enterprise Infrastructure Command Center")
    parser.add_argument("--demo",       action="store_true", help="Demo mode (no SSH)")
    parser.add_argument("--config-dir", default=str(Path(__file__).parent))
    args = parser.parse_args()

    cfg_manager = ConfigManager()
    cfg = cfg_manager.load()

    # Track first-run date (written once, never overwritten)
    if not cfg_manager.get_app_stats().get("first_run_date"):
        cfg_manager.update_app_stats(
            {"first_run_date": datetime.date.today().isoformat()}
        )

    if args.demo:
        _run_demo(cfg)
        return

    show_startup_banner(cfg_manager)

    if not cfg.hosts:
        print(f"No hosts configured in {DEFLECT_DIR / 'deflect.json'}")
        print("Add at least one host to Deflect One and re-run, or use --demo to preview.")
        sys.exit(0)

    asyncio.run(_run(cfg))


